-- Poems batch 208
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7832c404-52ef-4285-a83c-528fbc56e44c','和高廟浄明院梅巖御製韵二首  其一','徐清叟','宋','宋诗','song-poetry','','[]','千年奎畫照蒼霞，酬唱官梅竹外斜。',32,'全唐诗/poet.song.196000.json','["千年奎畫照蒼霞，酬唱官梅竹外斜。", "恭想皇靈天闕上，歸疆猶惜洛陽花。"]'),
('6c3cae72-8d4d-48ae-8b97-cd059efde8a8','和高廟浄明院梅巖御製韵二首  其二','徐清叟','宋','宋诗','song-poetry','','[]','偶因祀事訪丹霞，寺古山深石徑斜。',32,'全唐诗/poet.song.196000.json','["偶因祀事訪丹霞，寺古山深石徑斜。", "衝凍細尋梅信息，枝頭喜見狀元花。"]'),
('b469a188-f777-4fa3-b72f-9fc83ab7dfa2','贈建寧妓唐玉','徐清叟','宋','宋诗','song-poetry','','[]','上國新行巧樣花，一枝聊插鬢雲斜。',32,'全唐诗/poet.song.196000.json','["上國新行巧樣花，一枝聊插鬢雲斜。", "嬌羞未肯從郎意，故把芳容半面遮。"]'),
('f24f8c31-ab56-4175-90ab-06e29eaeb702','癸丑十月二日上天竺寺祈晴','徐清叟','宋','宋诗','song-poetry','','[]','金泥滑滑濺雕鞍，虔走禋祠謁宰官。',64,'全唐诗/poet.song.196000.json','["金泥滑滑濺雕鞍，虔走禋祠謁宰官。", "積雨水添湖面闊，久陰雲護嶺頭寒。", "妨收是處田家苦，開霽何時后土乾。", "現出日光須佛力，少令憂國寸心寬。"]'),
('85358abf-515e-4eb7-bc8a-10e18561318e','寄賈平章','徐清叟','宋','宋诗','song-poetry','','[]','撲面京塵鬢影華，杜鵑聲底客思家。',64,'全唐诗/poet.song.196000.json','["撲面京塵鬢影華，杜鵑聲底客思家。", "久陪宰相堂中食，五拜夫人廟裏花。", "和氣薰蒸由地主，孤根容易發天葩。", "雙壺走迸慳瓊報，聊寄頭綱六餠茶。"]'),
('dc9ff485-d897-468d-a1a9-3f960737144c','贈常庵江羽士','徐清叟','宋','宋诗','song-poetry','','[]','九曲溪頭活計，三生石上精魂。',28,'全唐诗/poet.song.196000.json','["九曲溪頭活計，三生石上精魂。", "沓沓閒雲何處，空山明月啼猿。"]'),
('9ed03653-db88-4780-a473-9963bb726620','牡丹','徐榮叟','宋','宋诗','song-poetry','','[]','姚魏從來洛下誇，千金不惜買繁華。',32,'全唐诗/poet.song.196000.json','["姚魏從來洛下誇，千金不惜買繁華。", "今年底事花能賤，緣是宮中不賞花。"]'),
('d8326442-1c33-4a0e-8ee7-47042f96030a','瓊花','徐榮叟','宋','宋诗','song-poetry','','[]','瓊甤走送寶瓶花，愧乏詩情用拜嘉。',64,'全唐诗/poet.song.196000.json','["瓊甤走送寶瓶花，愧乏詩情用拜嘉。", "一種清香來月殿，十分雅態出仙家。", "細看后土春冰薄，未覺劉郎日影斜。", "擬跨胎禽塵幾隔，珠簾十里自繁華。"]'),
('010652f3-fd81-4483-bc54-8e6be2589c17','茶','徐榮叟','宋','宋诗','song-poetry','','[]','官焙春綠入貢時，擔頭獵獵小黄旗。',32,'全唐诗/poet.song.196000.json','["官焙春綠入貢時，擔頭獵獵小黄旗。", "甘香不數嘗陽羨，密侍天顔喜可知。"]'),
('32d7927e-3cdd-4690-8889-63668595ebdb','題月山新居','徐榮叟','宋','宋诗','song-poetry','','[]','寵任辭樞極，新居卜月山。',48,'全唐诗/poet.song.196000.json','["寵任辭樞極，新居卜月山。", "人從生處樂，天與老來閑。", "翠擁千峯秀，羅縈一水灣。", "佳哉得真樂，恨不早知還。"]'),
('9d48fea0-83d2-416f-bfd7-aaa65c1705f0','贈常庵江羽士','徐榮叟','宋','宋诗','song-poetry','','[]','曾跨金牛入帝鄉，歸裝金薤富琳瑯。',32,'全唐诗/poet.song.196000.json','["曾跨金牛入帝鄉，歸裝金薤富琳瑯。", "喚回客枕邯鄲夢，澗草巖花亦自香。"]'),
('13dbedb1-2dbc-4c7b-b5fd-47c095b3aabe','甲戌廷對後到洞霄丙戌假守新安又得寄徑成詩紀游','汪立中','宋','宋诗','song-poetry','','[]','憶昔尋幽興未終，重來洞府訪仙翁。',64,'全唐诗/poet.song.196000.json','["憶昔尋幽興未終，重來洞府訪仙翁。", "十年塵世身將隠，千年華陽路暗通。", "山水只如前日好，松杉似與老人同。", "明朝又入黄塵去，回首青山一夢中。"]'),
('41bef1cf-79af-44e2-9387-fe09c1b49931','遊洞霄','汪立中','宋','宋诗','song-poetry','','[]','洞天福地萃名山，我喜登臨昔所慳。',64,'全唐诗/poet.song.196000.json','["洞天福地萃名山，我喜登臨昔所慳。", "五殿香嚴如在帝，九山青鎖若爲關。", "巖前鳴鳳當年事，野外驤龍反掌間。", "自顧武夷香火吏，真祠夢想不容攀。"]'),
('1a270de2-318f-435a-98f5-5a6ca0ed6bd2','題寶方洞','汪立中','宋','宋诗','song-poetry','','[]','籃輿郊上綠陰迷，七十一峯雲際齊。',64,'全唐诗/poet.song.196000.json','["籃輿郊上綠陰迷，七十一峯雲際齊。", "我住四窗誇勝境，今觀八洞恍真棲。", "碧簪挺特地如拔，乳竇玲瓏步可携。", "千里客愁爲銷盡，茶香書外好鶑啼。"]'),
('00e9387b-e727-46ce-892c-b25b74cf77f2','月夜懷林叔剛','梁該','宋','宋诗','song-poetry','','[]','凉生秋雨霽，華月上疏林。',72,'全唐诗/poet.song.196000.json','["凉生秋雨霽，華月上疏林。", "因聽落葉響，稍知秋意深。", "芳歲倏已徂，白髮鬢邊侵。", "故人渺何許，日夜懷徽音。", "無由親蘭藻，何以慰沖襟。", "雲中徒矯首，露下空長吟。"]'),
('7223894b-c68e-4fa9-8739-f6455f030430','以廬山三疊泉寄張宗瑞','湯巾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','九疊峯頭一道泉，分明來處與雲連。',64,'全唐诗/poet.song.196000.json','["九疊峯頭一道泉，分明來處與雲連。", "幾人競賞飛流勝，今日方知至味全。", "鴻漸但嘗唐代水，涪翁不到紹熙年。", "從茲康谷宜居二，試問真巖老詠仙。"]'),
('1c536c9f-c288-41b0-b13b-13a5be7a51dd','樵川郊行','李方子','宋','宋诗','song-poetry','','[]','避人忘井邑，耽靜步郊原。',48,'全唐诗/poet.song.196000.json','["避人忘井邑，耽靜步郊原。", "落葉風能掃，寒花霜更繁。", "山空樵響答，灘淺榜聲喧。", "願結山陽伴，長年此灌園。"]'),
('25b58030-7e28-4406-9446-a04ef5f1587b','過東吳','史彌應','宋','宋诗','song-poetry','','[]','出郭乘清興，扁舟一迅風。',48,'全唐诗/poet.song.196000.json','["出郭乘清興，扁舟一迅風。", "山光真黛比，水色與天同。", "宿鷺班班白，寒楓處處紅。", "誰知吾勝概，名冠甬句東。"]'),
('f886d564-e888-4bda-9d3f-fc12036f3657','小春見梅','史彌應','宋','宋诗','song-poetry','','[]','孤根十月已先溫，不待春風破玉痕。',32,'全唐诗/poet.song.196000.json','["孤根十月已先溫，不待春風破玉痕。", "冷豔一枝何處見，竹邊池閣水邊村。"]'),
('e6f1f876-7a65-40ca-85b8-ee45a619f597','山行','杜東','宋','宋诗','song-poetry','','[]','遠岫依依落照，平林隠隠疏鐘。',28,'全唐诗/poet.song.196000.json','["遠岫依依落照，平林隠隠疏鐘。", "獨跨蹇馿歸去，梅花一笑相逢。"]'),
('308d0219-2e02-4a9b-843e-969ea0d3e65f','綠珠','杜東','宋','宋诗','song-poetry','','[]','以色危身豈不知，甘心死別不生離。',32,'全唐诗/poet.song.196000.json','["以色危身豈不知，甘心死別不生離。", "樓前甲士紛如雪，正是花飛玉碎時。"]'),
('ca89131f-7766-497e-9dfb-6f52cad36da4','平山堂','杜東','宋','宋诗','song-poetry','','[]','平山堂下水雲重，孤笛凄凉淡月中。',64,'全唐诗/poet.song.196000.json','["平山堂下水雲重，孤笛凄凉淡月中。", "不見龍蛇飛素壁，只餘狐兔戍離宮。", "仙翁已逐風流盡，世事俱隨夢幻空。", "廣武無人同此意，慨然止有淚臨風。"]'),
('3f9cb621-0cdb-4206-ad2e-857fd3433492','括溪停舟','趙汝迕','宋','宋诗','song-poetry','','[]','樹古半成槎，溪邊歷歷斜。',48,'全唐诗/poet.song.196000.json','["樹古半成槎，溪邊歷歷斜。", "寒林欲無路，小塢不多家。", "去客背流葉，停舟見暮鴉。", "朝朝省秋水，頻減一痕沙。"]'),
('7c9a0ed9-2e3c-4bd7-9bcb-547e0ffeb4ae','四聖觀納凉','趙汝迕','宋','宋诗','song-poetry','','[]','林宮暑自薄，短簟逸人眠。',48,'全唐诗/poet.song.196000.json','["林宮暑自薄，短簟逸人眠。", "樹繫來時馬，風移聽處蟬。", "藥童清入畫，道士默如禪。", "忽憶山中雪，瘦梅逋老阡。"]'),
('911da288-cd32-471e-8da9-521c357ed3b2','哭趙蹈中','趙汝迕','宋','宋诗','song-poetry','','[]','族老今爲海內憐，清名多是布衣傳。',64,'全唐诗/poet.song.196000.json','["族老今爲海內憐，清名多是布衣傳。", "一封表乞從師郡，千里神寒覓句年。", "水鏡照人前日政，雨絲吹旐別時船。", "離家憶值梅初白，梅未成陰失此賢。"]'),
('8bba6d61-351f-4cae-b95c-1777a95b86fd','句  其一','趙汝迕','宋','宋诗','song-poetry','','[]','何用長堤柳，將眉與世顰。',12,'全唐诗/poet.song.196000.json','["何用長堤柳，將眉與世顰。"]'),
('a2839f29-6d69-43a4-92ed-723bb45a603b','句  其二','趙汝迕','宋','宋诗','song-poetry','','[]','夜雨梧桐王子府，春風楊柳相公橋。',16,'全唐诗/poet.song.196000.json','["夜雨梧桐王子府，春風楊柳相公橋。"]'),
('0f5d87d3-a493-43db-a10e-9c72b381be59','寄趙叔魯','戴師古','宋','宋诗','song-poetry','','[]','相知言莫盡，別後意如何。',48,'全唐诗/poet.song.196000.json','["相知言莫盡，別後意如何。", "命笑春冰薄，愁因夜雨多。", "全家寓京國，無地着吟哦。", "會得窮通理，從余緝薜蘿。"]'),
('256c637f-3f9e-4a4f-bcd7-7b9c50dcd57d','重建神秀樓追和忠定公韻','趙必愿','宋','宋诗','song-poetry','','[]','維茲城南樓，廢興端有時。',204,'全唐诗/poet.song.196000.json','["維茲城南樓，廢興端有時。", "昔我忠定公，樓成旋西歸。", "拜廳慚匪肖，易麾繇好溪。", "循環六十載，烏兔驚梭飛。", "吁嗟古雉堞，巨浸墮藩籬。", "陶甓既還舊，更創如有期。", "歲事喜中稔，度材授工師。", "非敢侈輪奐，聊爾遵先規。", "江山展圖畫，欄檻倚晴暉。", "肯堂久在念，今我身則夷。", "遼鶴去不返，遺墨猶淋漓。", "一時賸篇詠，皆表而出之。", "登眺惟疇昔，未覺此舉非。", "落成燈火夜，萬點天星移。", "潮生月在浦，酒闌風滿衣。", "幸繼前人躅，敬和前人詞。", "斯樓儻不朽，庶慰蒸湘悲。"]'),
('f4cb8c21-e345-4352-a9c9-e53b0c739f6f','秋高亭','趙必愿','宋','宋诗','song-poetry','','[]','秋空何太高，秋風何太清。',126,'全唐诗/poet.song.196000.json','["秋空何太高，秋風何太清。", "秋露何太皎，秋月何太明。", "秋山有素期，秋水莫間盟。", "力此久病身，試上高高亭。", "上欲駕扶摇，下欲跳清泠。", "手持紫玉簫，跨鵬或騎鯨。", "時吹復時止，霄壤隨縱橫。", "回首天上人，見我呼友生。", "我言你能許我三百六旬無一日之不秋，則我亦許你從此爲逍遥之朋。"]'),
('516b7ac4-1b61-46e4-826b-1e69a2a9741e','山月池','朱應龍','宋','宋诗','song-poetry','','[]','池底看明月，明月在山頭。',24,'全唐诗/poet.song.196000.json','["池底看明月，明月在山頭。", "清光連上下，分作兩輪秋。"]'),
('70490b8d-d267-48e5-9128-8ab17047d7fa','菊坡','朱應龍','宋','宋诗','song-poetry','','[]','口有綺語債，長詠菊坡詩。',24,'全唐诗/poet.song.196000.json','["口有綺語債，長詠菊坡詩。", "最好重陽景，雞肥酒熟時。"]'),
('9b9b7e23-bb1a-4bc9-aa03-4f96422d91da','勸農和江萬里韻','劉崇卿','宋','宋诗','song-poetry','','[]','年來兵餉瘠吾農，天遣仁侯作歲豐。',64,'全唐诗/poet.song.196000.json','["年來兵餉瘠吾農，天遣仁侯作歲豐。", "燕寢晝清塵不到，螺江春滿澤無窮。", "詩陶幽雅熙熙俗，文續周書噩噩風。", "別乘自憐無鍤地，勸耕却得到山中。"]'),
('e6cda186-375f-422e-9009-d42cc264dd69','卧龍潭','陳範','宋','宋诗','song-poetry','','[]','半巖欲墮潭渚深，晝陽不到午陰陰。',32,'全唐诗/poet.song.196000.json','["半巖欲墮潭渚深，晝陽不到午陰陰。", "洞簫一曲瑶笙斷，千山萬山雲水沉。"]'),
('7361566b-3035-4ab3-88d8-394513418246','句','陳範','宋','宋诗','song-poetry','','[]','倘來軒冕心無必，見在詩書足自娛。',16,'全唐诗/poet.song.196000.json','["倘來軒冕心無必，見在詩書足自娛。"]'),
('5b9bf4a0-0054-4472-af99-a218fb182afb','題松風館','鄭魏珽','宋','宋诗','song-poetry','','[]','一壑蕭然萬里間，此身落得似雲閒。',64,'全唐诗/poet.song.196000.json','["一壑蕭然萬里間，此身落得似雲閒。", "蹁躚野鶴身同逸，來往樵人語不關。", "瑶草茂時春淡蕩，亂溪交處水潺湲。", "偶懷知己携琴去，十里松風未出山。"]'),
('3a9a4f16-2b95-4e67-9f29-dd449fc5b949','題資福院平綠軒','江表祖','宋','宋诗','song-poetry','','[]','碧瓦丹棱轉盼成，一亭聊復寄閑情。',64,'全唐诗/poet.song.196000.json','["碧瓦丹棱轉盼成，一亭聊復寄閑情。", "人如水墨畫中立，山向烟蕪盡處橫。", "舟入柳陰衝鷺去，簷依波面蔭魚行。", "題詩每愧臨流意，吟苦那知白髮生。"]'),
('2b5d2f19-0f7c-496f-b0f3-606fa2d83101','南雁山','陳埴','宋','宋诗','song-poetry','','[]','千峯歷罷寄山窗，酒力詩狂總未降。',64,'全唐诗/poet.song.196000.json','["千峯歷罷寄山窗，酒力詩狂總未降。", "月白洞門花落盡，天空華表鶴飛雙。", "崖邊瀑雪寒侵夢，澗底笙簫冷韻腔。", "且喜懶殘煨芋熟，不妨久話共秋缸。"]'),
('3f1bf4f7-58af-4628-8576-3d3e4821d24d','宿難老堂','張伯常','宋','宋诗','song-poetry','','[]','漆園秋凈夜堂虛，偶伴橫林隠者居。',64,'全唐诗/poet.song.196000.json','["漆園秋凈夜堂虛，偶伴橫林隠者居。", "紙縐白雲垂帳厚，荻篩明月下簾疏。", "玉棋子奪三軍令，金剪刀翻數體書。", "疏廣拂衣慚不早，芰荷舟舫草茅蘆。"]'),
('bfeb9eba-0256-457e-82c2-13a0f4a95d7e','題雙峰顯祖院','張伯常','宋','宋诗','song-poetry','','[]','煖脈勻青地上苔，拂塵題柱記花開。',32,'全唐诗/poet.song.196000.json','["煖脈勻青地上苔，拂塵題柱記花開。", "海風一夜吹山雨，却送春寒入寺來。"]'),
('c9f7a6e0-d3ad-4893-bb3d-e8f84cf7ff05','述易述雅二章與趙清臣制帥  其一','袁甫','宋','宋诗','song-poetry','','[]','六十四卦，惟謙純吉。',80,'全唐诗/poet.song.196000.json','["六十四卦，惟謙純吉。", "九四大臣，居位以德。", "滿則易敧，盈兮斯食。", "惟謙下人，不違天則。", "此則伊何，元無損益。", "澄然太空，秉心惟一。", "明哲保身，神所輔翊。", "持此撝謙，與宋無極。"]'),
('8f0c6674-4bae-4dc5-b168-05327d0d383d','述易述雅二章與趙清臣制帥  其二','袁甫','宋','宋诗','song-poetry','','[]','大雅不作，訏謨音希。',80,'全唐诗/poet.song.196000.json','["大雅不作，訏謨音希。", "公既奏功，衮衣盍歸。", "歸矢爾謨，琅琅厥辭。", "用添帝聰，燭于幾微。", "天位孔艱，夙夜弼違。", "逆耳爲忠，隠情乃欺。", "擇乎二者，上帝監茲。", "煌煌祖業，忠臣念之。"]'),
('6876b447-4702-4e4a-8e06-e69ef0ab507b','三衢效周雅作鹿鳴宴詩三章  其一','袁甫','宋','宋诗','song-poetry','','[]','鹿鳴鹿鳴，呦呦之聲。',40,'全唐诗/poet.song.196000.json','["鹿鳴鹿鳴，呦呦之聲。", "我有嘉賓，柯山之英。", "來燕公堂，天府是升。", "同我鄉老，遹觀厥成。"]'),
('b07860fd-4f97-48a8-858f-3ca41528fac2','三衢效周雅作鹿鳴宴詩三章  其二','袁甫','宋','宋诗','song-poetry','','[]','鹿鳴鹿鳴，食苹與蒿。',42,'全唐诗/poet.song.196000.json','["鹿鳴鹿鳴，食苹與蒿。", "我有嘉賓，柯山之翹。", "歲逢丑矣，喜見斗杓。", "我有旨酒，嘉賓是招是邀。"]'),
('cd53044f-18c6-4da1-9b3c-2927b12d4192','三衢效周雅作鹿鳴宴詩三章  其三','袁甫','宋','宋诗','song-poetry','','[]','鹿鳴鹿鳴，惠我好音。',43,'全唐诗/poet.song.196000.json','["鹿鳴鹿鳴，惠我好音。", "我有嘉賓，言獻其琛。", "雖則軒裳，不改山林。", "我有十箴，以淑我嘉賓之心。"]'),
('0e09f155-2357-4b88-9bdd-e87f41c52f5f','朝陽三章  其一','袁甫','宋','宋诗','song-poetry','','[]','日之出矣，于彼扶桑。',51,'全唐诗/poet.song.196000.json','["日之出矣，于彼扶桑。", "鳳之鳴矣，于彼高岡。", "匪高岡則鳴，朝陽之光。", "君子如鳳，愛此朝陽。", "純德孔明，聞于四方。"]'),
('9bfded1a-f3f5-44ba-98b9-863e9d6b0187','朝陽三章  其二','袁甫','宋','宋诗','song-poetry','','[]','日之出矣，其光融融。',51,'全唐诗/poet.song.196000.json','["日之出矣，其光融融。", "鳳之鳴矣，其聲雝雝。", "鳴于何所，于彼梧桐。", "鳳兮鳳兮，和樂沖沖。", "匪鳳匪桐，在君子之躬。"]'),
('38183b1d-b5e9-44ab-aa08-9521849dfb3e','朝陽三章  其三','袁甫','宋','宋诗','song-poetry','','[]','日之出矣，萬象光明。',50,'全唐诗/poet.song.196000.json','["日之出矣，萬象光明。", "鳳之儀矣，簫韶之音。", "觀彼儀鳳，以觀我生。", "生生不息，匪虧匪盈。", "面此朝陽，默養和平。"]'),
('47ccfed3-d928-4d6a-8f2a-e2ae435f3023','和韓履善韻','袁甫','宋','宋诗','song-poetry','','[]','雨雪霏霏，青山華巔。',140,'全唐诗/poet.song.196000.json','["雨雪霏霏，青山華巔。", "能令山老，曷不老泉。", "雪高高山，雪深深淵。", "山自寂寂，泉自涓涓。", "我愛嶙峋，亦愛漪漣。", "雪兮入水，我觀其瀾。", "雪也在山，我取而餐。", "入水不見，依舊靈源。", "在山見雪，不見蒼然。", "蒼然雖改，巋然則存。", "見與不見，神光渾全。", "悟此雪詞，龜龍參前。", "一止一流，誰合誰分。", "忘言爲贅，言本無言。"]'),
('4288384b-6e58-4b46-b78e-d582ba5330cd','和晉齋兄韻','袁甫','宋','宋诗','song-poetry','','[]','斟酌元氣，斗爲帝車。',240,'全唐诗/poet.song.196000.json','["斟酌元氣，斗爲帝車。", "四時迭運，其信也且。", "天道不言，莫非教歟。", "日之升矣，雲翳掃除。", "本無體質，湛然太虛。", "歷山舜耕，雷澤舜漁。", "天德首出，茲焉權輿。", "晉齋作詩，誨語勤劬。", "我處山樊，飲水飯蔬。", "一雨蘇旱，民氣歡如。", "東鄰殺牛，西鄰刲豬。", "市賈不售，始到吾廬。", "買來烹之，每食無餘。", "凉哉枕簟，凄其葛綀。", "忽念世塗，滔滔淪胥。", "自昔興亡，具載詩書。", "蠱弊極矣，誰與爬梳。", "已而諦思，驚餌如魚。", "誰謂王門，可輕曳裾。", "觀詩末章，荷兄警予。", "老冉冉至，虛度望舒。", "學貴密察，勿事恢疏。", "一念微差，惡草必鋤。", "真剛大勇，那可躊躇。"]'),
('b192bc77-6339-4f7b-b235-a3573c515ebb','和惠宰修縣學韻','袁甫','宋','宋诗','song-poetry','','[]','人爵非貴，天爵惟尊。',180,'全唐诗/poet.song.196000.json','["人爵非貴，天爵惟尊。", "賢哉惠侯，興學祁門。", "祁門之士，夙號有文。", "兌習久廢，索居離羣。", "自侯來思，銳志興復。", "士脫舊穴，遷于喬木。", "人性本善，混混源泉。", "四端素具，若火始然。", "誰其啟之，君子德風。", "既修學宮，藏修其中。", "內養克充，外養亦備。", "爾不吾負，吾寧爾棄。", "壇名舞雩，樂道無欲。", "梁跨幽澗，潺潺潄玉。", "面此清致，皆學之助。", "本心融明，庶幾寡過。", "滔滔世途，人而匪天。", "兒童之戲，殆類紙鳶。"]'),
('070e2496-dda9-4aa2-ad91-cd2e281681f7','番陽喜晴贈幕僚','袁甫','宋','宋诗','song-poetry','','[]','大江以東，歲屢弗康。',240,'全唐诗/poet.song.196000.json','["大江以東，歲屢弗康。", "民病未蘇，正茲憂惶。", "一雨六旬，巨浸湯湯。", "我告上帝，是祈是禳。", "我來宿齋，室名朝陽。", "顧瞻斯名，與我心當。", "天告我兆，厥應果彰。", "朝陽一升，陰沴伏藏。", "衆水歸壑，殃轉爲祥。", "民奠攸居，歲保金穰。", "耄倪載詠，喜氣洋洋。", "匪我顓蒙，能動上蒼。", "頼我諸友，罔或怠荒。", "齋事孔明，純誠是將。", "上帝昭格，隨此瓣香。", "我勉諸友，秉德日彊。", "朝陽在我，自然發光。", "陽復之始，養而勿傷。", "常如對帝，中正齋莊。", "乃保終吉，以活吾氓。", "稍或安肆，罔念作狂。", "政刑弗謹，號令弗臧。", "天非可恃，祥覆爲殃。", "敬之敬之，斯須勿忘。"]'),
('07978d71-88f0-42a7-8d94-dbe2eb2e6f24','贈韓拙堂','袁甫','宋','宋诗','song-poetry','','[]','世所謂巧，請爲翁說。',180,'全唐诗/poet.song.196000.json','["世所謂巧，請爲翁說。", "巧于利口，佞辭河決。", "何如吉人，其言吶吶。", "巧于附勢，炙手可熱。", "何如節士，剛腸若鐵。", "巧于營生，百計漁奪。", "何如儒家，冷淡生活。", "拙反爲巧，巧乃大拙。", "驀然猛省，比論未徹。", "本無巧拙，奚較優劣。", "大道融融，曠兮太空。", "惡不待攻，善與人同。", "客訪拙翁，携酒相從。", "客去西東，翁數飛鴻。", "春日烘烘，適興携筇。", "興盡呼童，燕坐堂中。", "一門雍雍，蘭玉玲瓏。", "客賀拙翁，笑倚長松。"]'),
('78eafac0-b508-4deb-a28f-8ddae9b5fd00','題梅四首  其一','袁甫','宋','宋诗','song-poetry','','[]','占斷春光，水邊橫枝。',20,'全唐诗/poet.song.196000.json','["占斷春光，水邊橫枝。", "欲識生意，未著花時。"]'),
('36591bb5-b869-4b18-955f-2a7095bf3520','題梅四首  其二','袁甫','宋','宋诗','song-poetry','','[]','雪欺梅耶，抑梅欺雪。',20,'全唐诗/poet.song.196000.json','["雪欺梅耶，抑梅欺雪。", "孤高之操，凜凜清絕。"]'),
('b753681c-8fe8-48a1-bcab-8b3d0cfa9e66','題梅四首  其三','袁甫','宋','宋诗','song-poetry','','[]','花勿盡開，盡開香歇。',20,'全唐诗/poet.song.196000.json','["花勿盡開，盡開香歇。", "勿待月圓，纔圓即缺。"]'),
('f6842910-7010-42f9-a24d-a2650c269a2d','題梅四首  其四','袁甫','宋','宋诗','song-poetry','','[]','竹外一枝，嘯傲東風。',20,'全唐诗/poet.song.196000.json','["竹外一枝，嘯傲東風。", "許多真趣，在有無中。"]'),
('18666a84-1e5e-482d-a932-5490b336d71a','石松子','袁甫','宋','宋诗','song-poetry','','[]','殻堅于石，色白于雪。',182,'全唐诗/poet.song.196000.json','["殻堅于石，色白于雪。", "仁在其中，香味清絕。", "况之松子，格韻度越。", "庭前柏樹，視此亦劣。", "松柏著土，其子乃結。", "此仁無根，更何所著。", "松柏有種，有枯有活。", "此仁無種，生生不滅。", "天不能災，人不能伐。", "吾欲令此仁普徧廣博，吾欲令此仁取之不竭。", "家家具足，可採可擷。", "人人圓成，可咀可嚼。", "初無奧旨，亦無祕訣。", "不假思量，何勞論說。", "箇中渾全，了無分別。", "仰見高山兮，石洞之穴。", "俯此清泉兮，萬古不涸。"]'),
('043a539a-61bf-48ac-9f6d-297ef2706ed0','江東巡部紀行','袁甫','宋','宋诗','song-poetry','','[]','春過三之一，輕車走阡陌。',288,'全唐诗/poet.song.196000.json','["春過三之一，輕車走阡陌。", "平坂抹池陽，迤邐山路埆。", "風顛吹人面，雪滑皸人足。", "忽然銅鉦掛，九華醒兩目。", "自經千萬劫，寒翠光堪摘。", "半霄非人間，大江橫其側。", "行行逼宣州，麻姑正面矗。", "且上敬亭山，感慨懷李白。", "聽說三洞天，渴見恨無翮。", "巖幽鬼神哭，罅開星月燭。", "金沙爛吾前，祖師燈未沒。", "賡酬二三子，不覺詩筆禿。", "歙州我舊遊，迎笑兒童簇。", "本無棠蔭芾，漫云恩波沐。", "黄山悵無緣，不得搜仙窟。", "祁門山何如，險與石埭埒。", "山花溪邊明，時有新鳬浴。", "古木龍吟嘯，巨石虎蹲伏。", "偉哉岳鄂王，提兵舊盤礴。", "像設儼遺祠，光芒射斗宿。", "凌晨拜祠下，憂思心惻惻。", "無心惜落花，惟愁民捐瘠。", "浮梁與樂安，五十笑步百。", "幸瞻慈湖祠，風聲尚堪憶。"]'),
('33e33ed4-825b-47f3-9f8f-8a6b87e6850e','和高應朝','袁甫','宋','宋诗','song-poetry','','[]','明越兩相望，別久忘歲月。',72,'全唐诗/poet.song.196000.json','["明越兩相望，別久忘歲月。", "今秋對標榘，喜見冰玉潔。", "實材信有用，至剛元不折。", "青青歲寒松，不畏霜與雪。", "世道有夷險，人心難泯滅。", "煩公作津梁，勿使微言絕。"]'),
('774f679d-84dc-429a-b2c6-58b72e77f840','贈單判官秩滿言歸','袁甫','宋','宋诗','song-poetry','','[]','達士如弦直，直乃根性天。',120,'全唐诗/poet.song.196000.json','["達士如弦直，直乃根性天。", "平易無他事，大道本自然。", "吁嗟機巧人，屈曲而拘攣。", "不求心境靜，但取世俗妍。", "我來官柯山，同僚單君賢。", "贊畫得佽助，直道無盤旋。", "廉介味已熟，恬退性所便。", "兩載且追隨，使我無大愆。", "臨行重惜別，贈君可忘言。", "所願松柏操，歲寒毋變遷。"]'),
('bbd914e2-b6d6-40e2-a152-b37f043604ff','寄題夏時甫曉山亭詩','袁甫','宋','宋诗','song-poetry','','[]','夏君人中英，訥齋天下士。',132,'全唐诗/poet.song.196000.json','["夏君人中英，訥齋天下士。", "襟期脩篁友，節操孤松比。", "大書曉山扁，山色來棐几。", "愛此朝氣爽，未明攬衣起。", "訥齋我婦翁，頗曾窺涯涘。", "結交折輩行，逢人說夏子。", "因讀曉山吟，令我慨生死。", "人世亦何爲，仕宦聊爾爾。", "孰知死不朽，香名垂千祀。", "此人不復得，此詩誰能似。", "時甫盍刻石，方山可對峙。"]'),
('de5650ad-cbab-45e4-b315-b9ded42c8898','分題得莫氏荷池','袁甫','宋','宋诗','song-poetry','','[]','我老貧無居，借宅橫水北。',132,'全唐诗/poet.song.196000.json','["我老貧無居，借宅橫水北。", "軒窗五月凉，四面繞脩竹。", "方塘貯清泉，綠浄蔭湖目。", "初疑青錢小，稍展圓蓋綠。", "紅妝出菡萏，斂萼似羞縮。", "清晨露華滋，掩苒耀容服。", "風來香十里，雨過珠百斛。", "全家在清凉，衾枕有餘馥。", "吾師老瞿曇，六入漸驅逐。", "塵囂化五濁，熱惱變三伏。", "食實餐其根，對案何用肉。"]'),
('63f57989-15a9-4d0b-8f12-442f4f81f3ca','螳蜋捕蟬詩','袁甫','宋','宋诗','song-poetry','','[]','鳴蜩善擇木，木美葉敷腴。',204,'全唐诗/poet.song.196000.json','["鳴蜩善擇木，木美葉敷腴。", "國于美蔭中，自慶無他虞。", "螳蜋伺其便，欲進復趦趄。", "怒臂俄一施，捕取如囚拘。", "委身膏利吻，性命纔須臾。", "均之細微物，一何强弱殊。", "蜩乎汝無識，自知其過歟。", "物在宇宙間，謹默迺安居。", "今汝獨聒聒，晝夜長喧呼。", "汝閙力不足，彼靜智有餘。", "勝負從此決，誰謂汝非辜。", "螳蜋既得意，自謂真良圖。", "那知僅一飽，燕鵲已窺覦。", "出爾反乎爾，胡能獨全軀。", "乃知禍與福，不係巧與愚。", "嘵嘵固不免，默默復何如。", "置之不足道，燕坐觀厥初。"]'),
('536252c6-df29-46d9-962f-c96f1b95fd21','忠孝詩','袁甫','宋','宋诗','song-poetry','','[]','曾子立言詔後世，戰陳無勇非孝也。',256,'全唐诗/poet.song.196000.json','["曾子立言詔後世，戰陳無勇非孝也。", "戰死猶留千古名，大夫赤心爲宗社。", "而况判死乃得生，父母遺體非輕捨。", "忠孝從來只一原，此道於今識者寡。", "慈湖老師遺墨在，光燄萬丈追風雅。", "發揮天經與地義，爲憐世人多聾啞。", "跋語流傳壯矣哉，忠由孝出非外假。", "厥今邊庭尚繹騷，其勢飆欻陵諸夏。", "孤忠步步踏實地，紙上陳言付土苴。", "報國即是報親恩，忠孝斷斷非二者。", "兩閫對峙貴通情，胸懷如水常善下。", "不見天高并地闊，要令物物歸化冶。", "雍容譚笑凈邊塵，直把兵氛都汛灑。", "名垂竹帛增親榮，入覲至尊醉金斚。", "到此純孝通神明，冥冥之中錫純嘏。", "病夫山中何所能，功成請將椽筆寫。"]'),
('c4145b45-9691-452d-8de3-f475aaa1f6ed','辛亥寒食清明之交杜陵先生暫歸省謁與諸生食罷游後園獨坐蕭然戲作長句示諸兒','袁甫','宋','宋诗','song-poetry','','[]','春風吹花次第芳，桃紅李白薔薇黄。',208,'全唐诗/poet.song.196000.json','["春風吹花次第芳，桃紅李白薔薇黄。", "榆錢柳絮飛欲狂，酴醾引蔓草木香。", "老人燕坐窺虞唐，目覽千載游八荒。", "羣兒奔趨如羣羊，走過東阡復西廂。", "歸來汗喘無可將，何如明窗治墨莊。", "讀誦經史聲琅琅，音節閒美非笙簧。", "有如農夫勤理秧，秋來乃有千斯倉。", "先生既至心不忙，背念衮衮傾三湘。", "一語蹇吃涕泗滂，老大空腹徒悲傷。", "聖明天子坐未央，收拾俊傑羅文章。", "褎然舉首充賢良，仲舒軾轍俱軒昂。", "吾家有子雛鳳凰，聲價一日馳帝鄉。", "隨羣逐隊恣頡頏，終抱糞壤如蜣蜋。"]'),
('2da7bc4e-120d-435a-9b3b-43133ce17639','和陸伯微韻','袁甫','宋','宋诗','song-poetry','','[]','皇都喜見天宇晴，好風拂掠條不鳴。',128,'全唐诗/poet.song.196000.json','["皇都喜見天宇晴，好風拂掠條不鳴。", "幽人領袖二三子，適意湧金門外行。", "雲岫重重仍翼翼，舉頭不愧林間翮。", "賞心樂事浩無涯，獨念黎元生理窄。", "胸中宿昔富兵機，氣壓賁育走且疲。", "卯年會見佛貍死，天數一定端可推。", "九重求士忘食息，三聘躬耕在昕夕。", "願君努力應時須，宇宙垂名長的皪。"]'),
('18707fe1-d1a6-4558-bb15-59a0c75e8b46','和楊秀甫韻','袁甫','宋','宋诗','song-poetry','','[]','天下大物山與泉，山泉爲蒙義皎然。',140,'全唐诗/poet.song.196000.json','["天下大物山與泉，山泉爲蒙義皎然。", "坐對巖巖聽潺潺，以茲名齋日周旋。", "楊君作詩老更妍，解把山泉寫天全。", "山谷松梅詠坡仙，到今筆語带芳鮮。", "松梅雙清固堪憐，孰似山泉浩無邊。", "顧我蒙養鑽彌堅，要參聖處力加鞭。", "楊君一見出佳篇，古淡端如朱絲絃。", "絃中傳雅奏，難共俗人言。", "我欲和君一兩聯，山泉入夢且高眠。"]'),
('a16930c1-35be-428d-a7e8-a09e3a4db9c6','見牡丹呈諸友','袁甫','宋','宋诗','song-poetry','','[]','從來洛花天下最，姚黄魏紫尤奇異。',192,'全唐诗/poet.song.196000.json','["從來洛花天下最，姚黄魏紫尤奇異。", "坐令百花失顔色，喚作國香誰是對。", "十年之前來新安，閲盡妖嬈興欲蘭。", "晚得一枝睡露蟬，分明好似畫中看。", "人世匆匆駒過隙，重遊正值春三月。", "園丁折得數般來，旋買甆瓶謾成列。", "殷紅照日更嫣然，輕素含風玉色鮮。", "中有楊妃曾一捻，咄哉尤物累天全。", "我今褰帷問疾苦，皇華那受妖花汙。", "擲置道旁何足惜，亦如佞人吾所惡。", "頓使心胸和且平，况聞麥隴香氣騰。", "處處一犁春雨足，家家合掌慶豐登。"]'),
('f8b5bd28-b1b6-4d89-9352-62bbca9c4ebf','湖月贈朱幾仲','袁甫','宋','宋诗','song-poetry','','[]','天上月，三五盈兮三五缺。',160,'全唐诗/poet.song.196000.json','["天上月，三五盈兮三五缺。", "湖中月，無缺無圓無生滅。", "天上月，蝦蟇妖精敢作孽。", "湖中月，能使癡蟇蹤影沒。", "豈是蟾兔不如龍，不知龍有何祕訣。", "甓社湖中看明月，湖中天上雙皎潔。", "湛盧令我書大字，老來百事懶且拙。", "惟有作字氣如虹，寫罷森森清徹骨。", "神龍見之應驤首，共伴寒光千古揭。", "夜夜明月照我字，我字照湖兩相埒。", "更得湛盧著佳句，便與盂城成三絕。"]'),
('b32ade68-0e65-44a5-b5d3-58d859136b8a','詠丹桂贈周純甫馮德厚  其一','袁甫','宋','宋诗','song-poetry','','[]','一種自然色，如吾方寸丹。',48,'全唐诗/poet.song.196000.json','["一種自然色，如吾方寸丹。", "天教傳信到，人莫作花看。", "骨氣超凡俗，聲名徹廣寒。", "留君良爲此，憶別鼻休酸。"]'),
('b7724ef9-d3bb-4564-bda3-e9b9ad5d751c','詠丹桂贈周純甫馮德厚  其二','袁甫','宋','宋诗','song-poetry','','[]','孤却團圓月，今朝桂子丹。',48,'全唐诗/poet.song.196000.json','["孤却團圓月，今朝桂子丹。", "莫教疏雨打，留向晚秋看。", "色借幽巖秀，香通古壑寒。", "癡兒被花笑，世味只辛酸。"]'),
('56d073bf-f77e-4fca-9618-75101ea2723a','和韓履善韻','袁甫','宋','宋诗','song-poetry','','[]','談經說史謾支離，大道寧容小智窺。',64,'全唐诗/poet.song.196000.json','["談經說史謾支離，大道寧容小智窺。", "山峙川流俱是妙，鳶飛魚躍兩忘機。", "識天乃樂天之樂，非我安知我不知。", "細讀新詩消息好，桃花見後更無疑。"]'),
('3a5b1c20-f02a-47fc-96e2-1d194f3b7e59','和王伯友韻','袁甫','宋','宋诗','song-poetry','','[]','三春强半麥青青，是處田家只望晴。',64,'全唐诗/poet.song.196000.json','["三春强半麥青青，是處田家只望晴。", "雪壓霜欺愁正極，日融雲浄眼增明。", "紛紛民瘼關吾念，得得天公相此行。", "更問老農官與吏，幾人貪濁幾人清。"]'),
('a4b5eebb-5d84-47d9-af8b-eff878a54a0b','和毛中書勸農韻三首  其一','袁甫','宋','宋诗','song-poetry','','[]','曲奏梅花促曉更，更聲方斷又鳴鉦。',64,'全唐诗/poet.song.196000.json','["曲奏梅花促曉更，更聲方斷又鳴鉦。", "籃輿咿軋親巡野，櫪馬喧填看勉耕。", "酒酌田翁添醉色，澤均牧叟助歡聲。", "天公也欲催佳句，特放晴光分外明。"]'),
('b7fd95ca-9fb3-4a1b-a507-58b832164cdc','和毛中書勸農韻三首  其二','袁甫','宋','宋诗','song-poetry','','[]','歷遍田疇問我農，都言杼柚久虛空。',64,'全唐诗/poet.song.196000.json','["歷遍田疇問我農，都言杼柚久虛空。", "吏胥祇是工椎剝，倉廩何曾識腐紅。", "願得家家歌樂歲，直須日日扇和風。", "如今拙手徒餐粟，慚見天民四者窮。"]'),
('b8ccd718-558d-4386-8426-697cdacebe94','和毛中書勸農韻三首  其三','袁甫','宋','宋诗','song-poetry','','[]','勞農因得步河橋，仰視前賢隔九霄。',64,'全唐诗/poet.song.196000.json','["勞農因得步河橋，仰視前賢隔九霄。", "凡骨難仙安素履，腐儒學吏守邦條。", "荷公美意鞭駑質，惠我名篇勝翠翹。", "痛飲春醪那可强，胸中磊塊把詩澆。"]'),
('3ed12d32-575c-43e3-b02d-86b30fd929f7','和越帥汪仲宗韻','袁甫','宋','宋诗','song-poetry','','[]','稽山窟宅盡神仙，多少棠陰屬鉅賢。',64,'全唐诗/poet.song.196000.json','["稽山窟宅盡神仙，多少棠陰屬鉅賢。", "萬壑千巖長似舊，一翁二季美無前。", "風流自昔遺芳在，衣鉢于今盛事傳。", "行見直聲追軌躅，豈徒慶禮侈賓筵。"]'),
('96118871-ca89-4308-b888-5eeb1fdc75ce','和南康守韻','袁甫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','結亭故事重拈出，領略匡廬高更高。',64,'全唐诗/poet.song.196000.json','["結亭故事重拈出，領略匡廬高更高。", "身在山中迷面目，心遊局外見分毫。", "平湖雪意漫天急，古木風聲捲地號。", "此地徐徐鼛鼓節，知公一念在民勞。"]'),
('387a0777-2d33-4be4-b8c6-85bb3f1fb081','和履善遊三洞天韻','袁甫','宋','宋诗','song-poetry','','[]','長空萬里普光明，此地緣何獨著靈。',64,'全唐诗/poet.song.196000.json','["長空萬里普光明，此地緣何獨著靈。", "不是天晴窺白日，愛他月黑滿疏星。", "石松有子能呈巧，金囤無沙似遁形。", "驀地回頭千萬點，諦觀頓使我心醒。"]'),
('6036f72d-1eba-472f-bff7-08578aafcb75','和令君歲寒亭韻','袁甫','宋','宋诗','song-poetry','','[]','老幹森森當翠屏，壁間詩句有留名。',64,'全唐诗/poet.song.196000.json','["老幹森森當翠屏，壁間詩句有留名。", "昔逢利口擠之死，今伴蒼髯凜若生。", "雪壓枝擎猶有力，月高林靜更雙清。", "撫松似共黄門語，况聽蕭蕭枕上聲。"]'),
('c45b11d2-4edc-44d7-93a0-412beefd9310','蒙程伯寓知府給事以僕生祠妙唱見寄輒次韻奉酬','袁甫','宋','宋诗','song-poetry','','[]','聞道邦人尚去思，栽松植竹遶叢祠。',64,'全唐诗/poet.song.196000.json','["聞道邦人尚去思，栽松植竹遶叢祠。", "要知獨立無言處，正似危邦援絕時。", "平世功名付圖畫，暮年活計在鉤絲。", "謝公旌旆巡山後，千里慇懃寄好詞。"]'),
('cd88eaed-712b-4477-90f7-83b8dd5faeb8','新安鄉會','袁甫','宋','宋诗','song-poetry','','[]','紫陽自是神仙窟，誰泛仙槎競問津。',64,'全唐诗/poet.song.196000.json','["紫陽自是神仙窟，誰泛仙槎競問津。", "二妙先傳聯璧喜，九人齊著賜袍新。", "自憐十載龍門客，來領三科燕席賓。", "酌頌年家無浪語，黄山高節兩嶙峋。"]'),
('1a7ce7d5-3a0c-4c02-979d-56bb26788a82','送池陽張倅奉祠歸清江二首  其一','袁甫','宋','宋诗','song-poetry','','[]','題輿名滿大江東，忽憶家山閤皂中。',64,'全唐诗/poet.song.196000.json','["題輿名滿大江東，忽憶家山閤皂中。", "孤棹賦歸猶带雪，深衣養浩直摩空。", "從教風月分多少，獨抱春秋究始終。", "籍湜近來知叛否，只君不負紫陽翁。"]'),
('45a81aa5-c1a0-4a2a-b331-67d7db95fd8a','送池陽張倅奉祠歸清江二首  其二','袁甫','宋','宋诗','song-poetry','','[]','自憐凡骨未能仙，每對仙都輒爽然。',64,'全唐诗/poet.song.196000.json','["自憐凡骨未能仙，每對仙都輒爽然。", "序齒十年兄弟行，論交一日友朋緣。", "干戈滿地心憂國，事業彌天世急賢。", "已把封章排紫闥，未容問舍與求田。"]'),
('518eb195-623a-479e-8f4e-8f2c6d5f7671','魏鴻禧敘別二首  其一','袁甫','宋','宋诗','song-poetry','','[]','世間萬事盡筌蹄，塵外工夫好者希。',64,'全唐诗/poet.song.196000.json','["世間萬事盡筌蹄，塵外工夫好者希。", "大道精通元自在，旁門淺陋謾多岐。", "六年鐵冶勞經畫，九轉金丹默受持。", "歸去小溪溪上坐，要求消息在嬰兒。"]'),
('72dc220c-5003-49cc-888a-53d9bed46230','魏鴻禧敘別二首  其二','袁甫','宋','宋诗','song-poetry','','[]','別有金丹簡且真，不煩火候不勞神。',64,'全唐诗/poet.song.196000.json','["別有金丹簡且真，不煩火候不勞神。", "自知自信融融樂，無慮無營盎盎春。", "天地遊心元廣大，風雲入句更精神。", "我將歸去償茲願，溪上相逢只幅巾。"]'),
('3fc47c43-6ce6-4725-9acb-dc3d30868980','釣臺','袁甫','宋','宋诗','song-poetry','','[]','朔風吹我到嚴灘，擁被掀篷一破顔。',64,'全唐诗/poet.song.196000.json','["朔風吹我到嚴灘，擁被掀篷一破顔。", "寒色侵凌欺白髮，雪花撩亂失青山。", "未消據案千塵積，且愛哦詩一餉閒。", "慚愧釣臺風韻在，他年歸隠許躋攀。"]'),
('9ad23fdf-5894-4236-b20a-3e69d5ea1805','晦庵文公祠堂用令君韻','袁甫','宋','宋诗','song-poetry','','[]','當年獨抱伯牙名，身後祠堂列佩衾。',64,'全唐诗/poet.song.196000.json','["當年獨抱伯牙名，身後祠堂列佩衾。", "官職平生安義命，詩書終老惜光陰。", "一椽古歙溪山窟，千古長松風月林。", "彭令經營真有趣，箇中應契老師心。"]'),
('71571f77-0fd5-4862-96f3-5c7aa7342e8c','岳忠武祠三首  其一','袁甫','宋','宋诗','song-poetry','','[]','當年老檜肆欺謾，忠武哀哉抱寸丹。',64,'全唐诗/poet.song.196000.json','["當年老檜肆欺謾，忠武哀哉抱寸丹。", "頼有皇天爲吐氣，豈無青史更誅姦。", "字留陳迹何年泯，烟鎖空山盡日閒。", "世事關心眠不得，今朝下涕爲潸潸。"]'),
('ecdfb4af-552c-4d4f-b6e9-4fd0b41294ff','岳忠武祠三首  其二','袁甫','宋','宋诗','song-poetry','','[]','兒時曾住練江頭，長老頻頻說岳侯。',64,'全唐诗/poet.song.196000.json','["兒時曾住練江頭，長老頻頻說岳侯。", "手握天戈能決勝，心輕人爵祇尋幽。", "堪嗟爝火當時滅，誰信長川萬古流。", "機會莫言今到手，却愁無飯飽貔貅。"]'),
('9ac4ff7a-dd7e-42ad-9df4-4bf0ad25dd12','岳忠武祠三首  其三','袁甫','宋','宋诗','song-poetry','','[]','背嵬軍馬戰無儔，壓盡當年幾列侯。',64,'全唐诗/poet.song.196000.json','["背嵬軍馬戰無儔，壓盡當年幾列侯。", "先輩有聞多散軼，後生誰識發潛幽。", "傷心咄咄權臣事，滿眼滔滔債帥流。", "槌剝到今渾似鬼，向人休說是貔貅。"]'),
('cc1a8eb0-c484-4ab8-a587-92b2f824802f','詠東松庵','袁甫','宋','宋诗','song-poetry','','[]','作意東松訪舊聞，山巖窟裏梵宮存。',64,'全唐诗/poet.song.196000.json','["作意東松訪舊聞，山巖窟裏梵宮存。", "矮樓蛙井身如蟄，峭壁魚鱗手可捫。", "草草反成多景致，慳慳別是一乾坤。", "輸他飽飯安眠處，朝暮烟霞看吐吞。"]'),
('922f4671-3041-40e3-a0f7-4bac895822aa','褒三湯孝行','袁甫','宋','宋诗','song-poetry','','[]','誰道田家不讀書，一門孝行與人殊。',64,'全唐诗/poet.song.196000.json','["誰道田家不讀書，一門孝行與人殊。", "直將自已通天地，豈是無心惜體膚。", "人願生兒皆似此，神如祐善肯忘吾。", "勉哉一念勤推廣，已辦嘉名里巷呼。"]'),
('666db40e-01bd-4995-8183-05c934878cdc','讀朱冠之詩有作三首  其一','袁甫','宋','宋诗','song-poetry','','[]','孔孟宗師心中的，回由評品手持衡。',64,'全唐诗/poet.song.196000.json','["孔孟宗師心中的，回由評品手持衡。", "至剛大勇本來有，由義居仁熟處行。", "說到孤忠推自孝，輒拚一死肯偷生。", "此篇此語令人醒，夜半青燈看到明。"]'),
('4d8046d7-f838-4959-ac0c-57b6aef8a5b4','讀朱冠之詩有作三首  其二','袁甫','宋','宋诗','song-poetry','','[]','浮雲擘破月華明，怎得浮雲不再生。',64,'全唐诗/poet.song.196000.json','["浮雲擘破月華明，怎得浮雲不再生。", "幾度月明雲幾擘，全無雲翳月全清。", "後生欲解憑誰問，先覺雖知肯盡明。", "苦硬工夫須徹底，秋雲漠漠一輪橫。"]'),
('181b9ed3-e12b-4ed0-aed7-a4d4ec93cb5d','讀朱冠之詩有作三首  其三','袁甫','宋','宋诗','song-poetry','','[]','多言外好中何有，有德之言春意融。',64,'全唐诗/poet.song.196000.json','["多言外好中何有，有德之言春意融。", "惟一性天真洞徹，許多事理盡流通。", "句新悅耳源先涸，思苦雕肝味易窮。", "自古才人皆患此，就中崛强是揚雄。"]'),
('c32e87f7-4004-4180-9035-aab4a991de5b','題趙氏連理木圖','袁甫','宋','宋诗','song-poetry','','[]','連理呈祥炳寸丹，巽齋高致拂雲端。',64,'全唐诗/poet.song.196000.json','["連理呈祥炳寸丹，巽齋高致拂雲端。", "須知念念通冥漠，不見聲聲說急難。", "義槩莫如生死際，家風要使子孫看。", "城南我祖嘉名似，從此心期共不刊。"]'),
('0cb6ca82-163b-4afd-9cd5-8e12a3e58408','留無邪字','袁甫','宋','宋诗','song-poetry','','[]','此駿産渥洼，神奇莫浪誇。',24,'全唐诗/poet.song.196000.json','["此駿産渥洼，神奇莫浪誇。", "相期千里志，贈子字無邪。"]'),
('4b4318e1-453b-43e4-b4ce-e3800d2b052b','遊敬亭山用謫仙韻二首  其一','袁甫','宋','宋诗','song-poetry','','[]','黄檗道場古，裴公心事閒。',24,'全唐诗/poet.song.196000.json','["黄檗道場古，裴公心事閒。", "白詩三絕併，那似敬亭山。"]'),
('7e6d6215-ed14-43f5-8671-7cf1d30b5c27','遊敬亭山用謫仙韻二首  其二','袁甫','宋','宋诗','song-poetry','','[]','事從塵世去，心共白雲閒。',24,'全唐诗/poet.song.196000.json','["事從塵世去，心共白雲閒。", "不作遊山計，朝朝飽看山。"]'),
('1bf8fbb6-171d-438d-a0c5-0ba7b724c7cd','衢學講堂更名時習和貳車韻五首  其一','袁甫','宋','宋诗','song-poetry','','[]','道心無壞亦無成，只怕微雲點太清。',32,'全唐诗/poet.song.196000.json','["道心無壞亦無成，只怕微雲點太清。", "重坎之亨人不識，一輪素月本來明。"]'),
('c4287c28-1919-4a6a-9667-6f83ffae0c2f','衢學講堂更名時習和貳車韻五首  其二','袁甫','宋','宋诗','song-poetry','','[]','意味澄然未動初，綱常大道本同趨。',32,'全唐诗/poet.song.196000.json','["意味澄然未動初，綱常大道本同趨。", "直須麗澤工夫熟，便是當年詠舞雩。"]'),
('972e0b2a-ca0d-43a5-98fd-d6081f54eec6','衢學講堂更名時習和貳車韻五首  其三','袁甫','宋','宋诗','song-poetry','','[]','終身不察是凡人，一日三回省此身。',32,'全唐诗/poet.song.196000.json','["終身不察是凡人，一日三回省此身。", "參也親傳端的處，品題宜亞不違仁。"]'),
('e29186cd-1eae-4733-86a0-d5951f25344e','衢學講堂更名時習和貳車韻五首  其四','袁甫','宋','宋诗','song-poetry','','[]','緬懷周道意悠長，事業姬公念不忘。',32,'全唐诗/poet.song.196000.json','["緬懷周道意悠長，事業姬公念不忘。", "宗廟百官誰識者，仲由也只許升堂。"]'),
('cf72e707-edfe-425e-bfc0-542d64bbb911','衢學講堂更名時習和貳車韻五首  其五','袁甫','宋','宋诗','song-poetry','','[]','莫道今人不古如，分明氣象魯之洙。',32,'全唐诗/poet.song.196000.json','["莫道今人不古如，分明氣象魯之洙。", "坤爻六二知何義，試叩膠庠學易徒。"]'),
('7ebf1b34-fe89-4b3b-81f5-b956feb8aa53','再用前韻  其一','袁甫','宋','宋诗','song-poetry','','[]','瑚璉區區只小成，休言果藝與忠清。',32,'全唐诗/poet.song.196000.json','["瑚璉區區只小成，休言果藝與忠清。", "聖師忘食兼忘老，地久天長日月明。"]'),
('7c96ad56-1a00-4c6f-bfd1-0623d0c43346','再用前韻  其二','袁甫','宋','宋诗','song-poetry','','[]','修慝之餘德復初，更須辨白舍并趨。',32,'全唐诗/poet.song.196000.json','["修慝之餘德復初，更須辨白舍并趨。", "善哉三語當年問，直到于今想從雩。"]'),
('17a49eee-3a15-4e21-8838-71700b86468f','再用前韻  其三','袁甫','宋','宋诗','song-poetry','','[]','兩地參天命曰人，靈龜端合取諸身。',32,'全唐诗/poet.song.196000.json','["兩地參天命曰人，靈龜端合取諸身。", "笑渠到處閒尋覓，直信人言井有仁。"]'),
('57d754a8-4432-47f7-89e9-5d9d20202b9b','再用前韻  其四','袁甫','宋','宋诗','song-poetry','','[]','逝者如斯晝夜長，會心能使百憂忘。',32,'全唐诗/poet.song.196000.json','["逝者如斯晝夜長，會心能使百憂忘。", "生前身後渾如此，絲竹之音孔子堂。"]'),
('48355eb7-5ef7-47c1-a2b9-272ba9bbc6a2','再用前韻  其五','袁甫','宋','宋诗','song-poetry','','[]','小時所學老何如，自詫西河不記洙。',32,'全唐诗/poet.song.196000.json','["小時所學老何如，自詫西河不記洙。", "曾子斯言譏背本，祇今猶足警吾徒。"]'),
('a9cdd796-3eef-454f-a82b-ec26457165a1','再用前韻  其一','袁甫','宋','宋诗','song-poetry','','[]','逾年政化一無成，敢道民和獄訟清。',32,'全唐诗/poet.song.196000.json','["逾年政化一無成，敢道民和獄訟清。", "不以旁人評得失，箇中一點自知明。"]'),
('51364fc5-977d-4d0b-ae9f-35bd4429fb2b','再用前韻  其二','袁甫','宋','宋诗','song-poetry','','[]','心事如何忍負初，官居每憶過庭趨。',32,'全唐诗/poet.song.196000.json','["心事如何忍負初，官居每憶過庭趨。", "勤勤撫字今微驗，雨足春疇不待雩。"]'),
('938d34e0-1cbc-4e57-abf6-93e5ca6063de','再用前韻  其三','袁甫','宋','宋诗','song-poetry','','[]','誠心諭俗淑斯人，莫寶金珠寶此身。',32,'全唐诗/poet.song.196000.json','["誠心諭俗淑斯人，莫寶金珠寶此身。", "昨日偶拈鄉記看，幾家孝養漸興仁。"]'),
('e2cb524a-b16a-4b25-baed-cce7251443c9','再用前韻  其四','袁甫','宋','宋诗','song-poetry','','[]','吾儒政事話頭長，步步詩書可蹔忘。',32,'全唐诗/poet.song.196000.json','["吾儒政事話頭長，步步詩書可蹔忘。", "齊相未知真不擾，無端遜與蓋公堂。"]'),
('cf270406-d0c4-48f8-be26-a2b63fd15b04','再用前韻  其五','袁甫','宋','宋诗','song-poetry','','[]','蒲盧喻政意何如，此語源流亦自洙。',32,'全唐诗/poet.song.196000.json','["蒲盧喻政意何如，此語源流亦自洙。", "若願小民皆類我，須知類我始生徒。"]'),
('f838a479-0ad1-4466-af78-7dbe90574458','時習堂記言五典也載賡前韻以歌之  其一','袁甫','宋','宋诗','song-poetry','','[]','事親盡孝自天成，鑑本無塵水本清。',32,'全唐诗/poet.song.196000.json','["事親盡孝自天成，鑑本無塵水本清。", "相彼禽兮猶學習，靈烏反哺更分明。"]'),
('ba68a442-4b95-4099-b78b-fc40d76aad3f','時習堂記言五典也載賡前韻以歌之  其二','袁甫','宋','宋诗','song-poetry','','[]','習容齋戒適朝初，佩玉鏘鳴謹進趨。',32,'全唐诗/poet.song.196000.json','["習容齋戒適朝初，佩玉鏘鳴謹進趨。", "大分凜然冠屨判，一誠不散若郊雩。"]'),
('41b264db-1473-4722-876d-ea9a85988c61','時習堂記言五典也載賡前韻以歌之  其三','袁甫','宋','宋诗','song-poetry','','[]','齊家斷勿責他人，須信儀型只在身。',32,'全唐诗/poet.song.196000.json','["齊家斷勿責他人，須信儀型只在身。", "習習谷風譏義薄，交相愛也是爲仁。"]'),
('0281ff46-33ee-469e-b89b-f78ef04d43a8','時習堂記言五典也載賡前韻以歌之  其四','袁甫','宋','宋诗','song-poetry','','[]','徐行後長味深長，此道誰能篤不忘。',32,'全唐诗/poet.song.196000.json','["徐行後長味深長，此道誰能篤不忘。", "我欲講行鄉飲酒，大明上齒習斯堂。"]'),
('a826ecf4-e2c9-49ea-a5b7-b52af2feb71c','時習堂記言五典也載賡前韻以歌之  其五','袁甫','宋','宋诗','song-poetry','','[]','切偲取義思怡如，兌習工夫憶泗洙。',32,'全唐诗/poet.song.196000.json','["切偲取義思怡如，兌習工夫憶泗洙。", "泮水朋來方衮衮，三千攀附聖門徒。"]'),
('0de9e651-6e2c-47bd-a50f-ee7f2fac9794','再和時習五章章取禮記一句 王制習鄉上齒','袁甫','宋','宋诗','song-poetry','','[]','復禮工夫本易成，此心對越只寅清。',32,'全唐诗/poet.song.196000.json','["復禮工夫本易成，此心對越只寅清。", "居鄉上齒家常飯，此道于今晦不明。"]'),
('47112bd5-8433-4596-a70e-7c70f574d739','再和時習五章章取禮記一句 射義習射于澤','袁甫','宋','宋诗','song-poetry','','[]','蓬矢桑弧男子初，澤宮試事翼如趨。',32,'全唐诗/poet.song.196000.json','["蓬矢桑弧男子初，澤宮試事翼如趨。", "采蘩盈耳皆音節，盛樂何消待大雩。"]'),
('3169077c-c096-4f4d-a524-585df11a0f0a','再和時習五章章取禮記一句 月令鷹乃學習','袁甫','宋','宋诗','song-poetry','','[]','鷹猶知學况於人，羽翮沖霄具此身。',32,'全唐诗/poet.song.196000.json','["鷹猶知學况於人，羽翮沖霄具此身。", "須信數飛方解熟，熟之又熟即爲仁。"]'),
('b80723b5-4c22-428d-8b84-6cbc6fd00b81','再和時習五章章取禮記一句 玉藻習容觀玉聲','袁甫','宋','宋诗','song-poetry','','[]','佩玉之聲清越長，此身無故詎容忘。',32,'全唐诗/poet.song.196000.json','["佩玉之聲清越長，此身無故詎容忘。", "挈渠方屨圜冠士，登我光風霽月堂。"]'),
('3fdf673c-84be-49d6-9b3f-f5613f4f22f4','再和時習五章章取禮記一句 月令上丁習舞釋菜','袁甫','宋','宋诗','song-poetry','','[]','聖道洋洋滄海如，不流天下只流洙。',32,'全唐诗/poet.song.196000.json','["聖道洋洋滄海如，不流天下只流洙。", "上丁釋菜今非古，喚起遺風屬我徒。"]'),
('d0ca8fd5-ca02-4910-bdc5-5993da548cbb','壽趙處仁母夫人','袁甫','宋','宋诗','song-poetry','','[]','有子見知真西山，有孫又把桂枝攀。',32,'全唐诗/poet.song.196000.json','["有子見知真西山，有孫又把桂枝攀。", "堂前萱草年年綠，慶事天公定不慳。"]'),
('cca2d169-e006-43a1-9c5c-33cb0e02c37a','壽張亨之祖母夫人','袁甫','宋','宋诗','song-poetry','','[]','爲問蟠桃熟幾番，見兒髮白著衣斑。',32,'全唐诗/poet.song.196000.json','["爲問蟠桃熟幾番，見兒髮白著衣斑。", "孫枝又作紅蕖客，更願雲礽捧壽山。"]'),
('86ff432b-a8f7-4e34-989a-b8aeeb18265d','壽馮德厚三首  其一','袁甫','宋','宋诗','song-poetry','','[]','人生汩汩逐風波，祝子長年要若何。',32,'全唐诗/poet.song.196000.json','["人生汩汩逐風波，祝子長年要若何。", "一日洞然無障礙，元來佛法也無多。"]'),
('280e6161-df66-4f8e-aea1-b9c05fe18d04','壽馮德厚三首  其二','袁甫','宋','宋诗','song-poetry','','[]','麟經咀嚼造深微，攀取秋風第一枝。',32,'全唐诗/poet.song.196000.json','["麟經咀嚼造深微，攀取秋風第一枝。", "便把斯言爲子壽，崧高不用更吟詩。"]'),
