('61685c82-09aa-491a-bf9f-578618453a4f','見梅','袁甫','宋','宋诗','song-poetry','','[]','半月山行不識梅，近城纔見一枝開。',32,'全唐诗/poet.song.196000.json','["半月山行不識梅，近城纔見一枝開。", "呼童截竹敲冰水，盛取數枝隨轎來。"]'),
('ceafd2b4-e005-47fe-ac3c-db5a2299e007','元夕留城外','袁甫','宋','宋诗','song-poetry','','[]','三市香塵隘綺羅，遊人無奈月明何。',32,'全唐诗/poet.song.196000.json','["三市香塵隘綺羅，遊人無奈月明何。", "吾儂分得寬閒處，地闊天高得月多。"]'),
('8fd0b0d3-552e-405c-8238-b04c2f9144eb','憩折山市','袁甫','宋','宋诗','song-poetry','','[]','折山山下簇人烟，一似吳兒笑語喧。',32,'全唐诗/poet.song.196000.json','["折山山下簇人烟，一似吳兒笑語喧。", "始信臙脂溪水媚，木瓜分得也嫣然。"]'),
('ffb6a896-5210-46cd-b7a0-9b5698a741aa','耕樂詩四首  其一','袁甫','宋','宋诗','song-poetry','','[]','優游無事只耕田，顧我歸耕子已先。',32,'全唐诗/poet.song.196000.json','["優游無事只耕田，顧我歸耕子已先。", "可但千倉良足樂，不收一粒亦欣然。"]'),
('ecd6b8aa-348b-4b54-a247-965a453b922f','耕樂詩四首  其二','袁甫','宋','宋诗','song-poetry','','[]','一犁春雨趁農耕，歌咏康衢了此生。',32,'全唐诗/poet.song.196000.json','["一犁春雨趁農耕，歌咏康衢了此生。", "若有可憂方有樂，本無虧處亦無成。"]'),
('20c11b5f-7469-4a18-9a7b-8f9170f42d1f','耕樂詩四首  其三','袁甫','宋','宋诗','song-poetry','','[]','一片靈明自有田，當仁那肯遜儒先。',32,'全唐诗/poet.song.196000.json','["一片靈明自有田，當仁那肯遜儒先。", "歸來不說溪山好，只說癯仙氣浩然。"]'),
('903049e2-8eb7-4c37-a02d-3b0a0652a9be','耕樂詩四首  其四','袁甫','宋','宋诗','song-poetry','','[]','少時操筆代躬耕，老鶴如今太瘦生。',32,'全唐诗/poet.song.196000.json','["少時操筆代躬耕，老鶴如今太瘦生。", "已識箇中真樂地，誰云骨相費生成。"]'),
('20ab8611-0ec5-4fa3-9879-e3f7d3b4ff8b','題英烈廟','袁甫','宋','宋诗','song-poetry','','[]','二難千載牛山事，壓盡當年虎帳功。',32,'全唐诗/poet.song.196000.json','["二難千載牛山事，壓盡當年虎帳功。", "始屈終伸天赫赫，皇家特地侈真封。"]'),
('9a4cb688-3847-4101-b784-1bc70c9a2b60','題慈雲閣','袁甫','宋','宋诗','song-poetry','','[]','不見慈湖二十年，憂心如醉復如顛。',32,'全唐诗/poet.song.196000.json','["不見慈湖二十年，憂心如醉復如顛。", "我來忽見慈雲閣，恍若慈湖現我前。"]'),
('f44e160c-ee41-41fd-88c3-60d5c622c795','題陳和仲觀聚堂','袁甫','宋','宋诗','song-poetry','','[]','習庵築室，扁曰觀聚。',180,'全唐诗/poet.song.196000.json','["習庵築室，扁曰觀聚。", "堂前何有，萬象可覩。", "山如郛郭，烟雲吞吐。", "草木沃若，春光媚嫵。", "脩篁漫山，不知隆暑。", "何况秋空，呼日入戶。", "朔風吹雪，松聲如怒。", "上天下地，四方曰宇。", "物生其間，何可勝數。", "我于是觀，樂哉斯土。", "隨意作室，不華不窳。", "買山旋添，稍葺園圃。", "得趣幽閑，不入城府。", "良朋偶來，傾倒肺腑。", "不及時事，惟談鄒魯。", "朋去何爲，周易一部。", "消息盈虛，窮今亙古。", "觀乃自觀，寂無一語。"]'),
('7bbea0a9-c2c8-4e88-90e9-f478d3309311','題陳和仲尊明亭','袁甫','宋','宋诗','song-poetry','','[]','非德不尊，非道不明。',100,'全唐诗/poet.song.196000.json','["非德不尊，非道不明。", "爰取斯義，以名吾亭。", "亭在山巔，氣象巍然。", "山從何來，蜿蜿蜒蜒。", "我坐亭上，極目一望。", "群峯畢朝，尊無與抗。", "我撫亭下，萬狀難寫。", "一一分明，入我盞斝。", "有時携筇，偕二三朋。", "莫知我心，獨撫孤松。"]'),
('a5acc643-e5b3-4e12-9733-ea8f18c68e80','杜子墅留別','趙汝回','宋','宋诗','song-poetry','','[]','有朋不貴數，道合意自親。',72,'全唐诗/poet.song.196000.json','["有朋不貴數，道合意自親。", "早知離別難，會覿豈厭頻。", "青燈書閣下，細語交情真。", "酌此武陽泉，饌彼松江鱗。", "公庖復有携，得非知我貧。", "如何不我醉，明日隔征塵。"]'),
('4edb03d5-395c-42c4-a081-fead86c68d3e','漁父','趙汝回','宋','宋诗','song-poetry','','[]','衡嶽早來雨，湘江增綠波。',48,'全唐诗/poet.song.196000.json','["衡嶽早來雨，湘江增綠波。", "小舟浮似屋，香草結爲蓑。", "水定見魚影，夜清聞櫂歌。", "悠悠百年夢，醒少醉時多。"]'),
('80d34307-b33b-4d20-b428-ca963b388a3f','送李寅歸里','趙汝回','宋','宋诗','song-poetry','','[]','憐君竟不偶，每事與心違。',48,'全唐诗/poet.song.196000.json','["憐君竟不偶，每事與心違。", "南雪歲將暮，西江帆獨歸。", "停薪待官米，借宅共僧扉。", "吾老慙爲吏，相期尋釣磯。"]'),
('1121f643-160d-4aab-aa6c-2189b65f298e','東山堂','趙汝回','宋','宋诗','song-poetry','','[]','謝守登臨地，今爲博士居。',48,'全唐诗/poet.song.196000.json','["謝守登臨地，今爲博士居。", "由來好山水，常得近詩書。", "洞與衡嶽接，泉分玉井餘。", "年年爲吟事，春草不教鋤。"]'),
('8c09d183-fd07-4704-a6a9-c602cda84c9f','呈水心先生','趙汝回','宋','宋诗','song-poetry','','[]','鶴骨雖癯髮未斑，秋風鷗鷺共翛閒。',64,'全唐诗/poet.song.196000.json','["鶴骨雖癯髮未斑，秋風鷗鷺共翛閒。", "芙蓉夾徑纔通馬，楊柳沿池不礙山。", "外稿定於何日上，中興只在十年間。", "穀城片石無人識，胡騎堂堂出漢關。"]'),
('c08ed12f-6fc5-4a1f-944e-c60828b197b6','鴈山','趙汝回','宋','宋诗','song-poetry','','[]','木葉新時雨亦晴，山中少駐不妨程。',64,'全唐诗/poet.song.196000.json','["木葉新時雨亦晴，山中少駐不妨程。", "童嫌路峻頻癡坐，僧喜岩幽每促行。", "草蕩春深無鴈到，松林月上有猿聲。", "石屏一带三千丈，可惜題詩又不成。"]'),
('2ba517b9-0179-4fed-8b06-e6be940fb41d','山中即事','趙汝回','宋','宋诗','song-poetry','','[]','白日荒荒過不知，荼䕷開了覺春歸。',64,'全唐诗/poet.song.196000.json','["白日荒荒過不知，荼䕷開了覺春歸。", "山家賣笋櫻桃熟，河水生萍柳絮飛。", "久雨一晴螢火出，閏年三月杜鵑稀。", "沉沉松竹烟嵐冷，慙愧高僧借袷衣。"]'),
('b23b6e7a-947e-4e51-8bf5-073fe60e9b1d','峨眉山廨','趙汝回','宋','宋诗','song-poetry','','[]','褐衣蔬食苦吟身，肌骨雖清鬢雪新。',64,'全唐诗/poet.song.196000.json','["褐衣蔬食苦吟身，肌骨雖清鬢雪新。", "栗里未營三畝宅，桃源已過一年春。", "也知官職難癡望，化得妻兒不誶貧。", "別寫新詩寄鄉友，峨眉山下獨閒人。"]'),
('d41647a6-c822-42c8-bf64-735fb4d7e8a9','宿羅溪山','趙汝回','宋','宋诗','song-poetry','','[]','鷲嶺東游霽景微，碧桃花外一鶑飛。',32,'全唐诗/poet.song.196000.json','["鷲嶺東游霽景微，碧桃花外一鶑飛。", "樵夫不斫垂潭樹，知有僧人掛搭衣。"]'),
('26a174f2-0231-4f43-a303-17664149f5b6','二月十九日','趙汝回','宋','宋诗','song-poetry','','[]','客去關門讀莊老，燈花熠熠春蟲小。',32,'全唐诗/poet.song.196000.json','["客去關門讀莊老，燈花熠熠春蟲小。", "冰雪未消雷雨來，長安三月行人少。"]'),
('49014a2f-a663-41ac-a3fc-126102a2097a','簡陸少監','趙汝回','宋','宋诗','song-poetry','','[]','登瀛彼何人，選海渺無際。',240,'全唐诗/poet.song.196000.json','["登瀛彼何人，選海渺無際。", "巨矣萬斛舟，不與貧士濟。", "起檣開錦帆，逆浪使風勢。", "貧士望洋立，惆怳發深喟。", "少監笠澤英，清芬襲蘭砌。", "不經覓舉難，不道覓舉易。", "每恨里選衰，高才守低位。", "趨榮靡願辱，不富焉有貴。", "一塗總不歧，隻臂韝羣鷙。", "園桃各春妍，崖松以霜悴。", "端笏玉扆前，極口陳國是。", "上之及公卿，下之言守帥。", "剝膚到饑甿，孰與護元氣。", "凝陰積層霄，剽賊延內地。", "毋謂民不神，民情即天意。", "善瑟無弊絃，良工先利器。", "所願招雋豪，棄取委公義。", "庶幾臯伊出，扶傾掃沉翳。", "從來立仗馬，唯作噉蒭計。", "堂堂不諱朝，鳴鳳峙鵷陛。"]'),
('30a34849-6793-4c1e-b3b0-370822b4d5c9','游列真觀劉道士拉上潮際觀漁','趙汝回','宋','宋诗','song-poetry','','[]','珠宮何岧嶢，前江後層嶂。',156,'全唐诗/poet.song.196000.json','["珠宮何岧嶢，前江後層嶂。", "開山者何人，蕭梁山中相。", "竊惟經營初，豈曰此幽賞。", "地靈宜仙事，境寂銷俗相。", "既積惜水功，帝命使瀛丈。", "手泥燒丹竈，歲久化黄壤。", "石突古殿出，磵循陰廊響。", "道人如修靜，我豈陶官長。", "偶結清凈緣，下榻稅塵鞅。", "夜報前溪漁，命酒將鱠享。", "撐篷待月來，架槳乘潮上。", "秋高氣凄澹，清極思超敞。", "暫廢一夕眠，庶蒙列真奬。"]'),
('02089806-475a-4ac4-8689-825d51f21460','寄昭武馮司戶','趙汝回','宋','宋诗','song-poetry','','[]','朝解白鵠袍，夕投武陽壘。',288,'全唐诗/poet.song.196000.json','["朝解白鵠袍，夕投武陽壘。", "武陽衆盜區，風傳駭妻子。", "六月日癸亥，一書滿三紙。", "具言五月初，獨宿鍾石邸。", "脅從在所矜，渠魁固無幾。", "仰憑天子威，肅導使君指。", "豁達生路開，擲劍秉耡耜。", "始如浮釜魚，終如慕羶螘。", "游騎從何來，使我顔有泚。", "幸逃食其烹，猶存漢家體。", "黄巾與綠林，往昔殊僣擬。", "陸梁能幾時，寸戮而已矣。", "理國若理身，慮我不慮彼。", "潰癰復何難，實恐元氣毀。", "江閩五十邑，荆棘五千里。", "我農失種穫，我士乏儲峙。", "捕招兩悠悠，分明養彪兕。", "頃予參此軍，忽忽逾一紀。", "素飧歌伐檀，居前愧揚粃。", "坊閭儼在目，煨燼空遺址。", "使君君子儒，規摹用詩禮。", "軍勢李晟孤，國事賈生恥。", "蛟龍無波濤，胡能制蛇虺。", "誰謂曹掾卑，偉矣天下事。"]'),
('77e18f43-7272-4fa1-8c5c-8e430d22030e','送盧五方春分教端州','趙汝回','宋','宋诗','song-poetry','','[]','柳南矯矯蛟龍騫，古詩古文高入天。',304,'全唐诗/poet.song.196000.json','["柳南矯矯蛟龍騫，古詩古文高入天。", "奉試詞場三十年，柳度夜夜魁星躔。", "集英殿下聽臚傳，唱在第十衆所冤。", "天豈恨汝月蝕篇，罰使獨吟瘴海邊。", "中州近年栽木綿，春寒秋熱氣已偏。", "我心憂國身甚便，編排失手安足言。", "敵窺淮漢蹂兩川，君相不得高枕眠。", "古人度嶺悲南遷，今人度嶺如登仙。", "端溪溪闊山無烟，長腰米白鯽鯇鮮。", "山媼采蕉蜑采蠙，羽檄不警徭賦蠲。", "黨碑諸賢昔往還，人士盡識洛水源。", "廣文下馬春風前，升堂講書鼓鼘鼘。", "遠方朋來笈在肩，再拜願預弟子賢。", "中庸大學玄又玄，商盤周誥非雕鎸。", "燈花兩簷陳俎籩，一一口說手註篇。", "霜毫之筆雲濤牋，墨香瓦滑不受研。", "下巖古坑石柿填，千夫秉炬入戽泉。", "鑱出一片紫玉磚，色如馬肝鵒眼圓。", "得之酬直不論錢，乍是對客寒無氈。"]'),
('94943d60-4dbc-4b7a-8b0a-cd2ef063b3a0','翠閬行餞宋廷材分教大寧','趙汝回','宋','宋诗','song-poetry','','[]','蜀道不難兮，君無聽李白之狂歌。',106,'全唐诗/poet.song.196000.json','["蜀道不難兮，君無聽李白之狂歌。", "石棧梯雲入翠閬，峽船泝水通銀河，棧平峽穩行人多。", "灧澦堆前落錦帆，諸生郊謁冠峩峩。", "秋堂晨鼓講義出，亭夫樵豎知丘軻。", "官冷莫思歸去來，且可淡飯閑吟哦。", "君不見江西嶠南賊未滅，仕者蚤夜防弓戈。"]'),
('a9ef6dbc-557f-4609-94ae-6f3a63cb3aae','玉溪謠','趙汝回','宋','宋诗','song-poetry','','[]','雍灘束水水箭急，逆水上灘灘壁立。',179,'全唐诗/poet.song.196000.json','["雍灘束水水箭急，逆水上灘灘壁立。", "折篙斷纜船不前，乘船人懼梢人泣。", "柳風摇春花雨晴，飛帆忽過如飛星。", "仙人坐機織錦鯨，邀我爲賦銀河清。", "茫茫天路高無陛，予止坎兮曷爲至。", "閑將身事問仙人，仙人笑指灘船是。", "長風引船水沒灘，天地變化須臾間。", "不生凌清遡紫骨，何用費火燒還丹。", "五百童男東入海，水弱山遥無藥採。", "千層萬級通天臺，方士致神神不來。", "君不見桃花滿山不知處，劉阮逕入天台去。"]'),
('7c95ae6b-0b17-4396-ba5a-85577c8f881b','期平叔兄不至','趙汝回','宋','宋诗','song-poetry','','[]','兄昔別我遊衡麓，我亦東吟石橋瀑。',64,'全唐诗/poet.song.196000.json','["兄昔別我遊衡麓，我亦東吟石橋瀑。", "八年能接幾函書，弟今白頭兄何如。", "河水流澌雪風惡，梧桐渡口孤舟泊。", "山房夜坐兄不來，蠟梅花拆燈花落。"]'),
('fa607466-8af1-4b97-b01c-269c3584b989','贈劉道士','趙汝回','宋','宋诗','song-poetry','','[]','竹巖鳥啼雲影閑，此是玉帝藏書山。',64,'全唐诗/poet.song.196000.json','["竹巖鳥啼雲影閑，此是玉帝藏書山。", "他峯葉盡一霜後，仙洞春如三月間。", "白鬚道人年八十，指予漈路從溪入。", "靸著芒鞋不杖藜，嘯泉歸去衣裳濕。"]'),
('a631e043-d6db-4af1-857a-199b7673fa9b','送張敬甫常薄出守荆門','趙汝回','宋','宋诗','song-poetry','','[]','前年匹馬辭軍幕，今年千騎從天落。',192,'全唐诗/poet.song.196000.json','["前年匹馬辭軍幕，今年千騎從天落。", "座主門生合虎符，棠陰夾路春如昨。", "身名貴驟俗所羨，使君夷然心澹泊。", "父書盈篋本孫吳，師燈一點傳伊洛。", "莽莽叢榛亂草中，孤松昂昂立冰壑。", "自古十二取世官，換得青袍髮幾鶴。", "曾因窮達悟乘除，以寵爲危不爲樂。", "荆門形勢衿喉地，新城突兀壕未鑿。", "天子憂邊復愛民，鑿壕還恐妨犂穫。", "謂君夙抱文武資，須君小試綏懷畧。", "予聞衛國如衛身，癰疽甚毒腸胃薄。", "堂堂人物守邊州，國中羣盜令誰縛。"]'),
('4442fe70-0f9f-465d-b798-61a9de187862','薛景石瓜廬','趙汝回','宋','宋诗','song-poetry','','[]','湖村有真逸，愛着釣魚袍。',48,'全唐诗/poet.song.196000.json','["湖村有真逸，愛着釣魚袍。", "鶴語柴門靜，身閑筆硯勞。", "移來瓜種別，看得桂叢高。", "所寫雖云僻，文名不可逃。"]'),
('240ac38f-f638-4c87-83ad-7729ff66b189','除夕泛靈溪','趙汝回','宋','宋诗','song-poetry','','[]','拜敕管桃源，其如骨未仙。',48,'全唐诗/poet.song.196000.json','["拜敕管桃源，其如骨未仙。", "年荒醉者少，官小野人憐。", "臘雪梅花在，溪春草夢圓。", "新正有忙事，未訪洞霄泉。"]'),
('4d9f24d3-76df-4236-888f-b0bb92dd26e4','和荷渚寄同遊韻','趙汝回','宋','宋诗','song-poetry','','[]','知幾百事懶，夢只在山林。',48,'全唐诗/poet.song.196000.json','["知幾百事懶，夢只在山林。", "一馬塵中出，千峯頂上吟。", "月新松逕黑，柝靜斗城深。", "相憶梅花下，花寒瘦不禁。"]'),
('77aa868c-45ad-4fa4-945d-ed898c1128cf','春吟','趙汝回','宋','宋诗','song-poetry','','[]','一春吟未穩，今日再吟看。',48,'全唐诗/poet.song.196000.json','["一春吟未穩，今日再吟看。", "石井桐花晚，江城穀雨寒。", "白烟浮野寺，蒼蘚繡池欄。", "爲謝松梢鶴，官卑去住難。"]'),
('775cda0b-3b05-4e51-b670-da34f17ed040','寄題王次點東巖','趙汝回','宋','宋诗','song-poetry','','[]','生事付妻兒，山居清可知。',48,'全唐诗/poet.song.196000.json','["生事付妻兒，山居清可知。", "自言雪收後，不夢客遊時。", "洗石鎸唐帖，凭松讀楚詞。", "却愁登第去，草沒菊花籬。"]'),
('24531c13-67e2-40f3-bcd4-a980006d76d1','桂','趙汝回','宋','宋诗','song-poetry','','[]','一夜桂花發，千崖風露香。',48,'全唐诗/poet.song.196000.json','["一夜桂花發，千崖風露香。", "樹經秋幾過，人在月中央。", "不預離騷賦，空居寂寞鄉。", "山翁對之飲，酒色也鵝黄。"]'),
('ac5d3eba-a2b8-4562-a1c8-cbaf3c14582a','送趙正甫丞湘陰','趙汝回','宋','宋诗','song-poetry','','[]','行舟何所有，新酒滿甆瓶。',48,'全唐诗/poet.song.196000.json','["行舟何所有，新酒滿甆瓶。", "若使三閭飲，終應一念醒。", "官卑掌苗籍，吟苦掩松廳。", "清夢如湘水，遥通春草亭。"]'),
('79c47a72-722e-4afa-bea8-e818a98011d1','酬諸友喜歸之作','趙汝回','宋','宋诗','song-poetry','','[]','却歸思去日，十過草池春。',48,'全唐诗/poet.song.196000.json','["却歸思去日，十過草池春。", "新雪滿雙鬢，故交餘幾人。", "藏書蟫獨飽，借宅鶴同貧。", "夜起吟芳什，凉風吹桂輪。"]'),
('4ce22c57-9a7c-4744-8ecc-d6b2b7379220','送劉成道旅遊','趙汝回','宋','宋诗','song-poetry','','[]','從軍不願賞，歸補萬松栽。',48,'全唐诗/poet.song.196000.json','["從軍不願賞，歸補萬松栽。", "獨作漁樵計，安知婚嫁催。", "江船深夜月，山驛小春梅。", "老境詩閒淡，孤吟薦一杯。"]'),
('1fb5034c-2ea3-4822-bbec-013ff36ec906','初夏倚春望六祖寺','趙汝回','宋','宋诗','song-poetry','','[]','柳絮兼花片，舞風湘水濱。',48,'全唐诗/poet.song.196000.json','["柳絮兼花片，舞風湘水濱。", "濃嵐如細雨，初夏是殘春。", "鳥度山家曲，泉清佛界塵。", "年衰眠易醒，歸夢不能真。"]'),
('b1471ac5-c213-483b-90e9-eccbe59b08ae','聞趙昌甫赴召','趙汝回','宋','宋诗','song-poetry','','[]','甘得眠雲復飲冰，此翁不獨擅詩名。',64,'全唐诗/poet.song.196000.json','["甘得眠雲復飲冰，此翁不獨擅詩名。", "山深難避蒲輪召，陛遠聽扶藜杖行。", "老去報君心轉切，年來守局夢頻驚。", "有時湖上看垂釣，只憶磻溪溪水清。"]'),
('7a91758e-78ac-445f-a80d-c57c88676c06','題劉荆山母墓','趙汝回','宋','宋诗','song-poetry','','[]','綠草䰐鬖白露晞，老樵能記虎眠時。',64,'全唐诗/poet.song.196000.json','["綠草䰐鬖白露晞，老樵能記虎眠時。", "石函深貯懸鍾讖，翠壁新刊斷織碑。", "隴勢三分松檜色，泉聲千古蓼莪悲。", "珪郎向日升堂友，留宿雲庵撰誄辭。"]'),
('0b3f1c93-1991-4bad-9097-b803c032dc72','陸侍右得祠歸里往餞弗及寄以是詩','趙汝回','宋','宋诗','song-poetry','','[]','三以囊封入紫微，一星今夜出郎闈。',64,'全唐诗/poet.song.196000.json','["三以囊封入紫微，一星今夜出郎闈。", "賈誼幸無湘水謫，知章乞得鏡湖歸。", "乘潮不等詩人別，望闕恨憂諫者稀。", "笠澤門前古松下，他時容我借漁磯。"]'),
('b1f9412a-3bb8-4c1a-ad2e-886a56149e06','弔盧玉堂','趙汝回','宋','宋诗','song-poetry','','[]','金鑾坡上文星落，收拾遺文有幾函。',64,'全唐诗/poet.song.196000.json','["金鑾坡上文星落，收拾遺文有幾函。", "草制空教生白髮，蓋棺只是着青衫。", "吟魂夜訪林逋塚，破屋寒拋謝客巖。", "自有舊家椽筆在，豐碑豎起壓松杉。"]'),
('2b0611a5-42c0-48f4-8bb5-4767b0a04013','弔蔣弋陽','趙汝回','宋','宋诗','song-poetry','','[]','悲風急雨柳塘寒，巵酒篇詩哭肖韓。',64,'全唐诗/poet.song.196000.json','["悲風急雨柳塘寒，巵酒篇詩哭肖韓。", "長記湖西訪梅日，獨於船上取琴彈。", "弋陽百姓私營廟，紫府無人別擬官。", "墓隴從教長新草，雙鳬何處只空棺。"]'),
('8ce0e1df-a07b-4248-9e6e-8d0b43492e44','送蔣大璞赴揚州司戶','趙汝回','宋','宋诗','song-poetry','','[]','維揚幕府最風流，何掾梅開蔣掾遊。',64,'全唐诗/poet.song.196000.json','["維揚幕府最風流，何掾梅開蔣掾遊。", "新籍楚民今幾戶，舊年隨帝此停舟。", "慈親就養惟愁雪，元帥崇詩不畏秋。", "壕闊城高豈忘戰，平山堂北是神州。"]'),
('b9678d3e-480a-4f06-a63a-4d40aba89ffa','縱遊','趙汝回','宋','宋诗','song-poetry','','[]','人事元知不可諧，名山踏破幾青鞋。',64,'全唐诗/poet.song.196000.json','["人事元知不可諧，名山踏破幾青鞋。", "百錢掛杖無時醉，一鍤隨身到處埋。", "驛壁讀詩摩病眼，僧窗看竹散幽懷。", "亦知詩料無窮盡，燈火蕭踈過縣街。"]'),
('20f8c699-84a7-4960-acec-1c7377aadd3b','西湖重午作','趙汝回','宋','宋诗','song-poetry','','["\u897f\u6e56"]','高誦招魂招屈平，只應沉恨隔浮萍。',64,'全唐诗/poet.song.196000.json','["高誦招魂招屈平，只應沉恨隔浮萍。", "著騷直以尸爲諫，亡楚如何醉不醒。", "像虎空懸青艾束，辟兵難望綵絲靈。", "憑君一激沅湘水，浄洗中原血鎧腥。"]'),
('118b9d35-3655-4be2-9a93-713dab1af448','奉歸柳塘潘希白詩藁','趙汝回','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','織柳縫花雅道衰，將題錦卷復敲推。',64,'全唐诗/poet.song.196000.json','["織柳縫花雅道衰，將題錦卷復敲推。", "夜寒吟苦冰澌合，境寂心融造化來。", "斸石崑崙携玉下，乘槎河海到天迴。", "今時古調何人愛，東野長江在夜臺。"]'),
('e16c219e-7b13-48b2-b26c-7b3845f51e98','王道士惠柳檜','趙汝回','宋','宋诗','song-poetry','','[]','千年檜出寒巖罅，掘得根來比金價。',32,'全唐诗/poet.song.196000.json','["千年檜出寒巖罅，掘得根來比金價。", "髣髴山陰見此株，尋思却是關仝畫。"]'),
('fb44cf7f-292c-4ac6-8821-6a711465c854','凌霄花爲復上人作','趙汝回','宋','宋诗','song-poetry','','[]','嫋嫋枯藤淡絳葩，夤緣直上照殘霞。',32,'全唐诗/poet.song.196000.json','["嫋嫋枯藤淡絳葩，夤緣直上照殘霞。", "老僧不作依棲想，將謂青松自有花。"]'),
('a0ba0681-8ff1-4df1-aa7b-892e1606dafe','題頼若谷存齋','趙汝回','宋','宋诗','song-poetry','','[]','湛湛方寸天，清泠如止水。',87,'全唐诗/poet.song.196000.json','["湛湛方寸天，清泠如止水。", "其止涵空明，其潰汩泥滓。", "操之恍若遺，捨之渺何倚。", "瞬息苟不誠，愚智從此始。", "一篇中庸書，千古防意壘。", "吾子善守之，勉勉集衆美。", "獨不見鄰家翁，驅鷄呼犬斜陽中。"]'),
('4a714621-f160-4166-ab69-51f4cd7919a3','寄聖水照講師','趙汝回','宋','宋诗','song-poetry','','[]','聖水水深山亦深，寺前三十里清陰。',32,'全唐诗/poet.song.196000.json','["聖水水深山亦深，寺前三十里清陰。", "一僧趺坐松間石，不是安禪定苦吟。"]'),
('e5c58739-40d7-404f-a440-3fc1f9d71a81','春山堂','趙汝回','宋','宋诗','song-poetry','','[]','山在畫堂西，鈎簾靜對時。',48,'全唐诗/poet.song.196000.json','["山在畫堂西，鈎簾靜對時。", "林高日落早，巷僻客來遲。", "抱病獨不飲，愛閑君所知。", "階前碧梧葉，片片可題詩。"]'),
('121b6f7b-ef5a-42ea-8c3b-47ac11aea585','句  其一','趙汝回','宋','宋诗','song-poetry','','[]','春風過後雪初白，夜雨晴時水亦香。',16,'全唐诗/poet.song.196000.json','["春風過後雪初白，夜雨晴時水亦香。"]'),
('2bfb628a-7f66-484b-913b-d6499ddc9409','句  其二','趙汝回','宋','宋诗','song-poetry','','[]','屈原一點沉湘恨，李白三生捉月身。',16,'全唐诗/poet.song.196000.json','["屈原一點沉湘恨，李白三生捉月身。"]'),
('036593ea-0b88-49d4-8017-a65d5778bbfe','壽客','史鑄','宋','宋诗','song-poetry','','[]','東籬寂寞舊家鄉，頭白天生鬚又黄。',32,'全唐诗/poet.song.196000.json','["東籬寂寞舊家鄉，頭白天生鬚又黄。", "歲歲相陪重九宴，主人傳得引年方。"]'),
('9cdd508d-9060-4941-b2d1-7d9be186e321','勝金黄','史鑄','宋','宋诗','song-poetry','','[]','籬下秋深花正敷，煌煌金彩照吾廬。',32,'全唐诗/poet.song.196000.json','["籬下秋深花正敷，煌煌金彩照吾廬。", "維揚貢品雖稱貴，顔色看來反不如。"]'),
('082b2230-f72d-4d41-a470-61bbf1211b03','御愛黄','史鑄','宋','宋诗','song-poetry','','[]','貴品傳來自禁中，色鮮如柘恍迷蜂。',32,'全唐诗/poet.song.196000.json','["貴品傳來自禁中，色鮮如柘恍迷蜂。", "作歌亦見鍾情重，承眷應曾遇德宗。"]'),
('f3368bb0-e5a0-416e-9cc3-2ec4e5b6778f','御袍黄','史鑄','宋','宋诗','song-poetry','','[]','秋晚司花逞巧工，解將柘色染幽叢。',32,'全唐诗/poet.song.196000.json','["秋晚司花逞巧工，解將柘色染幽叢。", "待看開向丹墀畔，宛與君王服飾同。"]'),
('25257424-226c-47ac-993d-71bb4afeb264','九日黄  其一','史鑄','宋','宋诗','song-poetry','','[]','露叢花發例皆遲，異品敷金不詭隨。',32,'全唐诗/poet.song.196000.json','["露叢花發例皆遲，異品敷金不詭隨。", "應節及時真可愛，登高且把泛瑶巵。"]'),
('50b793d8-c105-4e54-aec0-652d059b8d75','九日黄  其二','史鑄','宋','宋诗','song-poetry','','[]','應時寒蘂拆秋含，晃耀良金色可參。',32,'全唐诗/poet.song.196000.json','["應時寒蘂拆秋含，晃耀良金色可參。", "似遇道人殷七七，故開佳節日三三。"]'),
('93927ddb-a43e-470e-9d68-6a467fe27997','金錢菊  其一','史鑄','宋','宋诗','song-poetry','','[]','陰陽鑄出遶籬邊，露洗風磨色燦然。',32,'全唐诗/poet.song.196000.json','["陰陽鑄出遶籬邊，露洗風磨色燦然。", "未解濟貧行世上，且圖買笑向樽前。"]'),
('2e093d41-f4ac-4437-aa82-2d221176be2d','金錢菊  其二','史鑄','宋','宋诗','song-poetry','','[]','天女將圖買斷秋，筭來白帝價難酬。',32,'全唐诗/poet.song.196000.json','["天女將圖買斷秋，筭來白帝價難酬。", "金錢滿閤翻嫌富，撒向幽叢竟不收。"]'),
('b70fbcfb-3aee-4a26-9b60-acd648924abe','金絲菊','史鑄','宋','宋诗','song-poetry','','[]','染人徒染金絲色，侍女謾歌金縷衣。',32,'全唐诗/poet.song.196000.json','["染人徒染金絲色，侍女謾歌金縷衣。", "爭似黄花得天巧，織成紋綹不須機。"]'),
('70242ea4-cca7-4c1f-a9f4-65ee8f6e0464','金鈴菊','史鑄','宋','宋诗','song-poetry','','[]','化工寫出爛盈枝，顆顆光明耀竹籬。',32,'全唐诗/poet.song.196000.json','["化工寫出爛盈枝，顆顆光明耀竹籬。", "賞翫佳人應笑道，待教繫向雪獅兒。"]'),
('7f7b0fb7-a540-45fa-9266-f382bd324442','金連菊','史鑄','宋','宋诗','song-poetry','','[]','迥出嬌紅媚一川，風刀細鏤耀籬邊。',32,'全唐诗/poet.song.196000.json','["迥出嬌紅媚一川，風刀細鏤耀籬邊。", "不妨捧向孩兒手，留取清香在佛前。"]'),
('8ce9b1ac-7cbf-429f-84b8-f692b735a719','側金盞','史鑄','宋','宋诗','song-poetry','','[]','圓模羅列占東籬，西帝賜來宮樣奇。',32,'全唐诗/poet.song.196000.json','["圓模羅列占東籬，西帝賜來宮樣奇。", "疑是花神清酌罷，儘教放處不妨欹。"]'),
('955d91b0-e9d9-4d82-858a-8358ab740738','金盞銀臺','史鑄','宋','宋诗','song-poetry','','[]','黄白天成酒器新，曉承清露味何醇。',32,'全唐诗/poet.song.196000.json','["黄白天成酒器新，曉承清露味何醇。", "恰如欲勸陶公飲，西皞應須作主人。"]'),
('a4d940e7-d83c-4c02-a24b-8c0227df8d81','滴滴金','史鑄','宋','宋诗','song-poetry','','[]','未見秋來花便開，人言因露作根荄。',32,'全唐诗/poet.song.196000.json','["未見秋來花便開，人言因露作根荄。", "千團萬點枝頭墜，盡化黄金出土來。"]'),
('92450a6e-b1bf-4fdc-b35a-d39df8394648','密友菊','史鑄','宋','宋诗','song-poetry','','[]','寒英雅稱伴吾徒，色正香清態有餘。',32,'全唐诗/poet.song.196000.json','["寒英雅稱伴吾徒，色正香清態有餘。", "日涉中園長與會，何憂因數反成疏。"]'),
('cc30a968-5a60-47ee-a994-61cba215b9be','又蜜卣菊','史鑄','宋','宋诗','song-poetry','','[]','化工也學割蜂房，秋卉粧成春蘂黄。',32,'全唐诗/poet.song.196000.json','["化工也學割蜂房，秋卉粧成春蘂黄。", "芬馥猶疑盛秬鬯，未容輕把泛霞觴。"]'),
('9b1d899c-f1ce-45f1-b14d-09f757e57e48','橙菊','史鑄','宋','宋诗','song-poetry','','[]','上林佳果久流聲，秋徑香苞特假名。',32,'全唐诗/poet.song.196000.json','["上林佳果久流聲，秋徑香苞特假名。", "正頼蟹肥新酒熟，幽人來賞兩含情。"]'),
('3207d198-7fbe-47f0-b002-d38fbfc72cf8','荔枝菊','史鑄','宋','宋诗','song-poetry','','[]','莫論枝上粟團黄，且喜籬邊珍顆香。',32,'全唐诗/poet.song.196000.json','["莫論枝上粟團黄，且喜籬邊珍顆香。", "若使唐家妃子見，料應誤摘醉中嘗。"]'),
('41fb0764-6773-469a-a09b-aa085195c0b9','茱萸菊','史鑄','宋','宋诗','song-poetry','','[]','品出陶家花品外，名存吳地藥名中。',32,'全唐诗/poet.song.196000.json','["品出陶家花品外，名存吳地藥名中。", "若將泛入重陽酒，不用分香摘兩叢。"]'),
('275d7c2f-01b5-4f2e-b716-e4b3d6939485','艾菊','史鑄','宋','宋诗','song-poetry','','[]','一入陶籬如楚俗，重陽重午兩關情。',32,'全唐诗/poet.song.196000.json','["一入陶籬如楚俗，重陽重午兩關情。", "惜哉刪後詩三百，菊奈無名艾有名。"]'),
('04897c04-7cf1-4b19-a8b8-6fbd5f47857e','末利菊','史鑄','宋','宋诗','song-poetry','','[]','來從西域馨香異，翻作東籬品目新。',32,'全唐诗/poet.song.196000.json','["來從西域馨香異，翻作東籬品目新。", "悟此肯爲微利役，殷勤來賞屬幽人。"]'),
('7da9fd02-5c45-4b50-9341-be01319efb04','甘菊','史鑄','宋','宋诗','song-poetry','','[]','南陽佳種傳來久，濟用須知味若飴。',32,'全唐诗/poet.song.196000.json','["南陽佳種傳來久，濟用須知味若飴。", "苗可代茶香自別，花堪入藥效尤奇。"]'),
('3d665bdf-4050-4ccf-9fcd-56355e19d33f','塔子菊','史鑄','宋','宋诗','song-poetry','','[]','金彩煌煌般若花，高蟠層級巧堪誇。',32,'全唐诗/poet.song.196000.json','["金彩煌煌般若花，高蟠層級巧堪誇。", "更添佛頂週遭種，成此良緣勝聚沙。"]'),
('38224eef-f34f-4f06-8a68-f90665bd7430','毬子菊','史鑄','宋','宋诗','song-poetry','','[]','團圞秋卉出籬東，惹露凌霜衮衮中。',32,'全唐诗/poet.song.196000.json','["團圞秋卉出籬東，惹露凌霜衮衮中。", "疑是花神拋未過，更教輾轉向西風。"]'),
('509a06e0-e912-43ed-a757-58d2fd57a86e','野菊','史鑄','宋','宋诗','song-poetry','','[]','寒郊露蘂疏仍小，瘦地霜枝細且長。',32,'全唐诗/poet.song.196000.json','["寒郊露蘂疏仍小，瘦地霜枝細且長。", "境僻人稀誰與採，馬蹄贏得踐餘香。"]'),
('4c2f904c-30fa-417e-8ea5-f0aec8ba2415','黄白菊','史鑄','宋','宋诗','song-poetry','','[]','二色秋英併一根，金宜爲友玉爲昆。',32,'全唐诗/poet.song.196000.json','["二色秋英併一根，金宜爲友玉爲昆。", "相依笑向西風裏，皓色須還中色尊。"]'),
('1cd99593-887b-4bf4-bc00-da8cc74add1e','十樣菊','史鑄','宋','宋诗','song-poetry','','[]','霜蘂多般同一本，天教成數殿秋榮。',32,'全唐诗/poet.song.196000.json','["霜蘂多般同一本，天教成數殿秋榮。", "從他蛺蝶偷香慣，偷遍無過一例清。"]'),
('7fd76ff3-f37e-4fea-958e-7121bedcf9c4','九華菊  其一','史鑄','宋','宋诗','song-poetry','','[]','功成丹鼎花堪比，花到重陽色正鮮。',32,'全唐诗/poet.song.196000.json','["功成丹鼎花堪比，花到重陽色正鮮。", "靖節集中名甚著，羨他慣服制頹年。"]'),
('5187a57a-c624-491c-b796-07cbe845b65e','九華菊  其二','史鑄','宋','宋诗','song-poetry','','[]','流芳千古傲霜英，剪玉絲金照眼明。',32,'全唐诗/poet.song.196000.json','["流芳千古傲霜英，剪玉絲金照眼明。", "若論駐顔功不小，仙丹端可與齊名。"]'),
('269a7e0f-a4e8-40f5-9246-ee7838c8dc1a','佛頂菊','史鑄','宋','宋诗','song-poetry','','[]','籬畔光明緣底盛，秋來千百化身多。',32,'全唐诗/poet.song.196000.json','["籬畔光明緣底盛，秋來千百化身多。", "露棲不必醍醐灌，雨沐何煩手掌摩。"]'),
('6686512c-1a76-48b6-a3ac-0eb90d46b1a1','大笑菊  其一','史鑄','宋','宋诗','song-poetry','','[]','玉顔已破晚秋葩，不費千金亦可誇。',32,'全唐诗/poet.song.196000.json','["玉顔已破晚秋葩，不費千金亦可誇。", "幽徑主人偏愛惜，且贏耳畔弗諠譁。"]'),
('4641394c-c2f8-4339-a0c9-4b95a44b2a37','大笑菊  其二','史鑄','宋','宋诗','song-poetry','','[]','晚節敷華性異常，黄冠白羽道家粧。',32,'全唐诗/poet.song.196000.json','["晚節敷華性異常，黄冠白羽道家粧。", "料應識破榮枯事，獨對秋風笑一場。"]'),
('6e33860f-3854-4512-9a04-3b809986a4b1','大笑菊  其三','史鑄','宋','宋诗','song-poetry','','[]','桃笑春風菊笑秋，冶容正色不相侔。',32,'全唐诗/poet.song.196000.json','["桃笑春風菊笑秋，冶容正色不相侔。", "寒梅一笑如堪索，這笑方爲是匹儔。"]'),
('e000d974-46d4-49c2-b690-b3c9a9c24708','玉甌菊','史鑄','宋','宋诗','song-poetry','','[]','化工施巧在秋葩，琢就圓模瑩可嘉。',32,'全唐诗/poet.song.196000.json','["化工施巧在秋葩，琢就圓模瑩可嘉。", "著底香心真蠟色，似留賞客欲分茶。"]'),
('873f284b-892e-4480-ab96-956375cd0594','銀盤菊','史鑄','宋','宋诗','song-poetry','','[]','秋英疑是白金裁，承露如從仙掌來。',32,'全唐诗/poet.song.196000.json','["秋英疑是白金裁，承露如從仙掌來。", "翻笑漢皇銅制古，斬新一樣也奇哉。"]'),
('f3761e05-5712-4cf5-b6fc-98c35e4f7a47','輪盤菊','史鑄','宋','宋诗','song-poetry','','[]','秋深籬下拆霜英，圓質風吹颺不停。',32,'全唐诗/poet.song.196000.json','["秋深籬下拆霜英，圓質風吹颺不停。", "天巧固非煩扁斲，日新又豈待湯銘。"]'),
('73b45554-5bde-48c6-86c8-e3be4dffe6da','粉團菊','史鑄','宋','宋诗','song-poetry','','[]','月姊容顔別一家，天真何必御鉛華。',32,'全唐诗/poet.song.196000.json','["月姊容顔別一家，天真何必御鉛華。", "秋來殘膩方拋棄，幻作籬邊馥馥花。"]'),
('77e4485d-74b2-42c3-adf3-e0af4cb4d922','月下白','史鑄','宋','宋诗','song-poetry','','[]','素質鮮明絕點塵，冰輪高照轉精神。',32,'全唐诗/poet.song.196000.json','["素質鮮明絕點塵，冰輪高照轉精神。", "叢叢皓彩如羅綺，箇樣誠堪示染人。"]'),
('a6db1ce4-3466-4094-9fc6-25bbbbf39676','纏枝白','史鑄','宋','宋诗','song-poetry','','[]','西風頓拆晚秋葩，色映霜華與月華。',32,'全唐诗/poet.song.196000.json','["西風頓拆晚秋葩，色映霜華與月華。", "不特翠枝柔猗儺，更饒綠葉密交加。"]'),
('b0de6866-ccd0-4a9e-abe4-1260ba6fcc5f','酴醾菊','史鑄','宋','宋诗','song-poetry','','[]','春架秋籬景一同，想因分種自蠶叢。',32,'全唐诗/poet.song.196000.json','["春架秋籬景一同，想因分種自蠶叢。", "但將酩酊酬佳節，不管花居酒品中。"]'),
('3b9c756c-b3e1-46d8-b917-b5e8fc8a6015','木香菊','史鑄','宋','宋诗','song-poetry','','[]','秋花也與藥名同，素彩鮮明曉徑中。',32,'全唐诗/poet.song.196000.json','["秋花也與藥名同，素彩鮮明曉徑中。", "多少清芬通鼻觀，何殊滿架拆東風。"]'),
('3fc09a51-7594-4348-b982-b239b9acc135','寒菊','史鑄','宋','宋诗','song-poetry','','[]','不畏霜風質自殊，不招蜂蝶艷何孤。',32,'全唐诗/poet.song.196000.json','["不畏霜風質自殊，不招蜂蝶艷何孤。", "梅花松竹如相見，便合添爲四友呼。"]'),
('3d7735ae-752e-4d40-8ae0-a3991c8e26b0','淮南菊','史鑄','宋','宋诗','song-poetry','','[]','割脂簇蠟密成團，傑出東籬最奈寒。',32,'全唐诗/poet.song.196000.json','["割脂簇蠟密成團，傑出東籬最奈寒。", "加紫翻宜霜後看，料應慣見屬劉安。"]'),
('6ec55cdf-2228-4347-ad62-10d9cd045902','徘徊菊','史鑄','宋','宋诗','song-poetry','','[]','花神著意駐秋光，不許寒葩陡頓芳。',32,'全唐诗/poet.song.196000.json','["花神著意駐秋光，不許寒葩陡頓芳。", "敷彩盤桓如有待，幽人把玩不須忙。"]'),
('6b1ef53c-575e-4066-a420-d155c2093c94','饅頭菊','史鑄','宋','宋诗','song-poetry','','[]','離火供炊餠餠圓，幽人飽翫向籬邊。',32,'全唐诗/poet.song.196000.json','["離火供炊餠餠圓，幽人飽翫向籬邊。", "採來還問堪餐否，應使癡兒口墮涎。"]'),
('2b34d025-8762-453c-99b6-f0c5d992301d','桃花菊','史鑄','宋','宋诗','song-poetry','','[]','仙源分派到籬東，灼灼穠華綴露叢。',32,'全唐诗/poet.song.196000.json','["仙源分派到籬東，灼灼穠華綴露叢。", "崔護詩章陶令酒，兩家混作一家風。"]'),
('10e82e95-0a51-4561-a61a-a441182a0650','燕脂菊','史鑄','宋','宋诗','song-poetry','','[]','天女染花情若狂，鮮妍直欲媚秋光。',32,'全唐诗/poet.song.196000.json','["天女染花情若狂，鮮妍直欲媚秋光。", "忍將陶徑黄金色，也學秦宮朱臉粧。"]'),
('8151de13-31d0-432f-bfdb-149565638d26','牡丹菊','史鑄','宋','宋诗','song-poetry','','[]','本是秋香九日黄，假爲國色百花王。',32,'全唐诗/poet.song.196000.json','["本是秋香九日黄，假爲國色百花王。", "待殘擬把酥煎啗，莫採芳英泛酒觴。"]'),
('7a1b6b3a-b064-41c3-a95f-53a81fd86e14','紅薇菊','史鑄','宋','宋诗','song-poetry','','[]','天厭花黄色改殷，東籬景物似東山。',32,'全唐诗/poet.song.196000.json','["天厭花黄色改殷，東籬景物似東山。", "逗遛春蘂爲秋蘂，荆棘了無藏葉間。"]'),
('70c1f0d4-fa9a-452f-b84d-f4d1916e65dc','繡菊','史鑄','宋','宋诗','song-poetry','','[]','寒葩縷縷結緗紅，不待纖針見巧工。',32,'全唐诗/poet.song.196000.json','["寒葩縷縷結緗紅，不待纖針見巧工。", "秋老從他宮線減，彩文翻喜入花叢。"]'),
('d155036f-1896-4748-8da7-4805fa20218c','石菊  其一','史鑄','宋','宋诗','song-poetry','','[]','花美雖堪寫團扇，艷妖未必入東籬。',32,'全唐诗/poet.song.196000.json','["花美雖堪寫團扇，艷妖未必入東籬。", "紀名何取它山物，徧問園官總不知。"]'),
('d361c9a9-c6d8-4c3b-8e53-baa533dec770','石菊  其二','史鑄','宋','宋诗','song-poetry','','[]','榦弱葉纖花特奇，艷濃九夏到秋時。',32,'全唐诗/poet.song.196000.json','["榦弱葉纖花特奇，艷濃九夏到秋時。", "枝頭結實元爲藥，爭奈越中人罕知。"]'),
('f0d97497-8e64-43c5-bdc9-9b981883098f','大菊','史鑄','宋','宋诗','song-poetry','','[]','菊名何大爲誰開，子結秋叢是藥材。',32,'全唐诗/poet.song.196000.json','["菊名何大爲誰開，子結秋叢是藥材。", "若用催生功不小，請嘗便可見嬰孩。"]'),
('d9e3e204-6aef-465a-8a85-6ba74e369720','孩兒菊','史鑄','宋','宋诗','song-poetry','','[]','地母提來風露徑，笑風泣露並堪憐。',32,'全唐诗/poet.song.196000.json','["地母提來風露徑，笑風泣露並堪憐。", "品微元乏香肌骨，濫預秋英得浪傳。"]'),
('ed0ad63d-f7e8-4112-b9d1-3ce7722272ee','春菊','史鑄','宋','宋诗','song-poetry','','[]','莫論園蔬品目卑，花開不減菊幽奇。',32,'全唐诗/poet.song.196000.json','["莫論園蔬品目卑，花開不減菊幽奇。", "燦然金色仍堪採，春老恰如秋老時。"]'),
('309675f0-1e90-467b-903b-b8b171000fd2','紫菊','史鑄','宋','宋诗','song-poetry','','[]','秋野閒花是繡鋪，佳名得自北人呼。',32,'全唐诗/poet.song.196000.json','["秋野閒花是繡鋪，佳名得自北人呼。", "若教尼父當時見，應惡紛紛色亂朱。"]'),
('3794a9a1-1a1a-4698-a5a0-b5ebf6498b35','觀音菊','史鑄','宋','宋诗','song-poetry','','[]','霞幢森列引薰風，高出疏籬紫滿叢。',32,'全唐诗/poet.song.196000.json','["霞幢森列引薰風，高出疏籬紫滿叢。", "翠葉纖纖如細柳，直宜插向浄瓶中。"]'),
('83d803a6-b77b-446a-ad3a-a4a59cab4174','繡線菊','史鑄','宋','宋诗','song-poetry','','[]','天成素縷結秋深，巧刺由來不犯針。',32,'全唐诗/poet.song.196000.json','["天成素縷結秋深，巧刺由來不犯針。", "籬下工夫何絢爛，條條綰綴紫花心。"]'),
('0716c5d4-a8aa-4a92-a5d9-ba11d8253269','佳友','史鑄','宋','宋诗','song-poetry','','[]','氣清色正品尤高，好事幽人善與交。',32,'全唐诗/poet.song.196000.json','["氣清色正品尤高，好事幽人善與交。", "開徑何須望三益，相陪雅尚在香苞。"]'),
('9e6036b6-c595-4795-9bb3-202ff2a4e445','壽客','史鑄','宋','宋诗','song-poetry','','[]','東籬冷落舊家鄉，性耐風霜氣味長。',32,'全唐诗/poet.song.196000.json','["東籬冷落舊家鄉，性耐風霜氣味長。", "幾度入來重九宴，主人傳得引年方。"]'),
('1cdc8320-fc36-4502-a288-d17800d0412a','對菊懷古','史鑄','宋','宋诗','song-poetry','','[]','靖節先生菊滿園，其名獨有九華存。',32,'全唐诗/poet.song.196000.json','["靖節先生菊滿園，其名獨有九華存。", "東籬若許塵蹤到，佳品須當盡討論。"]'),
('b90dbe76-0a94-4b67-bb91-4ac831530593','菊花','史鑄','宋','宋诗','song-poetry','','[]','獨芳三徑屬秋深，清致貞姿快賞心。',32,'全唐诗/poet.song.196000.json','["獨芳三徑屬秋深，清致貞姿快賞心。", "解道卓爲霜下傑，平生靖節最知音。"]'),
('7ad3b6a5-4fce-44ed-9919-924650ad3b3b','種菊','史鑄','宋','宋诗','song-poetry','','[]','幽懷遠慕陶彭澤，一畝荒園試爲鉏。',32,'全唐诗/poet.song.196000.json','["幽懷遠慕陶彭澤，一畝荒園試爲鉏。", "自種黄花添野景，幾多光彩照庭除。"]'),
('b5e74abe-2ebf-4d31-9abc-5fee1dc709ff','菊花','史鑄','宋','宋诗','song-poetry','','[]','無艷無妖別有香，知心誰解賞孤芳。',376,'全唐诗/poet.song.196000.json','["無艷無妖別有香，知心誰解賞孤芳。", "淵明酩酊知何處，安得斯人共一觴。", "霜裏鮮鮮照眼明，人言此解制頹齡。", "憐香擘破花心齅，酌盡齋中竹葉缾。", "一夜清霜殞物華，寒芳開晚獨堪嘉。", "折來嗅了依前嗅，不是尋常兒女花。", "籬菊含風暗度香，栽多不爲待重陽。", "愈風明目須真物，夢寐宜人入枕囊。", "露叢芬馥敵蘭芽，清賞終存好事家。", "莫遣兒童容易折，此花開後更無花。", "露裛幽花冷自香，藥中功效不尋常。", "祛風偏重山泉漬，胡廣隨緣却壽長。", "清香裛露對高齋，端仗茲花慰老懷。", "欲折一枝來侑酒，登高能賦屬吾儕。", "八月九月天氣凉，遶欄種菊一齊芳。", "好風應會幽人意，時去時來管送香。", "不趁盛時隨衆卉，幽姿高韻獨蕭然。", "別開小徑連松路，常愛陶潛遠世緣。", "籬菊開時寒有信，幽香還釀客懷清。", "折歸忍負金蕉葉，欲伴騷人賦落英。", "菊花有意浮盃酒，秋老霜濃滿檻開。", "多謝主人相管領，盡收清致助吟才。", "一夜新霜著瓦輕，照窗寒菊近人清。", "白髮年年不負盟。"]'),
('9b60d68e-703a-40ee-9f4e-abd7b3831c84','黄菊二十首','史鑄','宋','宋诗','song-poetry','','[]','黄花漠漠弄秋暉，竚立階前香在衣。',384,'全唐诗/poet.song.196000.json','["黄花漠漠弄秋暉，竚立階前香在衣。", "正色逢人何太晚，衰翁相對惜芬菲。", "白露黄花自遶籬，幽香深謝好風吹。", "陶公沒後無知己，歲歲花開知爲誰。", "遶籬黄菊自開花，開日仍逢小雨斜。", "自得金行真正色，肯參紅紫鬭紛華。", "金英寂寞爲誰開，底許清香鼻觀來。", "籬下先生時得醉，餘風千載出塵埃。", "滿園佳菊鬰金黄，壽質清癯獨傲霜。", "且喜年年作花主，依然相伴向秋光。", "五行正氣産黄花，不在詩家即酒家。", "詩筆酒盃俱有味，亦同元亮舊生涯。", "滿地黄花得意秋，移來庭檻助清幽。", "自緣稟性天生異，不與繁華混一流。", "籬邊黄菊爲誰開，轉憶陶潛歸去來。", "插了滿頭仍漬酒，且謀歡洽玉山頹。", "倚風黄菊遶疏籬，自有清香處處知。", "今日王孫好收采，濁醪霜蟹正堪持。", "金蘂繁開曉更清，薄霜濃露倍多情。", "歸田誰是淵明興，獨遶東籬萬事輕。", "叢菊疏疏著短籬，重陽前後始盈枝。", "托根占得中央色，不比凡花兒女姿。", "自有淵明方有菊，因人千古得嘉名。", "一年好處君須記，翠葉金華刮眼明。"]'),
('b83900a0-d9c0-4644-9afe-9a68c0b01184','白菊三首','史鑄','宋','宋诗','song-poetry','','[]','我憐貞白重寒芳，小徑低叢淡薄粧。',96,'全唐诗/poet.song.196000.json','["我憐貞白重寒芳，小徑低叢淡薄粧。", "謝女黄昏吟作雪，天然別是一般香。", "幽芳天與不尋常，逆鼻渾疑雪亦香。", "把酒可能追靖節，素英一色混瑶觴。", "瓊葩燦彩遶籬東，不怯清霜更耐風。", "淡泞精神無俗艷，獨高流品蕙蘭中。"]'),
('8cbf7b45-08b7-4a48-a03a-3ac8b77fc5db','黄白菊','史鑄','宋','宋诗','song-poetry','','[]','金英鑠鑠擅秋芳，中有孤叢色奪霜。',32,'全唐诗/poet.song.196000.json','["金英鑠鑠擅秋芳，中有孤叢色奪霜。", "手把數枝重疊嗅，兩般顔色一般香。"]'),
('cefd61d5-f1e7-451a-883a-17f30826825c','野菊','史鑄','宋','宋诗','song-poetry','','[]','一簇疏籬有野花，不應青女妬容華。',32,'全唐诗/poet.song.196000.json','["一簇疏籬有野花，不應青女妬容華。", "繁英自剪無人插，只有黄蜂趁兩衙。"]'),
('98fee5c3-4eee-4f56-abc5-ada1ab0ff46f','晚菊','史鑄','宋','宋诗','song-poetry','','[]','青蘂重陽不堪摘，重陽已過菊方開。',32,'全唐诗/poet.song.196000.json','["青蘂重陽不堪摘，重陽已過菊方開。", "不將時節較早晚，且折霜蕤浸玉醅。"]'),
('05a273b3-a627-4283-a60d-59e944e9ac84','殘菊','史鑄','宋','宋诗','song-poetry','','[]','節去蜂愁蝶不知，冷香消盡晚風吹。',32,'全唐诗/poet.song.196000.json','["節去蜂愁蝶不知，冷香消盡晚風吹。", "碎金狼藉不堪摘，空作主人惆悵詩。"]'),
('69416a5a-24f3-49a7-a4d0-ff00384e0330','種菊','史鑄','宋','宋诗','song-poetry','','[]','春初種菊助盤蔬，益氣輕身載舊圖。',32,'全唐诗/poet.song.196000.json','["春初種菊助盤蔬，益氣輕身載舊圖。", "終藉九秋扶正色，芳時偷得醉工夫。"]'),
('2eb60c46-68fa-45b8-ab76-92b00f93fd99','菊花五首','史鑄','宋','宋诗','song-poetry','','[]','不受陽和一點恩，不嫌青女到孤根。',160,'全唐诗/poet.song.196000.json','["不受陽和一點恩，不嫌青女到孤根。", "年年歲歲花相似，誰爲陶潛買酒樽。", "粲粲秋香雨露葩，天教晚發賽諸花。", "輕烟細雨重陽節，且盡芳樽戀物華。", "漸覺西風換物華，秋叢遶舍似陶家。", "世人若覓長生藥，百草枯時始見花。", "代謝相因寒事催，繞籬疏菊又花開。", "霜晴日淡虛庭裏，多少清香透入來。", "不是餐英泥楚騷，重陽菊蘂泛香醪。", "尋常不醉此時醉，陶令拋官意獨高。"]'),
('dd8fc958-3dec-49e3-b9f9-7fba8cf2b974','黄菊九首','史鑄','宋','宋诗','song-poetry','','[]','百卉千花了不存，獨開黄菊伴金樽。',304,'全唐诗/poet.song.196000.json','["百卉千花了不存，獨開黄菊伴金樽。", "欲知却老延齡藥，誰信幽香是返魂。", "菊是去年依舊黄，風從花裏過來香。", "杯中要作茱萸伴，更領詩人入醉鄉。", "白酒新熟山中歸，黄花漠漠弄秋暉。", "東籬採菊隠君子，醉覺人間萬事非。", "羽葆層層間彩金，醉來不厭遶叢吟。", "滿頭且應良辰插，不插滿頭辜此心。", "籬外黄花菊對誰，應知彭澤久思歸。", "有花堪折直須折，新酒初篘蟹正肥。", "無限黄花簇短籬，幽香深謝好風吹。", "勸君終日酩酊醉，莫待無花空折枝。", "花裏風神菊擅名，綠枝黄蘂有高情。", "詩人不悔衣霑露，步入芳叢脚自輕。", "幸無風雨近重陽，折取蕭蕭滿把黄。", "酒面浮英愛芬馥，銀觥須引十分强。", "不與羣芳競，宜乎殿顥商。", "露從今夜白，菊是去年黄。", "九日陶公酒，一生青女霜。", "有同高士操，得爾慰凄凉。"]'),
('f1fb5654-1ded-4a11-8f70-273d1a2909d2','白菊','史鑄','宋','宋诗','song-poetry','','[]','玉攢碎葉塵難染，露濕香心粉自勻。',32,'全唐诗/poet.song.196000.json','["玉攢碎葉塵難染，露濕香心粉自勻。", "一夜小園開似雪，清香自是藥中珍。"]'),
('ca3ce38d-46d5-484d-9f83-da62e9ad82fa','野菊二首','史鑄','宋','宋诗','song-poetry','','[]','熠熠溪邊野菊黄，風前花氣觸人香。',64,'全唐诗/poet.song.196000.json','["熠熠溪邊野菊黄，風前花氣觸人香。", "可憐此地無車馬，掃地爲渠持一觴。", "野花無主爲誰芳，酒熟漁家擘蟹黄。", "遇酒逢花須一笑，故留秋意作重陽。"]'),
('e0ea87d9-51a8-40e9-b8d6-615d9f1b5456','晚菊','史鑄','宋','宋诗','song-poetry','','[]','節過霜風衮衮來，菊花寂寞晚仍開。',32,'全唐诗/poet.song.196000.json','["節過霜風衮衮來，菊花寂寞晚仍開。", "誰云既晚何用好，爲我殷勤送一杯。"]'),
('1c628675-e579-4f4f-a08b-831f9f60df23','殘菊','史鑄','宋','宋诗','song-poetry','','[]','天地方收肅殺功，菊枝傾倒不成叢。',32,'全唐诗/poet.song.196000.json','["天地方收肅殺功，菊枝傾倒不成叢。", "碎金狼藉不堪摘，圖得人知色是空。"]'),
('e2c43431-5c16-4165-92ca-38dbf0dd7619','枯樹','趙時韶','宋','宋诗','song-poetry','','[]','斧斤不死老蒼虬，未肯甘心只麽休。',32,'全唐诗/poet.song.196000.json','["斧斤不死老蒼虬，未肯甘心只麽休。", "尚有阿婆三五態，背時塗抹趁風流。"]'),
('53240e86-3c37-493b-95ea-5a3284f2bf2e','芭蕉','趙時韶','宋','宋诗','song-poetry','','[]','摇摇如扇葉，風顫午窗陰。',24,'全唐诗/poet.song.196000.json','["摇摇如扇葉，風顫午窗陰。", "素不生枝節，人皆見赤心。"]'),
('9b4a3380-c9a8-439d-93d9-41dfa7ad48ca','吟梅','趙時韶','宋','宋诗','song-poetry','','[]','安得梅開向四時，騷人日日可吟詩。',32,'全唐诗/poet.song.196000.json','["安得梅開向四時，騷人日日可吟詩。", "年來萬事心都懶，只有吟梅興未衰。"]'),
('d5ba3668-d657-4c11-92f9-64e9aeb4e477','落梅','趙時韶','宋','宋诗','song-poetry','','[]','鹿胎點點上輕裘，腦片飄飄入寶篝。',32,'全唐诗/poet.song.196000.json','["鹿胎點點上輕裘，腦片飄飄入寶篝。", "更向佳人粧額看，梅花到底也風流。"]'),
('acd8427f-b94d-471d-a553-04b7580c1746','竹夫人','趙時韶','宋','宋诗','song-poetry','','[]','玉骨冰肌夏月凉，更無人妬得專房。',32,'全唐诗/poet.song.196000.json','["玉骨冰肌夏月凉，更無人妬得專房。", "醉翁愛作身邊伴，只恐西風又隔牀。"]'),
('a4f477d1-598b-4a7c-8018-b9707cbc4070','永陽道中','趙時韶','宋','宋诗','song-poetry','','[]','十年前此地，書劍記曾來。',48,'全唐诗/poet.song.196000.json','["十年前此地，書劍記曾來。", "士說紅鷹瓜，農誇白芋魁。", "溪渾魚放子，林動雉驚媒。", "評品全人少，山坡獨有梅。"]'),
('a7cf282a-c580-4381-911c-cfb8af5617c8','古杭道中','趙時韶','宋','宋诗','song-poetry','','[]','離家才是兩三程，便覺征衣綴軟塵。',64,'全唐诗/poet.song.196000.json','["離家才是兩三程，便覺征衣綴軟塵。", "湖海相逢迂闊好，江山不厭往來頻。", "溪魚有孕羹偏美，村酒無灰味却真。", "紆轡小兒莫相笑，柴桑終不負頭巾。"]'),
('8ca0d063-2996-42af-8103-5f693e2076bb','林下','趙時韶','宋','宋诗','song-poetry','','[]','山前山後雪漫漫，輸與田夫野老看。',32,'全唐诗/poet.song.196000.json','["山前山後雪漫漫，輸與田夫野老看。", "驛路自知荆棘甚，一枝遠贈故人難。"]'),
('36392d0c-84ea-42a9-9ba5-2e5014c5f119','浮山用平叔韻','趙時韶','宋','宋诗','song-poetry','','[]','抖擻襟塵訪梵宮，入門物色補陀蹤。',64,'全唐诗/poet.song.196000.json','["抖擻襟塵訪梵宮，入門物色補陀蹤。", "松雖未老曾留鶴，山不在高堪卧龍。", "案上楞巖尋舊跋，枕邊紙被認新縫。", "客題不要紗籠壁，遮莫輕敲飯後鐘。"]'),
('95bd9693-deae-454c-80a2-a65d92d32064','浮來山','趙時韶','宋','宋诗','song-poetry','','[]','秦鬼驅卯沙，聚結無蒼翠。',48,'全唐诗/poet.song.196000.json','["秦鬼驅卯沙，聚結無蒼翠。", "誰云海上移，能與潮浮至。", "洞噓蛟鼉腥，廟畫風雷異。", "雲母今有無，庶爲仙藥餌。"]'),
('cc7f395a-9f25-4051-a56e-afba2bca1812','縠波','趙時韶','宋','宋诗','song-poetry','','[]','鮫人機軸巧，織出水晶宮。',48,'全唐诗/poet.song.196000.json','["鮫人機軸巧，織出水晶宮。", "澣濯有新雨，卷舒無定風。", "晴嵐輕染綠，斜日半澆紅。", "漁父無端甚，輕舠截箇中。"]'),
('14d0881c-deaf-4754-bdd3-b89b263a2c02','雲峰','趙時韶','宋','宋诗','song-poetry','','["\u8861\u5c71"]','淡似衡山霧已開，濃如雨意黯陽臺。',32,'全唐诗/poet.song.196000.json','["淡似衡山霧已開，濃如雨意黯陽臺。", "黄昏天際迷歸鳥，錯認林梢不下來。"]'),
('f39ccde7-a722-46fb-837a-55008cfbb6f6','日梅','趙時韶','宋','宋诗','song-poetry','','[]','紅日移陰上粉牆，烘乾花底夜來霜。',32,'全唐诗/poet.song.196000.json','["紅日移陰上粉牆，烘乾花底夜來霜。", "不須水月黄昏景，疏影風前午更香。"]'),
('482ed7bb-5eba-449e-9a27-b63384b6ccd1','尋梅','趙時韶','宋','宋诗','song-poetry','','[]','春在溪橋第幾家，槎牙老樹竹籬遮。',32,'全唐诗/poet.song.196000.json','["春在溪橋第幾家，槎牙老樹竹籬遮。", "再三辨認枝頭雪，萬一無香恐未花。"]'),
('c388d117-c5ec-4c5b-abb3-c23641158010','戀梅','趙時韶','宋','宋诗','song-poetry','','[]','月下敲推夜未央，青鞋冷透不知霜。',32,'全唐诗/poet.song.196000.json','["月下敲推夜未央，青鞋冷透不知霜。", "兒童促我且眠去，畫在床屏亦有香。"]'),
('99d1f48e-4d11-4493-a451-dbeee5449566','愛梅','趙時韶','宋','宋诗','song-poetry','','[]','獨自敲推到夜深，情知未稱惜花心。',32,'全唐诗/poet.song.196000.json','["獨自敲推到夜深，情知未稱惜花心。", "玉兒已死雲英嫁，誰唱梅詞伴我吟。"]'),
('1bcdda35-d472-4ec3-a0d2-bdc466d5d22f','夢梅','趙時韶','宋','宋诗','song-poetry','','[]','夢醒春風笑一場，攬衣推枕起思量。',32,'全唐诗/poet.song.196000.json','["夢醒春風笑一場，攬衣推枕起思量。", "草塘夢句有何好，夢到梅花字字香。"]'),
('1a1d431b-e6ba-48a5-bc12-d3bc927002b0','梅癖','趙時韶','宋','宋诗','song-poetry','','[]','幾度溪橋戀影香，衝風冒雨也思量。',32,'全唐诗/poet.song.196000.json','["幾度溪橋戀影香，衝風冒雨也思量。", "儘教人笑成梅癖，死不將詩到海棠。"]'),
('ad82e657-74d1-47da-b99e-40931e406217','梅債','趙時韶','宋','宋诗','song-poetry','','[]','擬把吟篇倚閣休，見梅時復上心頭。',35,'全唐诗/poet.song.196000.json','["擬把吟篇倚閣休，見梅時復上心頭。", "家貧幸免抨{攴}苦，詩債還添一段愁。"]'),
('e7640b52-b799-433e-b982-af668e6cb2f5','山園小梅得疏影橫斜水清淺暗香浮動月黄昏十四詩  其一','趙時韶','宋','宋诗','song-poetry','','[]','寂寞籬邊野水涯，三花雨蘂带春來。',32,'全唐诗/poet.song.196000.json','["寂寞籬邊野水涯，三花雨蘂带春來。", "且圖冷淡爲生活，不傍門庭閙熱開。"]'),
