('ccb549c1-7ccc-4d02-a2d3-2aaf387310e1','燕','趙時韶','宋','宋诗','song-poetry','','[]','窮簷穩穩好巢成，莫向朱門附麗人。',32,'全唐诗/poet.song.196000.json','["窮簷穩穩好巢成，莫向朱門附麗人。", "青杏屋梁雖好看，笙歌未必可安身。"]'),
('73e61652-61c6-4714-b7b8-8dedab67ae6b','雁和彥山韻','趙時韶','宋','宋诗','song-poetry','','[]','叫月聲聲到枕兒，稻粱雖飽豈能肥。',32,'全唐诗/poet.song.196000.json','["叫月聲聲到枕兒，稻粱雖飽豈能肥。", "夜深且傍瀟湘宿，明日晴空萬里飛。"]'),
('8e8bfd15-6a47-491c-a6dc-0c55f3914c15','蜂','趙時韶','宋','宋诗','song-poetry','','[]','蜜成只觧供樽俎，蠟就徒能照綺羅。',32,'全唐诗/poet.song.196000.json','["蜜成只觧供樽俎，蠟就徒能照綺羅。", "堪嘆汝生無受用，鑽鑽刺刺欲如何。"]'),
('33d29ee9-9438-495f-9924-cb71f72dea15','蚊雷','趙時韶','宋','宋诗','song-poetry','','[]','朝來伏地悄無聲，入夜轟轟屋底鳴。',32,'全唐诗/poet.song.196000.json','["朝來伏地悄無聲，入夜轟轟屋底鳴。", "堪笑不能驚蟄戶，空將胡蝶夢魂驚。"]'),
('270683f5-0a7a-407b-9cc5-d641481e09a6','木魚用韻','趙時韶','宋','宋诗','song-poetry','','[]','香積厨邊想像中，儼然摇鬣出吳松。',64,'全唐诗/poet.song.196000.json','["香積厨邊想像中，儼然摇鬣出吳松。", "不隨紅蓼灘頭釣，常逐闍梨飯後鍾。", "塵土幾年成涸鮒，風波平地欲成龍。", "若教占作維祥夢，憂國書生亦願豐。"]'),
('f766214d-b8c6-43e0-bf83-0785d727459f','聞杜鵑','趙時韶','宋','宋诗','song-poetry','','[]','雨過山山翠欲流，杜鵑要好莫啼休。',32,'全唐诗/poet.song.196000.json','["雨過山山翠欲流，杜鵑要好莫啼休。", "錦城宮殿多烟草，枉與春風作對頭。"]'),
('2447409a-f173-4614-a77e-ce2b6100a463','祈雨感應琴齋簷溜忽得雙魚','趙時韶','宋','宋诗','song-poetry','','[]','簷流非沼亦非池，躍出雙魚亦自奇。',64,'全唐诗/poet.song.196000.json','["簷流非沼亦非池，躍出雙魚亦自奇。", "不是懸於庭上落，便因生出釜中來。", "聽琴莫笑音非古，叶夢須知稔可期。", "謾說佩金佳讖在，陶腰似覺未消伊。"]'),
('9ec636ef-ca16-4e8b-b963-dce26efb3188','庚辰春疥西峰壁  其一','趙時韶','宋','宋诗','song-poetry','','[]','三五年時折桂來，也曾班底戴花回。',32,'全唐诗/poet.song.196000.json','["三五年時折桂來，也曾班底戴花回。", "而今四十還流落，却被人呼老秀才。"]'),
('a23cae27-9519-4a70-89f4-9c9968282cc2','庚辰春疥西峰壁  其二','趙時韶','宋','宋诗','song-poetry','','[]','山中亦有薇堪采，海上那無節可持。',32,'全唐诗/poet.song.196000.json','["山中亦有薇堪采，海上那無節可持。", "野老不知人事改，相逢猶話舊年時。"]'),
('3c24c08a-7a5b-4035-a240-38ff4ecf2f2b','夜窗','趙時韶','宋','宋诗','song-poetry','','[]','候蟲鳴砌冷蕭蕭，半點殘燈伴寂寥。',32,'全唐诗/poet.song.196000.json','["候蟲鳴砌冷蕭蕭，半點殘燈伴寂寥。", "桐葉軃秋黄不徹，那堪小雨學芭蕉。"]'),
('bdcc3879-510f-4d1a-b056-ea37f58bde7a','贄管竹樓  其一','趙時韶','宋','宋诗','song-poetry','','[]','天生賢佐福閩州，衮舄熒煌尚黑頭。',64,'全唐诗/poet.song.196000.json','["天生賢佐福閩州，衮舄熒煌尚黑頭。", "司馬公留民可活，管夷吾在世何憂。", "東南人物幾華屋，今古乾坤一竹樓。", "三萬卷書三尺劍，男兒事業要伊周。"]'),
('9fb16582-4927-4346-a159-28749373ccb7','贄管竹樓  其二','趙時韶','宋','宋诗','song-poetry','','[]','我公自是活神明，皦日當空鬼魅驚。',64,'全唐诗/poet.song.196000.json','["我公自是活神明，皦日當空鬼魅驚。", "參輩雖多蕭相少，跖徒自濁伯夷清。", "吳兒久借乾坤造，閩囝重逢父母生。", "賸說謙尊能下士，青門還念種瓜平。"]'),
('d86ae226-8077-4268-8c32-4fcef2304c44','閑居書懷','趙時韶','宋','宋诗','song-poetry','','[]','簷溜垂垂筯未收，一年樂事負春遊。',64,'全唐诗/poet.song.196000.json','["簷溜垂垂筯未收，一年樂事負春遊。", "新添華髮羞開鏡，貪看青山懶下樓。", "天地至今多罔象，功名到底總蚍蜉。", "祇因知得清閑好，事大如山付醉休。"]'),
('b2669d2b-ab2b-4ac4-9fc8-b49a11865031','閑居感懷和屏山韻','趙時韶','宋','宋诗','song-poetry','','[]','還我山林且買鄰，荆榛不礙自由身。',64,'全唐诗/poet.song.196000.json','["還我山林且買鄰，荆榛不礙自由身。", "梅兄竹弟相依舊，李婢桃奴一任新。", "湖海到今無劍客，江山如作老詩人。", "不知尚父緣何事，白首投竿起渭濱。"]'),
('5d2e2d67-a67a-43f7-99e9-613b13db554a','占盡風情向小園','趙時韶','宋','宋诗','song-poetry','','[]','月下相逢當麗人，嫣然体態皎然身。',32,'全唐诗/poet.song.196000.json','["月下相逢當麗人，嫣然体態皎然身。", "誰知一角閑田地，包括乾坤不盡春。"]'),
('d74e186d-630b-4e7f-bb0a-53dffdf16ac1','不須檀板與金樽','趙時韶','宋','宋诗','song-poetry','','[]','醒來拍手倚雕欄，啜茗哦詩子細看。',32,'全唐诗/poet.song.196000.json','["醒來拍手倚雕欄，啜茗哦詩子細看。", "縱有淺斟低唱者，箇中清意不相干。"]'),
('1e8fd5d5-7d46-4254-b0e7-24f234f232e5','霜禽欲下先偷眼','趙時韶','宋','宋诗','song-poetry','','[]','翠羽啁嘈逐曉風，海仙時遣探芳叢。',32,'全唐诗/poet.song.196000.json','["翠羽啁嘈逐曉風，海仙時遣探芳叢。", "徘徊睥睨知何意，怕干時人挾彈弓。"]'),
('28c5ce02-af17-4987-8cbe-6fbac30d4927','粉蝶如知合斷魂','趙時韶','宋','宋诗','song-poetry','','[]','一自英臺魄化時，生來長是宿芳菲。',32,'全唐诗/poet.song.196000.json','["一自英臺魄化時，生來長是宿芳菲。", "傷心只欠含章夢，不得枝頭作雪飛。"]'),
('11744f73-77fd-4a1d-80fd-91dfae197420','余出留遠曾先生門牆因侍留耕先生座間出示有懷樓居倉使救荒之詩僭越用韻','趙時韶','宋','宋诗','song-poetry','','[]','乾坤秀氣孕三奇，勳葉人間有口碑。',64,'全唐诗/poet.song.196000.json','["乾坤秀氣孕三奇，勳葉人間有口碑。", "臺近棠陰遺澤在，樓輝秋萼起人思。", "後先玉季金昆政，多少丹山碧水詩。", "世事蕩來尚膠轕，頼君一手理紛絲。"]'),
('2139f7f1-27c1-4d36-beb0-7d7ea5556a65','文中子','趙時韶','宋','宋诗','song-poetry','','[]','一脈斯文繫大儒，干戈滿地獨詩書。',32,'全唐诗/poet.song.196000.json','["一脈斯文繫大儒，干戈滿地獨詩書。", "南風有操無人識，身在汾亭心在虞。"]'),
('5f765f81-eed0-47ec-a214-e66a9e9bca6d','偈頌二十五首  其一','釋智愚','宋','宋诗','song-poetry','','[]','迦葉當時性燥，下得一椎。',39,'全唐诗/poet.song.196000.json','["迦葉當時性燥，下得一椎。", "莫道文殊三處度夏，直饒黄面老子別有神通，也須腦門著地。"]'),
('6e6a82d9-0e14-44c4-b816-f0c4b0bbc375','偈頌二十五首  其二','釋智愚','宋','宋诗','song-poetry','','[]','秋風淅淅，秋水冷冷。',36,'全唐诗/poet.song.196000.json','["秋風淅淅，秋水冷冷。", "千辛萬苦，負笈擔簦。", "張公堠子李家店，草舍茅庵短作程。"]'),
('52075983-bc87-48e0-8d94-21ceb73ff142','偈頌二十五首  其三','釋智愚','宋','宋诗','song-poetry','','[]','人間燈，天上月。',40,'全唐诗/poet.song.196000.json','["人間燈，天上月。", "有明有暗，有圓有缺，底事貪觀心未歇。", "興聖室內無油，免得證龜作鼈。"]'),
('797eeb0a-08ec-45eb-a1da-1cc80ef25f41','偈頌二十五首  其四','釋智愚','宋','宋诗','song-poetry','','[]','金風吹落葉，玉露滴清秋。',36,'全唐诗/poet.song.196000.json','["金風吹落葉，玉露滴清秋。", "尀耐寒山子，無言笑點頭。", "既能明似鏡，何用曲如鈎。"]'),
('8d659c65-b225-4f0c-9e83-e986c9384104','偈頌二十五首  其五','釋智愚','宋','宋诗','song-poetry','','[]','天晴蓋却屋，乘時刈却禾。',24,'全唐诗/poet.song.196000.json','["天晴蓋却屋，乘時刈却禾。", "輸納皇租了，鼓腹唱謳歌。"]'),
('aa28ea3f-e3d5-4d21-8b6f-8ed08782deef','偈頌二十五首  其六','釋智愚','宋','宋诗','song-poetry','','[]','無義漢，誰識你。',40,'全唐诗/poet.song.196000.json','["無義漢，誰識你。", "口吃耳聾，馿拗到底。", "一氣轉一藏，是非終難洗。", "大法下衰，汙人唇齒。"]'),
('9122f509-f8a5-491d-99cb-c9e244749c5e','偈頌二十五首  其七','釋智愚','宋','宋诗','song-poetry','','[]','槿花凝露，梧葉鳴秋。',35,'全唐诗/poet.song.196000.json','["槿花凝露，梧葉鳴秋。", "遇景觸物，隨分知羞。", "住住，諸方聞得道，我說老婆禪。"]'),
('f0d39eea-8a02-4b52-8e4b-f7a3ceb0a854','偈頌二十五首  其八','釋智愚','宋','宋诗','song-poetry','','[]','一年有十二箇月，每月一度團圓，其餘盡是缺。',57,'全唐诗/poet.song.196000.json','["一年有十二箇月，每月一度團圓，其餘盡是缺。", "中間晦明出沒，太半有不見者。", "惟有今宵，分外皎潔。", "無物堪比倫，教我如何說。"]'),
('a1fbbf9b-1bc9-44a1-950d-26c3be1a2489','偈頌二十五首  其九','釋智愚','宋','宋诗','song-poetry','','[]','流虹七載夤緣盡，又向天寧理倩窠。',32,'全唐诗/poet.song.196000.json','["流虹七載夤緣盡，又向天寧理倩窠。", "脫得馿胎入馬腹，皮毛輕重不爭多。"]'),
('7b50989a-0ff6-49c1-9ff5-b788724e4b57','偈頌二十五首  其一○','釋智愚','宋','宋诗','song-poetry','','[]','好一局棋，黑白已分。',24,'全唐诗/poet.song.196000.json','["好一局棋，黑白已分。", "只是末後一著，無人知得落處。"]'),
('dcfda35c-23ad-48a5-a36c-79f32ae0f8ff','偈頌二十五首  其一一','釋智愚','宋','宋诗','song-poetry','','[]','古佛過去亦久矣，不知何處應羣生。',32,'全唐诗/poet.song.196000.json','["古佛過去亦久矣，不知何處應羣生。", "紫金光聚人難覩，空裏惟聞仙樂鳴。"]'),
('608441cd-138f-431c-b734-3b1406cabc48','偈頌二十五首  其一二','釋智愚','宋','宋诗','song-poetry','','[]','溪林葉墮，塞鴈聲寒。',36,'全唐诗/poet.song.196000.json','["溪林葉墮，塞鴈聲寒。", "見成公案，大難大難。", "百雜碎，鐵團圞，和風搭在玉闌干。"]'),
('171e3df7-21bf-46f3-a472-bbebb23600be','偈頌二十五首  其一三','釋智愚','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽七十二峯，華頂萬八千丈。',36,'全唐诗/poet.song.196000.json','["南嶽七十二峯，華頂萬八千丈。", "瞻之無際，仰之無垠。", "以此無窮數，用祝聖明君。"]'),
('9ad03174-bb69-4c26-89dd-778c453cd22c','偈頌二十五首  其一四','釋智愚','宋','宋诗','song-poetry','','[]','一日日，一時時。',38,'全唐诗/poet.song.196000.json','["一日日，一時時。", "逗到臘八夜，眼上錯安眉。", "東西不辨，南北狐疑，從教萬古業風吹。"]'),
('6cefb878-99fa-4397-bfe6-12acccd237b3','偈頌二十五首  其一五','釋智愚','宋','宋诗','song-poetry','','[]','聖人無己，靡所不己。',41,'全唐诗/poet.song.196000.json','["聖人無己，靡所不己。", "總塵剎無不是，差之毫釐失千里。", "仙仗飄颻去不還，從教六合清風起。"]'),
('edacec00-26fa-4c7b-8783-3077457857a5','偈頌二十五首  其一六','釋智愚','宋','宋诗','song-poetry','','[]','金以石試，人以言試。',26,'全唐诗/poet.song.196000.json','["金以石試，人以言試。", "古人自謂全璧而歸，不知身在草裏。"]'),
('dd4d1ab3-71d5-43c7-a942-f9c7f2b2f923','偈頌二十五首  其一七','釋智愚','宋','宋诗','song-poetry','','[]','一跳一躑，師子嚬呻。',37,'全唐诗/poet.song.196000.json','["一跳一躑，師子嚬呻。", "一新一舊，和氣如春。", "報恩尺不如寸，贏得癡坐，家裏有人。"]'),
('c3e50470-1df6-448c-9eac-b523b175dde6','偈頌二十五首  其一八','釋智愚','宋','宋诗','song-poetry','','[]','蠅見血，鶻捉鳩。',26,'全唐诗/poet.song.196000.json','["蠅見血，鶻捉鳩。", "拳來踢報，膠漆相投。", "難提掇處轉風流。"]'),
('42c4ab8c-71b1-4e04-9eff-b076c0d82663','偈頌二十五首  其一九','釋智愚','宋','宋诗','song-poetry','','[]','春風如刀，春雨如膏。',20,'全唐诗/poet.song.196000.json','["春風如刀，春雨如膏。", "衲僧門下，何用忉忉。"]'),
('928a1200-780f-42c1-bb4a-2b3924526ce4','偈頌二十五首  其二○','釋智愚','宋','宋诗','song-poetry','','[]','杜宇不如歸，竹雞泥滑滑。',36,'全唐诗/poet.song.196000.json','["杜宇不如歸，竹雞泥滑滑。", "深山巖崖中，誰道無佛法。", "有佛法，衲僧只有三隻襪。"]'),
('0fc30dec-f365-4d4b-bce4-136a03511012','偈頌二十五首  其二一','釋智愚','宋','宋诗','song-poetry','','[]','山僧恰似抱璞者，但欠臨風涕泣。',28,'全唐诗/poet.song.196000.json','["山僧恰似抱璞者，但欠臨風涕泣。", "不道舉世無人，只是可惜許。"]'),
('a72a8220-eebf-4d5a-82b0-533dc2eaf121','偈頌二十五首  其二二','釋智愚','宋','宋诗','song-poetry','','[]','說如建瓴，坐如山嶽。',20,'全唐诗/poet.song.196000.json','["說如建瓴，坐如山嶽。", "就下平高，咬牙爆爆。"]'),
('d66104aa-1d76-4c4a-ba96-ef134cf9d919','偈頌二十五首  其二三','釋智愚','宋','宋诗','song-poetry','','[]','大道只在目前，要且目前難覩。',28,'全唐诗/poet.song.196000.json','["大道只在目前，要且目前難覩。", "欲識大道真體，不離聲色言語。"]'),
('6e82affa-3ade-475b-a00b-6f5361be0c05','偈頌二十五首  其二四','釋智愚','宋','宋诗','song-poetry','','[]','古佛只在椎頭，每日呼來喚去。',44,'全唐诗/poet.song.196000.json','["古佛只在椎頭，每日呼來喚去。", "非惟網令清巖，下下要分緇素。", "興化當年錯用心，月明豈在珊瑚樹。"]'),
('340f9373-932a-4d33-9dd4-18e5cc912ec1','偈頌二十五首  其二五','釋智愚','宋','宋诗','song-poetry','','[]','斂影窮原懶出扃，曉雲如送又如迎。',32,'全唐诗/poet.song.196000.json','["斂影窮原懶出扃，曉雲如送又如迎。", "因思執手經行處，幾聽沙泉遶磵鳴。"]'),
('30a8c362-cdcc-426b-9a12-9a8e36c84c11','偈頌十三首  其一','釋智愚','宋','宋诗','song-poetry','','[]','不勞彈指，豈涉思惟。',20,'全唐诗/poet.song.196000.json','["不勞彈指，豈涉思惟。", "現成門戶，到者方知。"]'),
('92b894ec-9668-4eff-8c26-6ca47000ac7e','偈頌十三首  其二','釋智愚','宋','宋诗','song-poetry','','[]','居必擇鄰，鑑非止水。',20,'全唐诗/poet.song.196000.json','["居必擇鄰，鑑非止水。", "明暗相凌，言猶在耳。"]'),
('46ec3051-e11f-421d-9189-b9c36570267a','偈頌十三首  其三','釋智愚','宋','宋诗','song-poetry','','[]','水中鹽味，色裏膠青。',63,'全唐诗/poet.song.196000.json','["水中鹽味，色裏膠青。", "祖師只認得箇相似底，何異楚人以鷄爲鳳。", "我者裏任你三頭六臂，盡其來機，也無你湊泊處。", "慣將三尺喙，駡倒五湖僧。"]'),
('de67b07e-2b42-465b-82fb-cbb882a6331d','偈頌十三首  其四','釋智愚','宋','宋诗','song-poetry','','[]','傷弓之鳥，見曲木而高飛。',24,'全唐诗/poet.song.196000.json','["傷弓之鳥，見曲木而高飛。", "有人見得雲門，善爲我辭。"]'),
('3ebcba0e-1e26-43ca-8153-db42ccbcc033','偈頌十三首  其五','釋智愚','宋','宋诗','song-poetry','','[]','凈瓶裏澡洗，古檮下修身。',54,'全唐诗/poet.song.196000.json','["凈瓶裏澡洗，古檮下修身。", "彼此寸長尺短，何妨忝爲切鄰。", "相見又無事，不來還憶君。", "杜鵑啼斷月如晝，不似尋常空過春。"]'),
('6374ee43-e546-4c8a-afdf-22a7d7d46af7','偈頌十三首  其六','釋智愚','宋','宋诗','song-poetry','','[]','老和尚死去二十五年，有誰撐門拄戶。',67,'全唐诗/poet.song.196000.json','["老和尚死去二十五年，有誰撐門拄戶。", "雖與松源同日行，不會松源三轉語。", "父子背馳，面不相覩，直至如今成莽鹵。", "露冷風高秋意深，久矣無心薦藜黍。"]'),
('198b7bb0-776a-4866-b40a-390265f85de4','偈頌十三首  其七','釋智愚','宋','宋诗','song-poetry','','[]','華亭滿船猶不足，南泉驟步蹈不著。',30,'全唐诗/poet.song.196000.json','["華亭滿船猶不足，南泉驟步蹈不著。", "自餘眼底紛紛，總道見月忘指。"]'),
('96cd12b7-f282-4aa8-b3d3-9b1a102557f9','偈頌十三首  其八','釋智愚','宋','宋诗','song-poetry','','[]','葱嶺不見宋雲，全身豈在熊耳。',72,'全唐诗/poet.song.196000.json','["葱嶺不見宋雲，全身豈在熊耳。", "石火電光殊莫擬，雙檮堂上再相逢。", "究竟何曾缺兩齒，雪際傳心，篩灰厭鬼，後代兒孫誰來。", "你粗羹淡飯當殷勤，四海香風從此起。"]'),
('ed881f11-5907-494f-8432-0dc902a07fd0','偈頌十三首  其九','釋智愚','宋','宋诗','song-poetry','','[]','溈山若無後語，儘自包裹得去。',28,'全唐诗/poet.song.196000.json','["溈山若無後語，儘自包裹得去。", "其奈用處太過，以致栓索俱露。"]'),
('e8094629-0e7a-42ce-91ff-1522df6f6fc2','偈頌十三首  其一○','釋智愚','宋','宋诗','song-poetry','','[]','我本無心有所希求，今此寶藏自然而至。',53,'全唐诗/poet.song.196000.json','["我本無心有所希求，今此寶藏自然而至。", "二林小衆，枯枯燥燥，鶴望多時。", "珊瑚枕，明月珠，從便採取，只是不得觸諱。"]'),
('50727980-5b0a-4276-bb7f-870bc75ee553','偈頌十三首  其一一','釋智愚','宋','宋诗','song-poetry','','[]','遠之莫及故曰短，蹤之不即故曰蓬。',42,'全唐诗/poet.song.196000.json','["遠之莫及故曰短，蹤之不即故曰蓬。", "波波浪浪，西西東東。", "直鈎已掛雙峨碧，一橈香散蘆花風。"]'),
('9ab6901b-3d06-4512-94ad-537fa63e2a24','偈頌十三首  其一二','釋智愚','宋','宋诗','song-poetry','','[]','十萬里水雲蹤跡，七百年西竺陳人。',79,'全唐诗/poet.song.196000.json','["十萬里水雲蹤跡，七百年西竺陳人。", "眼睛烏律卒，面子黑鱗皴。", "傳衣付法，惹起埃塵。", "如今紅紫亂朱紛然而出，豈止乎少林五葉一花之春。", "斯臨遠諱，薦此溪蘋，萬古千秋累子孫。"]'),
('9b31ef73-e208-4a1e-8cdf-4bfd951d7285','偈頌十三首  其一三','釋智愚','宋','宋诗','song-poetry','','[]','日日日東上，日日日西沉。',24,'全唐诗/poet.song.196000.json','["日日日東上，日日日西沉。", "無爲無事者，子細好推尋。"]'),
('b751edf6-ddfa-44bf-96c2-444e22bca685','偈頌二十四首  其一','釋智愚','宋','宋诗','song-poetry','','[]','約束萬象，聳動人天。',28,'全唐诗/poet.song.196000.json','["約束萬象，聳動人天。", "風雲會合，來自日邊，縱饒海口亦難宣。"]'),
('3896f758-b33c-4155-85bc-c3587304c459','偈頌二十四首  其二','釋智愚','宋','宋诗','song-poetry','','[]','同門出入，未嘗謾你。',26,'全唐诗/poet.song.196000.json','["同門出入，未嘗謾你。", "諸人苟或粉飾太過，山僧只得掩耳。"]'),
('f5dddc06-8e2e-4929-8f96-ce27d7da2334','偈頌二十四首  其三','釋智愚','宋','宋诗','song-poetry','','[]','雞足峯前，黄梅渡口，逗到冷泉幾掣肘。',50,'全唐诗/poet.song.196000.json','["雞足峯前，黄梅渡口，逗到冷泉幾掣肘。", "若謂凌霄非正傳，畢竟衣法屬誰手。", "野犴鳴，獅子吼，虛空昨夜翻筋斗。"]'),
('6e10a327-d430-4f43-9136-58e9d196cf50','偈頌二十四首  其四','釋智愚','宋','宋诗','song-poetry','','[]','虎憎雞嘴，聞者畏之。',24,'全唐诗/poet.song.196000.json','["虎憎雞嘴，聞者畏之。", "後人衡鑑不高，喚作二俱弄險。"]'),
('30feb97c-ef73-46c4-b52f-3e55a6d60218','偈頌二十四首  其五','釋智愚','宋','宋诗','song-poetry','','[]','人間無，天上有，往往無人脫窠臼。',48,'全唐诗/poet.song.196000.json','["人間無，天上有，往往無人脫窠臼。", "四海娟娟洗玉魂，九野茫茫白兔走。", "寒山子，不關口，也落馬駒羣隊後。"]'),
('d50b5359-af28-423e-9df2-bd06ff8a2c37','偈頌二十四首  其六','釋智愚','宋','宋诗','song-poetry','','[]','一人要貧貧不得，一人要富富不得。',32,'全唐诗/poet.song.196000.json','["一人要貧貧不得，一人要富富不得。", "要知貧富不相當，且請各歸本位立。"]'),
('b26c87db-be70-4447-97eb-11f9ce8df8ef','偈頌二十四首  其七','釋智愚','宋','宋诗','song-poetry','','[]','朕聞上古，其風朴略。',50,'全唐诗/poet.song.196000.json','["朕聞上古，其風朴略。", "王言如絲，誰敢不聽。", "忽有人問鄮山，只向他道，風門海口，當風抵浪，也須是箇人始得。"]'),
('f061c502-f1e7-4ce2-9163-2149ce696012','偈頌二十四首  其八','釋智愚','宋','宋诗','song-poetry','','["\u8861\u5c71"]','鏡容鷹爪，面目可憎。',56,'全唐诗/poet.song.196000.json','["鏡容鷹爪，面目可憎。", "掉發南嶽，下山教化。", "從臾檮林，對御講經。", "不守疆界，干犯清平。", "滅得中峯正法眼，破沙盆子話方行。"]'),
('5def9c84-244e-46d8-8243-cca5fb7242a0','偈頌二十四首  其九','釋智愚','宋','宋诗','song-poetry','','[]','舊去新來懶送迎，巖間塚下見枯形。',32,'全唐诗/poet.song.196000.json','["舊去新來懶送迎，巖間塚下見枯形。", "忍成殘臘半宵夢，坐對寒檠兩歲燈。"]'),
('6a4a6b14-85d1-4e46-914a-2c87d985ffe5','偈頌二十四首  其一○','釋智愚','宋','宋诗','song-poetry','','[]','時遷物換，革故鼎新。',34,'全唐诗/poet.song.196000.json','["時遷物換，革故鼎新。", "土膏未動，商量打春。", "太公有意垂釣，夫子無心獲麟。"]'),
('48077395-ed46-49fe-b9de-0cfa7f720e5f','偈頌二十四首  其一一','釋智愚','宋','宋诗','song-poetry','','[]','去時曉露消袢暑，歸日秋聲滿夕陽。',32,'全唐诗/poet.song.196000.json','["去時曉露消袢暑，歸日秋聲滿夕陽。", "恩渥重重何以報，望無雲處祝天長。"]'),
('1f2ba927-a222-4ac8-b977-021c871e5aab','偈頌二十四首  其一二','釋智愚','宋','宋诗','song-poetry','','[]','一年又一年，循環數不足。',49,'全唐诗/poet.song.196000.json','["一年又一年，循環數不足。", "本分面上人，猶如隔羅縠。", "惟有南極老人，扣天鼓三下，望北關而祝，願我王萬福。"]'),
('7e784ac0-5ccb-4a57-bf46-65fe8995258d','偈頌二十四首  其一三','釋智愚','宋','宋诗','song-poetry','','[]','外闔不閉，跨天下而無蘄。',24,'全唐诗/poet.song.196000.json','["外闔不閉，跨天下而無蘄。", "會得許你，陞其堂入其室。"]'),
('0369bb37-8919-4dc0-a31e-38b1bb0ba04e','偈頌二十四首  其一四','釋智愚','宋','宋诗','song-poetry','','[]','世尊三昧，金口玉音，親付囑紫泥芝檢。',50,'全唐诗/poet.song.196000.json','["世尊三昧，金口玉音，親付囑紫泥芝檢。", "九重城裏鳳銜來，再霑雨露之恩，光闡法門之盛。", "聲前妙證，聳動羣心。"]'),
('a4b9784f-a98f-4475-900e-7f5b70927a16','偈頌二十四首  其一五','釋智愚','宋','宋诗','song-poetry','','[]','烟慘淡，石玲瓏。',26,'全唐诗/poet.song.196000.json','["烟慘淡，石玲瓏。", "面面廝覷，千峯萬峯，一團和氣在其中。"]'),
('a6df9a78-60c4-4200-942b-6131e456b57f','偈頌二十四首  其一六','釋智愚','宋','宋诗','song-poetry','','[]','春入湖山，先放花明。',91,'全唐诗/poet.song.196000.json','["春入湖山，先放花明。", "御苑人歸上國，南山鶴唳青松。", "壯皇都人傑地靈，窺紫府洞天風月。", "透聲透色，絕類離倫。", "不妨垂手入廛，畢竟難逃至化。", "且望闕酬恩，如何祝賛。", "版圖遠奏堯天闊，萬物呈祥樂聖情。"]'),
('995889b8-b14d-454f-bf71-7df4e8518086','偈頌二十四首  其一七','釋智愚','宋','宋诗','song-poetry','','[]','奸峭互陳，對面千里。',30,'全唐诗/poet.song.196000.json','["奸峭互陳，對面千里。", "有人寄僧過夏，南山大開東閤，彼此出家兒。"]'),
('1287d143-b821-4ae4-906d-8c354a842c1d','偈頌二十四首  其一八','釋智愚','宋','宋诗','song-poetry','','[]','此山無路，及門者誰。',23,'全唐诗/poet.song.196000.json','["此山無路，及門者誰。", "會得擺手同歸，不然隨我來。"]'),
('46410ec6-39bf-4177-8984-06e64f7af589','偈頌二十四首  其一九','釋智愚','宋','宋诗','song-poetry','','[]','釋迦掩室於摩竭，因甚坐在者裏。',25,'全唐诗/poet.song.196000.json','["釋迦掩室於摩竭，因甚坐在者裏。", "炷拜勤渠，齊之以禮。"]'),
('f5acec4c-439c-45da-9888-d736f3d349d8','偈頌二十四首  其二○','釋智愚','宋','宋诗','song-poetry','','[]','虎頭燕頷，鳥嘴魚顋。',27,'全唐诗/poet.song.196000.json','["虎頭燕頷，鳥嘴魚顋。", "盡向者裏納款，且道者裏是甚麽所在。"]'),
('d905597d-58a1-4ead-be80-d59183043e39','偈頌二十四首  其二一','釋智愚','宋','宋诗','song-poetry','','[]','有意退欄，無心耕牧。',42,'全唐诗/poet.song.196000.json','["有意退欄，無心耕牧。", "九重降勑，如萬國春回。", "一道恩光，似千日並照。", "法門騰煥，巖壑生秋。"]'),
('03dbb04e-1f37-4fa8-9921-d021f772c100','偈頌二十四首  其二二','釋智愚','宋','宋诗','song-poetry','','[]','日出而作，日入而息。',25,'全唐诗/poet.song.196000.json','["日出而作，日入而息。", "熈熈然如登春臺，且道承誰恩力。"]'),
('825788e8-ef62-44f6-8b78-8ac97e6cb982','偈頌二十四首  其二三','釋智愚','宋','宋诗','song-poetry','','[]','出山而見，入戶而知。',28,'全唐诗/poet.song.196000.json','["出山而見，入戶而知。", "雞棲鳳巢，隣壁之輝，何必區區點綴伊。"]'),
('3a6764d0-59c3-410c-88de-e5f42f4193ad','偈頌二十四首  其二四','釋智愚','宋','宋诗','song-poetry','','[]','勤儉起家，叢林麟鳳。',28,'全唐诗/poet.song.196000.json','["勤儉起家，叢林麟鳳。", "入門一見，和氣可掬，知心不在頻叮囑。"]'),
('5b70426b-5e19-4d31-800a-fe086843d212','自贊','釋智愚','宋','宋诗','song-poetry','','[]','不開駡人口，難以見其慈。',56,'全唐诗/poet.song.196000.json','["不開駡人口，難以見其慈。", "不徵衲子病，難以表其師。", "似之則殃門添禍，否之則鳳林吒之。", "畫工筆熟不識伊，白髮毿毿箇是誰。"]'),
('b862a3ea-cb83-4818-894f-1b68d414bac3','蓬萊宣長老請贊','釋智愚','宋','宋诗','song-poetry','','[]','啐啄之機，臨崖一拶。',36,'全唐诗/poet.song.196000.json','["啐啄之機，臨崖一拶。", "虎嘯龍吟，二九十八。", "宣禪自是惡冤家，學伊豈止頂門瞎。"]'),
('425c4467-df49-4d74-b83a-ec2369fb7e85','妙源首座請贊','釋智愚','宋','宋诗','song-poetry','','[]','道不可傳，貌不可繪。',36,'全唐诗/poet.song.196000.json','["道不可傳，貌不可繪。", "冷坐深雲，虎視百怪。", "源遠流長滅正宗，不比瞎馿趁大隊。"]'),
('dde59c9a-46df-4503-8c43-8d6f65257a34','無隠侍者請贊','釋智愚','宋','宋诗','song-poetry','','[]','斗斗㖃㖃，雷驅電馳。',52,'全唐诗/poet.song.196000.json','["斗斗㖃㖃，雷驅電馳。", "垂手未遊象外，虛空突出毫釐。", "目前難遏密，冷落有誰知。", "父攘羊，子證之，從教萬古黑風吹。"]'),
('199753e5-7370-48de-a3fa-9456a13b39f6','本立藏主請贊','釋智愚','宋','宋诗','song-poetry','','[]','春山萬疊，秋水一痕。',40,'全唐诗/poet.song.196000.json','["春山萬疊，秋水一痕。", "凜然風彩，何處求真。", "大方出沒兮全生全殺，叢林悱悱兮獨角一麟。"]'),
('38c4737c-d1ff-46b0-bfde-0d377b6be701','無補侍者請贊','釋智愚','宋','宋诗','song-poetry','','[]','計較拙於鳩，軒昂老而虎。',46,'全唐诗/poet.song.196000.json','["計較拙於鳩，軒昂老而虎。", "聞必意消，見者難覩，到頭不識賓中主。", "黑漆竹篦劈面揮，師資誰謂無裨補。"]'),
('9418fb14-a732-40f7-acdb-f06bcbf53753','法雲首座請贊','釋智愚','宋','宋诗','song-poetry','','[]','咿嗚咿，那得知。',44,'全唐诗/poet.song.196000.json','["咿嗚咿，那得知。", "寒酸看不上眼，手面移東換西。", "拱良工手，破衲僧疑。", "行到水窮處，坐看雲起時。"]'),
('38b78b88-d5aa-4461-a5e1-e3b069600d2d','頌古一百首  其一','釋智愚','宋','宋诗','song-poetry','','[]','紫金光聚照山河，天上人間意氣多。',32,'全唐诗/poet.song.196000.json','["紫金光聚照山河，天上人間意氣多。", "曾勑文殊領徒衆，毗耶城裏問維摩。"]'),
('730e496d-068d-4c2a-ae4f-a61b69f69a1e','頌古一百首  其二','釋智愚','宋','宋诗','song-poetry','','[]','有三尺劍可以謁趙國，無千里眼難以見懸絲。',30,'全唐诗/poet.song.196000.json','["有三尺劍可以謁趙國，無千里眼難以見懸絲。", "巍巍堂堂，三界大師。"]'),
('78d29aa3-d933-49b7-b2da-dc9cc0826389','頌古一百首  其三','釋智愚','宋','宋诗','song-poetry','','[]','有力量人終是別，等閑垂手便相應。',32,'全唐诗/poet.song.196000.json','["有力量人終是別，等閑垂手便相應。", "如何夜半扶桑日，推上須彌最上層。"]'),
('228f17f7-b8a0-45a0-9c78-39c717f86703','頌古一百首  其四','釋智愚','宋','宋诗','song-poetry','','[]','夜闌天際墮金盆，膝上焦桐調轉新。',32,'全唐诗/poet.song.196000.json','["夜闌天際墮金盆，膝上焦桐調轉新。", "易水悲風輕按指，鸞膠難續斷腸人。"]'),
('29aa861b-1f8d-4bc2-b47e-b40d2eb7686b','頌古一百首  其五','釋智愚','宋','宋诗','song-poetry','','[]','鐵壁迸開雲片片，黑出輥出月團團。',32,'全唐诗/poet.song.196000.json','["鐵壁迸開雲片片，黑出輥出月團團。", "就中明暗相陵處，天外出頭誰解看。"]'),
('b530236f-7e2b-42bd-afc8-c1aa39bb7250','頌古一百首  其六','釋智愚','宋','宋诗','song-poetry','','[]','大人境界終難到，到後如何說向人。',32,'全唐诗/poet.song.196000.json','["大人境界終難到，到後如何說向人。", "不是當人知見力，莫將知見別疏親。"]'),
('775a7991-75c9-4058-91ae-39594e1291d5','頌古一百首  其七','釋智愚','宋','宋诗','song-poetry','','[]','玉簫吹徹鳳凰臺，古殿深沈曉未開。',32,'全唐诗/poet.song.196000.json','["玉簫吹徹鳳凰臺，古殿深沈曉未開。", "滿地落花春已過，綠陰空鎖舊莓苔。"]'),
('3434f64c-671d-4fd5-8cac-2df67208e2c8','頌古一百首  其八','釋智愚','宋','宋诗','song-poetry','','[]','石潤非玉，水麗非金。',34,'全唐诗/poet.song.196000.json','["石潤非玉，水麗非金。", "大禹决而西泝，卞和泣而陸沈。", "美兮渺兮，錯古礱今。"]'),
('8c85da3b-a4cd-47b8-b144-6404cad9fb92','頌古一百首  其九','釋智愚','宋','宋诗','song-poetry','','[]','泠泠寒溜泣秋壑，纔會滄溟便泛舟。',32,'全唐诗/poet.song.196000.json','["泠泠寒溜泣秋壑，纔會滄溟便泛舟。", "見說許由曾洗耳，可憐巢父更鞭牛。"]'),
('096515d0-b0e2-490e-864d-27618b77a64c','頌古一百首  其一○','釋智愚','宋','宋诗','song-poetry','','[]','青山白雲，碧溪蘿月。',20,'全唐诗/poet.song.196000.json','["青山白雲，碧溪蘿月。", "畫虎成狸，只得一橛。"]'),
('515adfbc-d7a8-4687-87b6-e43a5250501d','頌古一百首  其一一','釋智愚','宋','宋诗','song-poetry','','[]','好將真法供如來，花在幽巖險處開。',32,'全唐诗/poet.song.196000.json','["好將真法供如來，花在幽巖險處開。", "一夜狂風吹欲盡，落英無數點蒼苔。"]'),
('613097a3-050b-410e-84f6-101b6012c8df','頌古一百首  其一二','釋智愚','宋','宋诗','song-poetry','','[]','青牛仙去不虛傳，常用虛中落斷邊。',32,'全唐诗/poet.song.196000.json','["青牛仙去不虛傳，常用虛中落斷邊。", "自是一生多蹇薄，夜深猶立古皇前。"]'),
('6b5567d0-bb93-4a7b-9b9d-8c725d94b0c9','頌古一百首  其一三','釋智愚','宋','宋诗','song-poetry','','[]','一口吞盡三世佛，牙如劍樹眼如鈴。',32,'全唐诗/poet.song.196000.json','["一口吞盡三世佛，牙如劍樹眼如鈴。", "斷絃不必鸞膠續，只要知音側耳聽。"]'),
('f71a469b-609e-472b-829f-88e5daf1456f','頌古一百首  其一四','釋智愚','宋','宋诗','song-poetry','','[]','籩豆纔陳見聖人，莫將生死較疏親。',32,'全唐诗/poet.song.196000.json','["籩豆纔陳見聖人，莫將生死較疏親。", "清臺曆日煩君看，一歲終須有一春。"]'),
('21024665-c1d1-4293-9404-211ecbc32168','頌古一百首  其一五','釋智愚','宋','宋诗','song-poetry','','[]','行弔先桃茢，喪車後紙錢。',24,'全唐诗/poet.song.196000.json','["行弔先桃茢，喪車後紙錢。", "老胡門下客，寧可入黄泉。"]'),
('2fabdc2d-5f4e-4921-8123-48258de3c790','頌古一百首  其一六','釋智愚','宋','宋诗','song-poetry','','[]','萬仞崖頭拚得去，不知何處覓全屍。',32,'全唐诗/poet.song.196000.json','["萬仞崖頭拚得去，不知何處覓全屍。", "業風吹起再甦醒，却問如今是甚時。"]'),
('56ac0500-1bc3-4989-9bda-773f9b0a9354','頌古一百首  其一七','釋智愚','宋','宋诗','song-poetry','','[]','野水浮輕楫，暖烟生紫蓴。',24,'全唐诗/poet.song.196000.json','["野水浮輕楫，暖烟生紫蓴。", "晚來湖上望，多是罟魚人。"]'),
('8b9343cb-a197-4fee-96db-1fad91af6d7a','頌古一百首  其一八','釋智愚','宋','宋诗','song-poetry','','[]','事到無心不苟欺，烏玄鵠白尚懷疑。',32,'全唐诗/poet.song.196000.json','["事到無心不苟欺，烏玄鵠白尚懷疑。", "自非親見黄頭老，爭敢逢人泄漏伊。"]'),
('572ff89c-ae4e-4352-8938-7458adbdf145','頌古一百首  其一九','釋智愚','宋','宋诗','song-poetry','','[]','白石鑿鑿，韞爾美璞。',20,'全唐诗/poet.song.196000.json','["白石鑿鑿，韞爾美璞。", "君子道晦，君子斯樂。"]'),
('55eee5b1-a0fc-4756-baf9-c720be5e2810','頌古一百首  其二○','釋智愚','宋','宋诗','song-poetry','','[]','季咸曾相壺丘子，隨變難分亟自逃。',32,'全唐诗/poet.song.196000.json','["季咸曾相壺丘子，隨變難分亟自逃。", "輸與高樓凝望者，烱然明可察秋毫。"]'),
('a68d9123-d9cd-41d9-b543-7767b12f1244','頌古一百首  其二一','釋智愚','宋','宋诗','song-poetry','','[]','欲識窮原處，何人爲指迷。',24,'全唐诗/poet.song.196000.json','["欲識窮原處，何人爲指迷。", "夕陽鷄犬外，桃李自成蹊。"]'),
