('f17566d8-a165-4685-958f-a020903e7ef1','渡蘆贊','釋智愚','宋','宋诗','song-poetry','','[]','江空蘆葉冷，風靜衲衣輕。',24,'全唐诗/poet.song.196000.json','["江空蘆葉冷，風靜衲衣輕。", "不得梁天子，無人知姓名。"]'),
('db31254e-af9f-4de5-b01e-feb1f3ee850d','面壁贊','釋智愚','宋','宋诗','song-poetry','','[]','嵌枯石老，黶瘦衣荒。',28,'全唐诗/poet.song.196000.json','["嵌枯石老，黶瘦衣荒。", "死水垂釣，陸地乘航。", "當初好采見梁王。"]'),
('248b387c-ff6f-48f7-8c25-820be7b1686b','西歸贊','釋智愚','宋','宋诗','song-poetry','','[]','壁觀九年，葫蘆按水。',36,'全唐诗/poet.song.196000.json','["壁觀九年，葫蘆按水。", "無計脫身，强分皮髓。", "隻履恓恓何處歸，月明後夜思熊耳。"]'),
('162378a3-6da7-4d68-b09e-7b1cc2ff259a','智者大師贊','釋智愚','宋','宋诗','song-poetry','','["\u8861\u5c71"]','太虛無雲，清鏡無痕。',46,'全唐诗/poet.song.196000.json','["太虛無雲，清鏡無痕。", "如意舉手，花雨繽紛。", "契南嶽不傳之旨，見靈山未散之人。", "妙圓體極，即相非真。"]'),
('eec10e7f-3c0e-44f8-81b0-f9053f2900b8','須菩提贊','釋智愚','宋','宋诗','song-poetry','','[]','持貝葉，倚瘦藜。',25,'全唐诗/poet.song.196000.json','["持貝葉，倚瘦藜。", "解空未盡，說是說非。", "無端引惹憍尸。"]'),
('e79ce377-1948-42e7-bbed-9f8e23e9e999','布袋和尚贊  其一','釋智愚','宋','宋诗','song-poetry','','[]','一肩駝不起，兩脚走如飛。',28,'全唐诗/poet.song.196000.json','["一肩駝不起，兩脚走如飛。", "業風交輥笑嘻嘻，問渠是誰渠不知。"]'),
('75bae2cc-df01-4f48-a7e3-e88158c612c5','布袋和尚贊  其二','釋智愚','宋','宋诗','song-poetry','','[]','夢裡昇兜率，閻浮待下生。',24,'全唐诗/poet.song.196000.json','["夢裡昇兜率，閻浮待下生。", "不須呈懵袋，亞毒已流行。"]'),
('6377c829-c0ed-422f-a278-9da42192f403','放拄杖睡贊','釋智愚','宋','宋诗','song-poetry','','[]','能所頓忘，佯佯瞌睡。',20,'全唐诗/poet.song.196000.json','["能所頓忘，佯佯瞌睡。", "一息不來，百川鼎沸。"]'),
('079f600a-b720-4d9e-8151-9d6b22da9afc','寒山拾得贊  其一','釋智愚','宋','宋诗','song-poetry','','[]','爨下偷僧飯，崖根抱虎眠。',34,'全唐诗/poet.song.196000.json','["爨下偷僧飯，崖根抱虎眠。", "懶吟長短句，來把梵書看。", "真箇看，牛皮也須穿。"]'),
('c38290ed-2a40-41ee-93ed-b8c48abcd30c','寒山拾得贊  其二','釋智愚','宋','宋诗','song-poetry','','[]','帚柄不忘，寸心未息。',34,'全唐诗/poet.song.196000.json','["帚柄不忘，寸心未息。", "冷眼看人，多少荆棘。", "咄哉遺棄小兒，豐干草裏拾得。"]'),
('d70d0371-88be-4402-8ef1-1d9459275d19','寒山背身立贊','釋智愚','宋','宋诗','song-poetry','','[]','駡豐干，是者漢。',34,'全唐诗/poet.song.196000.json','["駡豐干，是者漢。", "竹筒盛菜柦，指出教人見。", "其實只要知機，不欲彰頭露面。"]'),
('b1e2b6ae-16a0-47aa-930d-7ad5942798b6','拾得指空笑贊','釋智愚','宋','宋诗','song-poetry','','[]','木屐竹帚，粘脚綴手。',34,'全唐诗/poet.song.196000.json','["木屐竹帚，粘脚綴手。", "古佛家風，泥豬疥狗。", "指天大笑一聲，驚得虛空倒走。"]'),
('b0a51a27-0eae-41d5-b23f-389c4fcdbcb1','豐干騎虎贊','釋智愚','宋','宋诗','song-poetry','','[]','萬德不將來，猛獸自馴伏。',36,'全唐诗/poet.song.196000.json','["萬德不將來，猛獸自馴伏。", "一嘯出林，陰風拔木。", "只知拊掌放憨，不覺山青水綠。"]'),
('410d98f4-85c0-4c55-a47f-4292f41ac77c','寒拾問訊贊','釋智愚','宋','宋诗','song-poetry','','[]','金銀窟裏出來，彼此囊無一鏹。',36,'全唐诗/poet.song.196000.json','["金銀窟裏出來，彼此囊無一鏹。", "鬭貧不鬭富，做盡窮伎倆。", "大蟲來也，急須合掌。"]'),
('93293219-5536-458b-b4c3-d1575c4f6829','寒山作吟身勢贊','釋智愚','宋','宋诗','song-poetry','','[]','一句子，有也未。',34,'全唐诗/poet.song.196000.json','["一句子，有也未。", "蹙斷眉頭，做盡手勢。", "靠倒維摩記得無，至今一默喧天地。"]'),
('d28dc795-b5ed-4060-bfe2-5adb370e10ec','拾得磨墨過筆贊','釋智愚','宋','宋诗','song-poetry','','[]','頭戴樺皮冠，脚穿破木履。',47,'全唐诗/poet.song.196000.json','["頭戴樺皮冠，脚穿破木履。", "有磨墨過筆之功，無二千酬瀉瓶之水。", "捉敗了也，國清寺裡偷佛飯，元來是你。"]'),
('104a96ad-b336-4988-ac4c-edc8d5941155','栽松道者贊','釋智愚','宋','宋诗','song-poetry','','[]','鬰鬰冰壑姿，株株手親植。',24,'全唐诗/poet.song.196000.json','["鬰鬰冰壑姿，株株手親植。", "欲知來去蹤，雙峯聳寒碧。"]'),
('91a5f151-89d0-4614-bfca-0fa74b9346ee','蹈碓老盧贊','釋智愚','宋','宋诗','song-poetry','','[]','用智恰如愚，無人辨得渠。',24,'全唐诗/poet.song.196000.json','["用智恰如愚，無人辨得渠。", "粃糠和月擣，意在脫衣盂。"]'),
('4cd4be47-2bd6-4c7c-9e26-96c065f871a7','神光參達磨贊','釋智愚','宋','宋诗','song-poetry','','[]','石禪寒到骨，松雪照清眸。',24,'全唐诗/poet.song.196000.json','["石禪寒到骨，松雪照清眸。", "此道如山重，難將一臂酬。"]'),
('4442b886-8bae-4d81-aae2-6ae60ea1f3ea','馬祖接石鞏贊','釋智愚','宋','宋诗','song-poetry','','[]','草枯山欲冷，逗曉入重雲。',24,'全唐诗/poet.song.196000.json','["草枯山欲冷，逗曉入重雲。", "一箭無雙中，何如射一羣。"]'),
('35b06de3-6b0d-47f3-bcde-747d4b5705f0','丹霞遇龐公贊','釋智愚','宋','宋诗','song-poetry','','[]','邂逅漉籬翁，言談耳又聾。',24,'全唐诗/poet.song.196000.json','["邂逅漉籬翁，言談耳又聾。", "不知何處去，破帽裹西風。"]'),
('dde3bf66-0db4-4c6a-8d87-985d7858b6f0','良遂見麻谷贊','釋智愚','宋','宋诗','song-poetry','','[]','閉戶復携鉏，雲深路更迂。',24,'全唐诗/poet.song.196000.json','["閉戶復携鉏，雲深路更迂。", "須知形影外，肝膽向人輸。"]'),
('d6275dbc-edf2-48eb-902d-a3d4b6ae0ded','藥山和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','以梵夾，對凈瓶。',20,'全唐诗/poet.song.196000.json','["以梵夾，對凈瓶。", "一字不掛眼，常轉如是經。"]'),
('32a76587-84cb-4b70-b508-15a5a59b0e18','懶瓚和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','石林冰冷，糞火芋香。',20,'全唐诗/poet.song.196000.json','["石林冰冷，糞火芋香。", "深撥淺得，滋味最長。"]'),
('4a742092-31bf-463a-8cf8-7d4c4a9bf294','支遁和尚歸休圖贊','釋智愚','宋','宋诗','song-poetry','','[]','忍寒騎瘦馬，雙眼碧於秋。',24,'全唐诗/poet.song.196000.json','["忍寒騎瘦馬，雙眼碧於秋。", "寄語王公道，無錢買沃洲。"]'),
('99d023e7-423f-4205-9c36-c2191667a614','郁山主贊','釋智愚','宋','宋诗','song-poetry','','[]','日暖跨馿出，溪橋款步行。',24,'全唐诗/poet.song.196000.json','["日暖跨馿出，溪橋款步行。", "因思遭攧處，寸草不曾生。"]'),
('d1034cb7-0b8a-415c-8053-20898e97e6b9','政黄牛贊','釋智愚','宋','宋诗','song-poetry','','[]','朝看白雲去，暮騎黄犢歸。',24,'全唐诗/poet.song.196000.json','["朝看白雲去，暮騎黄犢歸。", "山窮橋斷處，鷺鷥那得知。"]'),
('f87fb198-6b7f-49e7-b891-b3a49b0b1c26','亮座主贊','釋智愚','宋','宋诗','song-poetry','','[]','虛空講得，參天荆棘。',32,'全唐诗/poet.song.196000.json','["虛空講得，參天荆棘。", "一喚回頭，杳無蹤跡。", "夕陽掛樹梢，依然隠不得。"]'),
('42b7efca-d611-44c4-81ca-94f247e3e082','泉大道浴湫圖贊','釋智愚','宋','宋诗','song-poetry','','[]','拚身躍入深淵，等閑握起龍首。',54,'全唐诗/poet.song.196000.json','["拚身躍入深淵，等閑握起龍首。", "腥風怒雷，烏飛兔走，驚得慈明幾掣肘。", "乞兒伎倆不多，千古膾炙人口，好將白棒劈脊摟。"]'),
('3f052705-c60e-4f37-8f00-eed0233253db','朝陽對月贊','釋智愚','宋','宋诗','song-poetry','','[]','寒暑不到處，山窮石自枯。',48,'全唐诗/poet.song.196000.json','["寒暑不到處，山窮石自枯。", "涕零知骨冷，隨分著工夫。", "一卷無題目，持來傍石根。", "眼昏嫌字小，華梵恐難分。"]'),
('45f3ac8b-cf85-4a13-a585-a8104afd3ccd','趙州和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','眼似鼓椎，頭如木杓。',20,'全唐诗/poet.song.196000.json','["眼似鼓椎，頭如木杓。", "欲識趙州，八十行脚。"]'),
('238559e7-ef98-43d2-92a4-f99fa5e9bbd1','臨際大師贊','釋智愚','宋','宋诗','song-poetry','','[]','黄檗棒頭，大愚肋下。',20,'全唐诗/poet.song.196000.json','["黄檗棒頭，大愚肋下。", "後代兒孫，烏焉成馬。"]'),
('1e952dcc-2c22-4a21-bc5f-9fd2e2778793','普化和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','呈真嚇殺盤山，對衆侮慢臨際。',42,'全唐诗/poet.song.196000.json','["呈真嚇殺盤山，對衆侮慢臨際。", "靜處畏影逃形，閙裏掀天撲地。", "鎮州城外活埋，至今雞驚犬吠。"]'),
('fbe7fcff-00ec-412f-831f-6295b035ead2','雲門大師贊','釋智愚','宋','宋诗','song-poetry','','["\u8861\u5c71"]','掉發睦州，脫賺靈樹。',38,'全唐诗/poet.song.196000.json','["掉發睦州，脫賺靈樹。", "赤體露金風，清波無透路。", "阿師脚跛不能行，休對乾峯南嶽去。"]'),
('9b30d7b3-6fbe-4b12-9ce9-ebe1dec18f9a','玄沙和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','不出飛猿，皮下有血。',68,'全唐诗/poet.song.196000.json','["不出飛猿，皮下有血。", "釣魚放生，死中得活。", "譏雪峯用力太過，笑靈雲根底未徹。", "只知意在鈎頭，不覺眼中著屑。", "阿呵呵，誰辨別。", "萬頃烟波，一鈎新月。"]'),
('1c19534b-d4c5-4c95-90d6-316c8091ab53','船子和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','烟水寒，扁舟小，華亭江上相尋討。',62,'全唐诗/poet.song.196000.json','["烟水寒，扁舟小，華亭江上相尋討。", "負命底劈口一橈，點頭處狼藉不少。", "父子怯相酬，誰道翻身早。", "出黄蘆，入紅蓼。", "收拾絲綸，江天未曉。"]'),
('521d7c26-d74c-4f71-9226-d9f07d5e51d4','太白興禪師贊','釋智愚','宋','宋诗','song-poetry','','[]','泯跡深藏一塢雲，仙官何事苦相親。',32,'全唐诗/poet.song.196000.json','["泯跡深藏一塢雲，仙官何事苦相親。", "修行不是無靈驗，懶作關門閑戶人。"]'),
('af4afa0c-b357-4fb1-acf0-3a164b33c377','宗庵主贊','釋智愚','宋','宋诗','song-poetry','','[]','袈裟裹草鞋，赤脚桐城走。',24,'全唐诗/poet.song.196000.json','["袈裟裹草鞋，赤脚桐城走。", "只者破生涯，抵死揚家醜。"]'),
('b75e476b-e10c-42de-a29d-e3f85fc300d1','慈明圓和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','去見神鼎諲，絕叫屋梁倒。',24,'全唐诗/poet.song.196000.json','["去見神鼎諲，絕叫屋梁倒。", "不得脫手法，打折你馿腰。"]'),
('300aa697-fb90-4453-abc2-6df0592128df','楊岐會和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','灰頭土面，弄假像真。',20,'全唐诗/poet.song.196000.json','["灰頭土面，弄假像真。", "三脚馿子，獨角麒麟。"]'),
('59377eee-d56f-4f5a-b864-e0aaae2c6a9e','雪竇顯禪師贊','釋智愚','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','凝而不結，混而常清。',91,'全唐诗/poet.song.196000.json','["凝而不結，混而常清。", "挺然嶽立，卒乎砥平。", "擬師之道兮虛空釘橛，美師之德兮色重裏膠青。", "妙高萬疊兮春歸錦鏡，翠螺一抹兮霜後洞庭。", "在彼在此兮初無朕跡，或舒或卷兮水赴滄溟，遐想高躅兮實我法城。"]'),
('4ded0952-4f01-4002-86da-f5af75869454','黄龍南禪師贊','釋智愚','宋','宋诗','song-poetry','','["\u8861\u5c71"]','山泐潭之水，奮衡山之雲。',32,'全唐诗/poet.song.196000.json','["山泐潭之水，奮衡山之雲。", "三關多漏網，誰是負恩人，晦堂之下有清新。"]'),
('a5956f17-eab6-40b2-a3ee-1e902d6c66dc','白雲端和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','接納少機關，勘驗無眼目。',24,'全唐诗/poet.song.196000.json','["接納少機關，勘驗無眼目。", "時時膈氣築，只要煨蘆菔。"]'),
('5fdd363f-592e-4852-b23b-bbb877d8245e','保寧勇和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','性燥衲僧，佒佯座主。',44,'全唐诗/poet.song.196000.json','["性燥衲僧，佒佯座主。", "抹過村草步頭，直下挨肩佛祖。", "楊岐其師，白雲其侶。", "一鳴鳳臺，凌跨今古。"]'),
('977ef9cc-351c-4b68-9359-eb3bd60dbbbf','五祖演和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','師之道兮不可得而稱，師之德兮不可得而述。',93,'全唐诗/poet.song.196000.json','["師之道兮不可得而稱，師之德兮不可得而述。", "師之行兮不可得而聞，師之業兮不可得而見。", "道德行業，聞見稱述，世人昭昭然若其。", "荷佛祖慧命於將仆之際，轉凡夫於賢聖之域。", "是謂之東山老人，吾不得而知焉。"]'),
('0bf6da39-c33c-4352-9dca-8ef79affbb93','圓悟勤禪師贊','釋智愚','宋','宋诗','song-poetry','','[]','尸碧岩，謗乳竇，擊高庵，據甌阜，此皆人所議論不到。',64,'全唐诗/poet.song.196000.json','["尸碧岩，謗乳竇，擊高庵，據甌阜，此皆人所議論不到。", "說甚麽減竈法無文印，盡情約下置而勿論。", "或曰毀譽不在乎兩端之間，䖃苴翁別有長處。"]'),
('9c911d9d-e6e3-47c2-80e9-1e10d2897aba','虎丘隆和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','柔弱丰神，骨器剛大。',40,'全唐诗/poet.song.196000.json','["柔弱丰神，骨器剛大。", "小喜多嗔，貴買賤賣。", "形影師資二十年，所以圓悟目之爲睡虎者也。"]'),
('72ff2f7a-5a4a-4568-8f83-fccb7d5bec07','宏智禪師贊','釋智愚','宋','宋诗','song-poetry','','[]','金鳳初鳴，玉人啟戶。',20,'全唐诗/poet.song.196000.json','["金鳳初鳴，玉人啟戶。", "露冷風高，子歸就父。"]'),
('de419986-8d2e-4544-b766-004c38802f67','大慧禪師贊','釋智愚','宋','宋诗','song-poetry','','[]','前無釋迦，後無達磨。',95,'全唐诗/poet.song.196000.json','["前無釋迦，後無達磨。", "駡雨駡風，祇要做大。", "黑漆竹篦胡打亂打，是佛是魔劈面便唾，因茲天降其咎。", "衡陽梅陽，十七年吞饑忍餓。", "將謂萬里生還知非，元來一星子不曾改過。", "者般瞎禿得人憎，天上人間無兩箇。", "咄。"]'),
('841f25d6-755e-4b42-8e9f-c2782cec8877','應庵和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','奮劈胸拳，撈摸虛空骨髓。',38,'全唐诗/poet.song.196000.json','["奮劈胸拳，撈摸虛空骨髓。", "開活入眼，瞎却自己頂門。", "從茲海湧峯危，是謂東山正續。"]'),
('be43ecee-fe6e-408c-95ee-ab8b0613f98c','密庵和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','行脚不到大徹堂前，剛要凌滅應庵門戶。',52,'全唐诗/poet.song.196000.json','["行脚不到大徹堂前，剛要凌滅應庵門戶。", "指柳駡楊，吹沙嗅土，却笑謝郎眉忒豎。", "欲識中峯箇裏人，無尾大蟲不是虎。"]'),
('b7355b0a-f7df-452b-8bb2-ae87f794e789','石窗和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','秋鷺翹松，寒蟾卧水。',37,'全唐诗/poet.song.196000.json','["秋鷺翹松，寒蟾卧水。", "芝峯老骨雖不在明白裡，離婁師曠覓無蹤，千古萬古祇者是。"]'),
('1d5e73ef-47b8-4bd7-bc36-8fa820dfbeca','松源和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','水庵室裏爭鋒，一掌打得耳聾。',42,'全唐诗/poet.song.196000.json','["水庵室裏爭鋒，一掌打得耳聾。", "從茲喚鐘作甕，滅却楊岐正宗。", "自謂水菴可入，却言不識中峯。"]'),
('be79623a-2a90-4246-a44d-62d3a043418a','運庵先師贊','釋智愚','宋','宋诗','song-poetry','','[]','行脚祇參松源，早是信卜賣屋。',58,'全唐诗/poet.song.196000.json','["行脚祇參松源，早是信卜賣屋。", "更說東山正傳，大似老馬嚼粟。", "近人情，無面目，引得兒孫阿轆轆。", "報恩盡力讚揚，也是鷺股割肉。"]'),
('63c86199-8ef0-4fc1-8380-f2213d5f8617','南明不庵悟和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','飛來峯下，打失護身符子。',44,'全唐诗/poet.song.196000.json','["飛來峯下，打失護身符子。", "南明山中，駡詈三平祖師。", "闡提薄福，俗眼難窺。", "夫是之謂不庵老古錐。"]'),
('b3a2866e-707e-4357-b99a-2a4a21614dd2','南嶽修首座贊','釋智愚','宋','宋诗','song-poetry','','["\u8861\u5c71"]','雲霧充饑腹，烟霞補破衣。',24,'全唐诗/poet.song.196000.json','["雲霧充饑腹，烟霞補破衣。", "祝融峯頂寺，幾度對斜暉。"]'),
('b344740c-6f81-41bb-835f-4f9216216747','靈隠石鼓夷和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','面目嚴冷，狠氣如雲。',50,'全唐诗/poet.song.196000.json','["面目嚴冷，狠氣如雲。", "攛掇翁木大，顛倒上樹。", "品藻果駡天，見地不親。", "咬牙嚙齒，走石飛塵，鷲峰別有劫壺春。"]'),
('4f3eed65-20e5-490c-aecf-16bc8c0dcdcf','靈山古雲粹法師贊','釋智愚','宋','宋诗','song-poetry','','[]','三觀互融顯其機，十門不二蕩其跡。',64,'全唐诗/poet.song.196000.json','["三觀互融顯其機，十門不二蕩其跡。", "如月印水兮光入其微，如春在花兮香襲其裓。", "是謂教庠之英，北峯之嫡。", "描邈將來不如伊，從教大地無人識。"]'),
('654ddcb4-3a50-4226-861f-35c468f91082','玉泉普明法師贊','釋智愚','宋','宋诗','song-poetry','','[]','金石絲竹難以類乎聲，碧雲清風難以同其調。',87,'全唐诗/poet.song.196000.json','["金石絲竹難以類乎聲，碧雲清風難以同其調。", "玉光幽潔，花信融通。", "妙在有無外，豈墮空假中。", "張生伏筆，何處形容。", "此是適庵老子之常準，肯與能詩能畫者同。", "藉藉流芳靈苑寺，眇然千古仰高蹤。"]'),
('5c19d2be-76fc-4ed6-94f3-b5cb3d7fd782','出山古像贊','釋智愚','宋','宋诗','song-poetry','','[]','金鐘夜擊九重城，六載歸來改瘦形。',32,'全唐诗/poet.song.196000.json','["金鐘夜擊九重城，六載歸來改瘦形。", "待得衆生心眼活，雪山依舊碧崚嶒。"]'),
('c6f63ef0-f19a-4c1a-a913-c5c6ebbffbaa','維摩示疾圖贊','釋智愚','宋','宋诗','song-poetry','','[]','一生口嘴嘮嘈，偏要攙行奪市。',41,'全唐诗/poet.song.196000.json','["一生口嘴嘮嘈，偏要攙行奪市。", "詐病毗耶離城，引得許多閑神野鬼稽首浄名。", "咄，我不識你。"]'),
('4e57ec95-1945-4447-998c-e8c68d176178','布袋回頭笑髑髏贊','釋智愚','宋','宋诗','song-poetry','','[]','咄者髑髏，荒草堆頭。',20,'全唐诗/poet.song.196000.json','["咄者髑髏，荒草堆頭。", "歛眉一笑，萬壑雲收。"]'),
('af728557-7e5b-4003-b8c1-6764e84e60a6','三教合一面贊','釋智愚','宋','宋诗','song-poetry','','[]','龜證無功，會三歸一。',20,'全唐诗/poet.song.196000.json','["龜證無功，會三歸一。", "各有面子，不欲露出。"]'),
('e34d26ef-13f7-4475-88f1-00e1e9ecb852','懶瓚和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','枕石苔生，崖藤影綠。',20,'全唐诗/poet.song.196000.json','["枕石苔生，崖藤影綠。", "天書促行，芋子未熟。"]'),
('bad02f49-130a-4ed2-aed2-bd8dbd9ee0fd','鰕子和尚贊','釋智愚','宋','宋诗','song-poetry','','[]','清溪影寒，以鰕爲目。',20,'全唐诗/poet.song.196000.json','["清溪影寒，以鰕爲目。", "無柄笊籬，東摝西摝。"]'),
('44607fa1-f087-43c5-b562-74d7c95d5f5e','郁山主贊','釋智愚','宋','宋诗','song-poetry','','[]','略彴蹈翻天地黑，盲馿惡拗弄蹄行。',32,'全唐诗/poet.song.196000.json','["略彴蹈翻天地黑，盲馿惡拗弄蹄行。", "從茲不到茶川上，溪水自涵山影清。"]'),
('f73d787f-d6cc-400d-92a0-99a682ac4a0d','政黄牛贊','釋智愚','宋','宋诗','song-poetry','','[]','犢角銅瓶掛曉烟，谿山多是往來篇。',32,'全唐诗/poet.song.196000.json','["犢角銅瓶掛曉烟，谿山多是往來篇。", "不知底事吟情險，吹落秋風白鳥邊。"]'),
('388a0e58-c76a-4f99-8b6e-b34477c2e799','朝陽毳衲贊','釋智愚','宋','宋诗','song-poetry','','[]','鍼無肉，補不足。',28,'全唐诗/poet.song.196000.json','["鍼無肉，補不足。", "傍晨曦，倚岩谷。", "怕見黄葉飛，未風先皺眉。"]'),
('133cb9fb-e784-483f-b85c-203ee188971d','對月了經贊','釋智愚','宋','宋诗','song-poetry','','[]','欲要了，無可了。',28,'全唐诗/poet.song.196000.json','["欲要了，無可了。", "山頭月，圓又缺。", "只好罷休看，夜深風露寒。"]'),
('af432a15-5c54-404c-bcc2-42a4ebda1582','寒山拾得贊','釋智愚','宋','宋诗','song-poetry','','[]','五峯石上，雙澗松邊。',20,'全唐诗/poet.song.196000.json','["五峯石上，雙澗松邊。", "是者伎倆，莫駡豐干。"]'),
('a37430ed-8d02-4e40-9ea4-652136b2fbfa','上竺柏庭月法師畫像贊','釋智愚','宋','宋诗','song-poetry','','[]','厚重如山，寬大如海。',69,'全唐诗/poet.song.196000.json','["厚重如山，寬大如海。", "丹青有神，莫擬其蹤。", "僧繇筆妙，難狀其跡。", "如上國之春歸，香風四吹。", "如銀蟾之出水，萬象歛影。", "是爲三教融通，大法之宗主者也。"]'),
('632f4167-0c3f-4324-a448-c0996e11376f','無準和尚禪者請贊仍侍立贊','釋智愚','宋','宋诗','song-poetry','','[]','移圓就方則辛，抑方爲圓則苦。',52,'全唐诗/poet.song.196000.json','["移圓就方則辛，抑方爲圓則苦。", "枘鑿不相入，是無準門戶。", "五峯峨峨兮等觀，萬象撥撥兮誰覩。", "霜降水落，子歸就父。"]'),
('cf039f83-0059-4a94-9222-98feb1554b5d','寶嚴崇辯訥法師畫像贊','釋智愚','宋','宋诗','song-poetry','','[]','身槁如柴，眼明如電。',60,'全唐诗/poet.song.196000.json','["身槁如柴，眼明如電。", "衡鑑台嶺，品藻山外之宗。", "揮呵悟門，不墮文字之相。", "以訥爲辯，以戒爲礙。", "橫拈麈尾雨花傾，萬象森羅俱鼎沸。"]'),
('dbda8bac-3029-44eb-909e-2a233d68b115','寶林遠和尚遊山像師孫侍行贊','釋智愚','宋','宋诗','song-poetry','','[]','德臘俱高，孫枝益茂。',60,'全唐诗/poet.song.196000.json','["德臘俱高，孫枝益茂。", "以勤儉苦節中興隸業，以老氣餘韻平視諸方。", "眉稜垂雪，杖竹凝霜。", "步趨有人兮清風可繼，澹常古道兮劫外徜徉。"]'),
('80f92c01-a956-4ae8-a6a7-afe973f28648','禮寶峰馬大師塔','釋智愚','宋','宋诗','song-poetry','','[]','舌貫鼻端，牛行虎視。',50,'全唐诗/poet.song.196000.json','["舌貫鼻端，牛行虎視。", "祇者形模，轉增聾戾。", "萬丈寒潭兮泐水無波，千仞寶山兮浮圖鎖翠，八十四人兮猶居學地。"]'),
('20be0413-4512-4b97-a412-ba3f51a3d522','禮大梅常禪師塔','釋智愚','宋','宋诗','song-poetry','','[]','鼯鼠聲中，顛來倒去。',20,'全唐诗/poet.song.196000.json','["鼯鼠聲中，顛來倒去。", "馬頷馿腮，不須解註。"]'),
('e4474ba9-82bb-4a54-a6c2-f308df0cd3e2','禮龍牙遁禪師塔','釋智愚','宋','宋诗','song-poetry','','[]','翠微際北腕頭短，洞水逆流方到家。',32,'全唐诗/poet.song.196000.json','["翠微際北腕頭短，洞水逆流方到家。", "年老脚跟宜著襪，不能隨處蹈泥沙。"]'),
('d29d2b4e-f90a-416a-a56f-33cb65913ad5','禮石霜千僧塚塔','釋智愚','宋','宋诗','song-poetry','','[]','萬指恬然一路歸，髑髏對對眼如眉。',32,'全唐诗/poet.song.196000.json','["萬指恬然一路歸，髑髏對對眼如眉。", "須知一色明邊外，生死如何搆得伊。"]'),
('2102aeaf-152d-470f-9a45-268cf6f11ede','禮石霜慈明大師塔','釋智愚','宋','宋诗','song-poetry','','[]','水繞山圍獅子窟，赫赫金毛從此出。',64,'全唐诗/poet.song.196000.json','["水繞山圍獅子窟，赫赫金毛從此出。", "野犴既死狐兔悲，天下叢林閙聒聒。", "我來不敢重步行，森嚴匝匝清風生。", "三拜無言出門去，烟笛一聲牛背橫。"]'),
('a9d2a47d-a7b5-455e-9eed-2c2d6d43ac70','禮明招謙禪師塔','釋智愚','宋','宋诗','song-poetry','','[]','藤深蔓短塔纍纍，以眼名龍恐是伊。',32,'全唐诗/poet.song.196000.json','["藤深蔓短塔纍纍，以眼名龍恐是伊。", "放下泥盤叉手笑，阿師曾誤矮闍梨。"]'),
('4b3aa025-c869-4887-a115-c9a64f19536f','禮牧護和尚定身塔','釋智愚','宋','宋诗','song-poetry','','[]','牧牧純來歲月多，至今殻漏未消磨。',32,'全唐诗/poet.song.196000.json','["牧牧純來歲月多，至今殻漏未消磨。", "莫嫌截斷蘇溪水，尚有禪巖掛綠蘿。"]'),
('cfc30be0-ccbb-4514-8153-5916c1ebcb7e','禮明教大師塔','釋智愚','宋','宋诗','song-poetry','','[]','道樹將摧皇祐間，力扶危處幾多難。',32,'全唐诗/poet.song.196000.json','["道樹將摧皇祐間，力扶危處幾多難。", "因思今日安然者，忍數空庭竹幾竿。"]'),
('334c151e-9124-423e-8a83-653815c6ae6b','覺範和尚塔在同安','釋智愚','宋','宋诗','song-poetry','','[]','說文字禪籠絡虛空，駡古塔主不明要旨。',44,'全唐诗/poet.song.196000.json','["說文字禪籠絡虛空，駡古塔主不明要旨。", "褒貶抑揚，流行坎止。", "棲鳳喦高插杳冥，落花啼鳥誰相委。"]'),
('c7ebbda0-a28e-4bf7-a16d-72f3ccb22fe8','釋雪竇革轍二門','釋智愚','宋','宋诗','song-poetry','','[]','迦葉聆箏起舞，淵明聞鐘皺眉。',28,'全唐诗/poet.song.196000.json','["迦葉聆箏起舞，淵明聞鐘皺眉。", "息耕斗室危坐，半窗凍日熙熙。"]'),
('b2f1c397-3534-42c2-adca-faf4957498d1','大功不宰','釋智愚','宋','宋诗','song-poetry','','[]','碧玉溪頭黄葉村，不聞花鳥到籬門。',32,'全唐诗/poet.song.196000.json','["碧玉溪頭黄葉村，不聞花鳥到籬門。", "憨眠似覺底時節，山月半規新吐痕。"]'),
('3223ca57-81d5-4f3f-93d8-f299f2b7e293','善應無方','釋智愚','宋','宋诗','song-poetry','','[]','兩脚蹣跚林葉稀，去來初不涉離微。',32,'全唐诗/poet.song.196000.json','["兩脚蹣跚林葉稀，去來初不涉離微。", "靈機未轉已先照，蹤跡擬從何處歸。"]'),
('2cb87059-7b66-4de2-b278-4d0e8a4f16b4','緣對','釋智愚','宋','宋诗','song-poetry','','[]','石牀偃月夢魂冷，溪水寫真癯影清。',32,'全唐诗/poet.song.196000.json','["石牀偃月夢魂冷，溪水寫真癯影清。", "平生矻矻自忘我，世外不知誰可盟。"]'),
('0f2474b0-06d7-4b86-8dd5-26b0518a1858','君子有所思','釋智愚','宋','宋诗','song-poetry','','[]','孤舟十萬里，委命在危流。',24,'全唐诗/poet.song.196000.json','["孤舟十萬里，委命在危流。", "五葉芬芳後，神州法已秋。"]'),
('8e8ee2b1-2319-4147-a644-4234843a80d0','閲宗鏡錄','釋智愚','宋','宋诗','song-poetry','','[]','百卷非文字，精探海藏深。',48,'全唐诗/poet.song.196000.json','["百卷非文字，精探海藏深。", "老胡三寸舌，鏡主幾生心。", "力破塵勞網，能銷曠劫金。", "歸原何所似，花底囀靈禽。"]'),
('db66b387-64d3-4c7c-8f5f-0a7c11ecfe83','鑄印','釋智愚','宋','宋诗','song-poetry','','[]','袍著金花勒小驄，揚鞭幾度月明中。',32,'全唐诗/poet.song.196000.json','["袍著金花勒小驄，揚鞭幾度月明中。", "黄河界上空來往，直至如今未樹功。"]'),
('449ab6d0-1644-4ff4-8214-4f78575c34b4','銷印','釋智愚','宋','宋诗','song-poetry','','[]','鐵鞋無底飽風霜，歲晚歸來卧石牀。',32,'全唐诗/poet.song.196000.json','["鐵鞋無底飽風霜，歲晚歸來卧石牀。", "一對眼睛烏律律，半隨雲影挂寒堂。"]'),
('aee57ffd-a965-47ed-881a-33b6daaae14c','回鴈峰晚望','釋智愚','宋','宋诗','song-poetry','','[]','孤筇影落清湘外，看盡歸雲歛復翔。',32,'全唐诗/poet.song.196000.json','["孤筇影落清湘外，看盡歸雲歛復翔。", "身世悠悠心自許，幾回到此立斜陽。"]'),
('167bf600-71bf-4d35-b82f-404d4dc9941e','衡陽龐居士庵','釋智愚','宋','宋诗','song-poetry','','[]','居士當年錯用心，渾家不睦到如今。',32,'全唐诗/poet.song.196000.json','["居士當年錯用心，渾家不睦到如今。", "摝籬柄短無人買，空自蕭蕭風滿林。"]'),
('199078c9-84f5-48b2-92d9-66cee90d070f','登祝融峰','釋智愚','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽諸峯七十二，惟有祝融峯最高。',64,'全唐诗/poet.song.196000.json','["南嶽諸峯七十二，惟有祝融峯最高。", "九千七百三十丈，下視寰海如秋豪。", "岷峨華頂遠俯伏，九華五老來相朝。", "上封老僧日無事，興來以手摩雲霄。"]'),
('720e5c7e-1929-4cb6-9167-660407a68962','方廣寺','釋智愚','宋','宋诗','song-poetry','','[]','雲中玉磬無時響，木末金燈永夜明。',32,'全唐诗/poet.song.196000.json','["雲中玉磬無時響，木末金燈永夜明。", "勝地正緣人罕到，古今門戶未嘗扃。"]'),
('5c0df1b0-71d4-43c9-8a72-af346338ab2f','訪趙野雲不值','釋智愚','宋','宋诗','song-poetry','','[]','久思閑對老維摩，欲話衆生病痛多。',32,'全唐诗/poet.song.196000.json','["久思閑對老維摩，欲話衆生病痛多。", "丈室無端鐵門限，未應容易野人過。"]'),
('f8681a99-be79-40c3-bb4f-40f660de22ed','圓書記之錢唐','釋智愚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','誰管鮎魚上竹竿，拚身捱得髑髏乾。',32,'全唐诗/poet.song.196000.json','["誰管鮎魚上竹竿，拚身捱得髑髏乾。", "者回歸去西湖上，犢草鷗波不亂看。"]'),
