('77e0b989-de88-43ea-bd41-61b669cf0194','昌老號竹谿','釋智愚','宋','宋诗','song-poetry','','[]','疏疏綠影釀寒清，高節虛心久得名。',32,'全唐诗/poet.song.196000.json','["疏疏綠影釀寒清，高節虛心久得名。", "不見月明流水處，好風時引鳳雛聲。"]'),
('d05be77a-d4b4-4019-a162-4fa6dfb182e7','潭老號古淵','釋智愚','宋','宋诗','song-poetry','','[]','蛟龍窟宅初無底，神禹難窮淺與深。',32,'全唐诗/poet.song.196000.json','["蛟龍窟宅初無底，神禹難窮淺與深。", "好把凝流消息子，沛然爲雨活叢林。"]'),
('7be87869-70cb-470f-bc1a-48fa9a2e9fd6','溥禪者西還','釋智愚','宋','宋诗','song-poetry','','[]','梅影稀疏蘭葉香，吳中水草越中行。',32,'全唐诗/poet.song.196000.json','["梅影稀疏蘭葉香，吳中水草越中行。", "荒田觸目無人揀，款款歸來带月耕。"]'),
('45d7b7e4-9378-4424-a6c7-52b525def04f','僧字止中','釋智愚','宋','宋诗','song-poetry','','[]','鍊實而食，擇木而棲。',34,'全唐诗/poet.song.196000.json','["鍊實而食，擇木而棲。", "靈靈自晦，物物難齊。", "秋歛巢虛睡穩，夢破月印清溪。"]'),
('44034b71-4a80-4f28-9961-31236727a0a9','閲侍者鏡潭','釋智愚','宋','宋诗','song-poetry','','[]','雨過天風靜，波光似鑄成。',24,'全唐诗/poet.song.196000.json','["雨過天風靜，波光似鑄成。", "不須頻鑑照，妍醜自分明。"]'),
('8c255d56-4763-4be5-9765-74a3d1b4ef7a','牧童','釋智愚','宋','宋诗','song-poetry','','[]','烟暖谿頭草正肥，儘教牛飽卧晴曦。',32,'全唐诗/poet.song.196000.json','["烟暖谿頭草正肥，儘教牛飽卧晴曦。", "捲桐又入深深塢，吹盡春風不自知。"]'),
('7272ca77-d343-45ed-9c9a-26bb9a0ed9d4','漁父','釋智愚','宋','宋诗','song-poetry','','[]','菰蒲葉冷暮天低，斷岸舟橫水四圍。',32,'全唐诗/poet.song.196000.json','["菰蒲葉冷暮天低，斷岸舟橫水四圍。", "祇有一竿湘楚竹，未嘗容易下漁磯。"]'),
('4b7ae0a3-1995-4c2d-a7ea-42531eeb1607','曾禪人唯之','釋智愚','宋','宋诗','song-poetry','','[]','當頭一諾未爲親，大道難將語默分。',32,'全唐诗/poet.song.196000.json','["當頭一諾未爲親，大道難將語默分。", "不聽晚風江上笛，一聲吹破碧天雲。"]'),
('32764c5c-af32-423c-b373-ee1ac2ff2308','楫禪人之太白','釋智愚','宋','宋诗','song-poetry','','[]','明明不可銘，斷續復誰聽。',48,'全唐诗/poet.song.196000.json','["明明不可銘，斷續復誰聽。", "海上有癡絕，山中無白丁。", "天風生寂籟，霜月下寒汀。", "子去忘幽討，重巖猶未扃。"]'),
('dbb6d351-ef16-4267-9715-7c5a106e18f9','萬松山贈張省元','釋智愚','宋','宋诗','song-poetry','','[]','鑽仰無門扉不通，靜如古井鑑秋容。',32,'全唐诗/poet.song.196000.json','["鑽仰無門扉不通，靜如古井鑑秋容。", "樂天自得道中術，時引清風吹萬松。"]'),
('c4f3cc41-3e16-4af0-aa36-4b703f82e0fb','僧遊台鴈','釋智愚','宋','宋诗','song-poetry','','[]','音旨雙消不可聞，捲衣南去與誰論。',32,'全唐诗/poet.song.196000.json','["音旨雙消不可聞，捲衣南去與誰論。", "龍湫水澀石橋滑，得路應敲尊者門。"]'),
('2a209a10-dd3d-4880-8258-c5043f2d4b90','牀屏怪松','釋智愚','宋','宋诗','song-poetry','','[]','蛟幹虬枝巧作蟠，鱗鱗鬣鬣自生寒。',32,'全唐诗/poet.song.196000.json','["蛟幹虬枝巧作蟠，鱗鱗鬣鬣自生寒。", "卧間不致爲妖去，只就濤聲起處看。"]'),
('db7c903d-83c8-4eae-8055-94de2d18c3ec','僧歸越','釋智愚','宋','宋诗','song-poetry','','[]','露激風摶岸草秋，攬衣何處上蘭舟。',32,'全唐诗/poet.song.196000.json','["露激風摶岸草秋，攬衣何處上蘭舟。", "無方始是知方者，莫效支師泥沃洲。"]'),
('5be7168a-2fd8-49b4-bfbe-d362100bbf0b','遠塵軒','釋智愚','宋','宋诗','song-poetry','','[]','開窗種脩竹，鑿石搆方池。',24,'全唐诗/poet.song.196000.json','["開窗種脩竹，鑿石搆方池。", "良夜月來此，勞生幾箇知。"]'),
('65bef61f-b98c-4903-ae69-76a572823406','遊金華洞天','釋智愚','宋','宋诗','song-poetry','','[]','颼颼崖溜靜邊聞，到此仙凡咫尺分。',32,'全唐诗/poet.song.196000.json','["颼颼崖溜靜邊聞，到此仙凡咫尺分。", "鶴駕朝真何日返，洞門終日鎖寒雲。"]'),
